def _generic_patch_adjust(patch: Dict[str, object], key: str, delta: float) -> None:
    """ヒューリスティック距離パッチのスカラー要素を安全に補正する。"""
    try:
        patch[key] = float(patch.get(key, 0.0) or 0.0) + float(delta)
    except Exception:
        pass



def _generic_patch_style_adjust(patch: Dict[str, object], label: str, delta: float) -> None:
    """ヒューリスティック距離パッチの脚質要素を安全に補正する。"""
    try:
        sb = dict(patch.get('style_bias', {}) or {})
        sb[label] = float(sb.get(label, 0.0) or 0.0) + float(delta)
        patch['style_bias'] = sb
    except Exception:
        pass



def _build_generic_course_profile(surface: str, dist: float, venue: str = '') -> Dict[str, object]:
    """未登録コース向けの汎用コースプロファイルを生成する。"""
    profile = dict(COURSE_PROFILE_NEUTRAL)
    profile['style_bias'] = dict(COURSE_PROFILE_NEUTRAL.get('style_bias', {}) or {})
    bucket = _course_profile_distance_bucket(dist)
    base = ((GENERIC_COURSE_PROFILE_DATA.get(surface, {}) or {}).get(bucket, {}) or {})
    if base:
        sb = dict(profile.get('style_bias', {}) or {})
        sb.update(dict(base.get('style_bias', {}) or {}))
        profile['style_bias'] = sb
        for key in ['straight', 'corner', 'stamina', 'power', 'speed', 'gate', 'agility']:
            if key in base:
                try:
                    profile[key] = float(base.get(key, profile.get(key, 0.5)) or profile.get(key, 0.5))
                except Exception:
                    pass
    if venue in LOCAL_RACECOURSE_NAMES and surface == 'dirt':
        _course_profile_adjust(profile, 'straight', -0.06)
        _course_profile_adjust(profile, 'corner', 0.08)
        _course_profile_adjust(profile, 'power', 0.05)
        _course_profile_adjust(profile, 'gate', 0.06)
        _course_style_adjust(profile, 'FRONT', 0.10)
        _course_style_adjust(profile, 'REAR', -0.08)
    elif venue in LOCAL_RACECOURSE_NAMES and surface == 'turf':
        _course_profile_adjust(profile, 'straight', -0.02)
        _course_profile_adjust(profile, 'corner', 0.04)
        _course_profile_adjust(profile, 'agility', 0.04)
        _course_style_adjust(profile, 'MIDDLE', 0.04)
    return profile



def _resolve_generic_course_distance_patch(venue: str, surface: str, dist: float) -> tuple[str, dict]:
    """未登録距離・未登録競馬場向けのヒューリスティック距離パッチを返す。"""
    if (not surface) or (not np.isfinite(dist)):
        return '', {}
    bucket = _course_profile_distance_bucket(dist)
    patch = dict(((GENERIC_DISTANCE_PATCH_DATA.get(surface, {}) or {}).get(bucket, {}) or {}))
    if not patch:
        return '', {}
    if surface == 'turf':
        if dist <= 1200:
            _generic_patch_adjust(patch, 'speed', 0.04)
            _generic_patch_adjust(patch, 'gate', 0.02)
        elif dist <= 1600:
            _generic_patch_adjust(patch, 'straight', 0.02)
            _generic_patch_adjust(patch, 'agility', 0.02)
        elif dist <= 2200:
            _generic_patch_adjust(patch, 'stamina', 0.04)
            _generic_patch_adjust(patch, 'power', 0.02)
        else:
            _generic_patch_adjust(patch, 'stamina', 0.08)
            _generic_patch_adjust(patch, 'power', 0.04)
            _generic_patch_style_adjust(patch, 'REAR', 0.04)
    elif surface == 'dirt':
        if dist <= 1200:
            _generic_patch_adjust(patch, 'speed', 0.06)
            _generic_patch_adjust(patch, 'gate', 0.04)
            _generic_patch_style_adjust(patch, 'FRONT', 0.04)
        elif dist <= 1700:
            _generic_patch_adjust(patch, 'speed', 0.02)
            _generic_patch_adjust(patch, 'corner', 0.02)
            _generic_patch_adjust(patch, 'power', 0.04)
        elif dist <= 2000:
            _generic_patch_adjust(patch, 'stamina', 0.06)
            _generic_patch_adjust(patch, 'power', 0.06)
            _generic_patch_style_adjust(patch, 'MIDDLE', 0.02)
        else:
            _generic_patch_adjust(patch, 'stamina', 0.10)
            _generic_patch_adjust(patch, 'power', 0.08)
            _generic_patch_style_adjust(patch, 'FRONT', -0.04)
            _generic_patch_style_adjust(patch, 'REAR', 0.04)
    if venue in LOCAL_RACECOURSE_NAMES and surface == 'dirt':
        _generic_patch_adjust(patch, 'straight', -0.03)
        _generic_patch_adjust(patch, 'corner', 0.05)
        _generic_patch_adjust(patch, 'gate', 0.04)
        _generic_patch_adjust(patch, 'power', 0.04)
        _generic_patch_style_adjust(patch, 'FRONT', 0.05)
        _generic_patch_style_adjust(patch, 'REAR', -0.05)
    elif venue in LOCAL_RACECOURSE_NAMES and surface == 'turf':
        _generic_patch_adjust(patch, 'corner', 0.03)
        _generic_patch_adjust(patch, 'agility', 0.03)
        _generic_patch_style_adjust(patch, 'MIDDLE', 0.03)
    label_venue = venue or '汎用'
    patch['label'] = f"{label_venue}{'芝' if surface == 'turf' else 'ダ'}{int(round(float(dist)))}m"
    patch['_distance_source'] = 'heuristic'
    if venue in JRA_COURSE_PROFILE_DATA:
        patch['_distance_confidence'] = 0.62
    elif venue in LOCAL_RACECOURSE_NAMES:
        patch['_distance_confidence'] = 0.56
    else:
        patch['_distance_confidence'] = 0.48
    patch['_distance_anchor'] = f'heuristic_{bucket}'
    return str(int(round(float(dist)))), patch



def _normalize_racecourse_name(name: Optional[str]) -> str:
    """競馬場名をJRA・地方の標準名へ正規化する。"""
    s = str(name or '').strip().replace('競馬場', '')
    for k in tuple(JRA_COURSE_PROFILE_DATA.keys()) + tuple(LOCAL_RACECOURSE_NAMES):
        if k and (k in s):
            return k
    return ''



def _course_profile_distance_bucket(dist: float) -> str:
    """距離(m)を大まかなコース特性バケットへ変換する。"""
    if not np.isfinite(dist):
        return 'unknown'
    if dist <= 1400:
        return 'sprint'
    if dist <= 1800:
        return 'mile'
    if dist <= 2400:
        return 'middle'
    return 'long'



def _course_profile_adjust(profile: Dict[str, object], key: str, delta: float) -> None:
    """0-1スケールのコースプロファイル要素を安全に補正する。"""
    try:
        profile[key] = clamp(float(profile.get(key, 0.5) or 0.5) + float(delta), 0.0, 1.0)
    except Exception:
        pass



def _course_style_adjust(profile: Dict[str, object], label: str, delta: float) -> None:
    """脚質バイアスを安全に補正する。"""
    try:
        sb = dict(profile.get('style_bias', {}) or {})
        sb[label] = clamp(float(sb.get(label, 0.0) or 0.0) + float(delta), -1.0, 1.0)
        profile['style_bias'] = sb
    except Exception:
        pass



def _resolve_course_distance_patch(venue: str, surface: str, dist: float) -> tuple[str, dict]:
    """競馬場・馬場・距離から距離別コース補正パッチを返す。

    優先順:
    1. 完全一致
    2. 前後の登録距離から線形補間
    3. 許容差内の最近傍距離
    4. 未登録コース向けヒューリスティック補完
    """
    if (not surface) or (not np.isfinite(dist)):
        return '', {}
    raw = (((JRA_COURSE_DISTANCE_PROFILE_DATA.get(venue, {}) or {}).get(surface, {}) or {})) if venue else {}
    if not raw:
        return _resolve_generic_course_distance_patch(venue, surface, dist)

    parsed: Dict[int, Dict[str, object]] = {}
    for k, v in raw.items():
        try:
            parsed[int(float(k))] = dict(v or {})
        except Exception:
            continue
    if not parsed:
        return _resolve_generic_course_distance_patch(venue, surface, dist)

    keys = sorted(parsed.keys())
    target = float(dist)
    tolerance = 220.0 if surface == 'turf' else 180.0
    nearest = min(keys, key=lambda x: abs(float(x) - target))
    nearest_gap = abs(float(nearest) - target)
    if nearest_gap > tolerance:
        return _resolve_generic_course_distance_patch(venue, surface, dist)

    if nearest_gap < 1e-6:
        patch = dict(parsed.get(nearest, {}) or {})
        patch['_distance_source'] = 'exact'
        patch['_distance_confidence'] = 1.0
        patch['_distance_anchor'] = str(int(nearest))
        return str(int(nearest)), patch

    lower_keys = [k for k in keys if float(k) <= target]
    upper_keys = [k for k in keys if float(k) >= target]
    lower = max(lower_keys) if lower_keys else None
    upper = min(upper_keys) if upper_keys else None
    blend_gap_limit = 500.0 if surface == 'turf' else 400.0

    if lower is not None and upper is not None and lower != upper:
        span = float(upper - lower)
        if span > 0.0 and span <= blend_gap_limit:
            ratio = (target - float(lower)) / span
            label = f'{venue}{"芝" if surface == "turf" else "ダ"}{int(round(target))}m'
            patch = _blend_course_patch(parsed.get(lower, {}), parsed.get(upper, {}), ratio, label=label)
            patch['_distance_source'] = 'blend'
            patch['_distance_confidence'] = float(clamp(0.92 - 0.20 * min(abs(ratio - 0.5) * 2.0, 1.0), 0.70, 0.94))
            patch['_distance_anchor'] = f'{int(lower)}-{int(upper)}'
            patch['_distance_blend_ratio'] = float(clamp(ratio, 0.0, 1.0))
            return f'{int(lower)}-{int(upper)}', patch

    patch = dict(parsed.get(nearest, {}) or {})
    patch['_distance_source'] = 'nearest'
    patch['_distance_confidence'] = float(clamp(1.0 - nearest_gap / max(tolerance, 1.0), 0.55, 0.90))
    patch['_distance_anchor'] = str(int(nearest))
    return str(int(nearest)), patch



def _course_profile_apply_patch(profile: Dict[str, object], patch: Dict[str, object]) -> None:
    """距離別の補正パッチを既存コースプロファイルへ重ねる。"""
    patch = dict(patch or {})
    if not patch:
        return
    if 'style_bias' in patch:
        sb = dict(profile.get('style_bias', {}) or {})
        for k, v in dict(patch.get('style_bias', {}) or {}).items():
            try:
                sb[str(k)] = clamp(float(sb.get(k, 0.0) or 0.0) + float(v), -1.0, 1.0)
            except Exception:
                continue
        profile['style_bias'] = sb
    if 'draw_bias' in patch:
        profile['draw_bias'] = dict(patch.get('draw_bias', {}) or {})
    if patch.get('label'):
        profile['distance_label'] = str(patch.get('label', '') or '')
    for key in ['straight', 'corner', 'stamina', 'power', 'speed', 'gate', 'agility']:
        if key in patch:
            try:
                _course_profile_adjust(profile, key, float(patch.get(key, 0.0) or 0.0))
            except Exception:
                pass



def _meta_text(meta: Dict[str, str], keys: list[str]) -> str:
    """meta の候補キー群から文字列を連結して返す。"""
    m = meta or {}
    return ' '.join(str(m.get(k, '') or '') for k in keys)



def _infer_race_class_id(meta: Dict[str, str]) -> int:
    """レース名・クラス名から簡易 class_id を推定する。"""
    s = _meta_text(meta, ['class_name', 'class', 'race_class', 'grade', 'race', 'course_info']).replace('　', ' ')
    if any(x in s for x in ['G1', 'ＧⅠ', 'GⅠ', 'GI', 'Jpn1', 'Ｇ１', 'G2', 'ＧⅡ', 'GⅡ', 'Jpn2', 'Ｇ２', 'G3', 'ＧⅢ', 'GⅢ', 'Jpn3', 'Ｇ３', '重賞']):
        return 5
    if ('オープン' in s) or ('リステッド' in s) or re.search(r'(^|[^A-Z])L([^A-Z]|$)', s):
        return 4
    if ('3勝' in s) or ('1600万' in s):
        return 3
    if ('2勝' in s) or ('1000万' in s):
        return 2
    if ('1勝' in s) or ('500万' in s):
        return 1
    if any(x in s for x in ['未勝利', '新馬', 'メイクデビュー']):
        return 0
    return -1



def _infer_rail_setting(meta: Dict[str, str]) -> str:
    """meta からレール設定 A/B/C を推定する。"""
    s = _meta_text(meta, ['rail_course', 'rail', 'course_info']).upper()
    for key in ['A', 'B', 'C']:
        if (f'{key}コース' in s) or re.search(fr'(^|[^A-Z]){key}([^A-Z]|$)', s):
            return key
    return ''



def _infer_race_month(meta: Dict[str, str]) -> int:
    """meta から開催月を推定する。"""
    s = _meta_text(meta, ['date', 'race_date', 'race', 'course_info'])
    m = re.search(r'(?:19|20)\d{2}[/-](\d{1,2})[/-]\d{1,2}', s)
    if not m:
        m = re.search(r'(\d{1,2})月', s)
    try:
        if m:
            mm = int(m.group(1))
            return mm if 1 <= mm <= 12 else 0
    except Exception:
        pass
    return 0



def _is_tokyo_turf_1400(meta: Dict[str, str]) -> bool:
    """東京芝1400m 戦かどうかを判定する。"""
    venue = ''
    for k in ['racecourse_inferred', 'venue', 'racecourse', 'place_name', 'track_name', 'race', 'course_info']:
        venue = _normalize_racecourse_name((meta or {}).get(k, ''))
        if venue:
            break
    dist, surface = _meta_distance_surface(meta or {})
    return venue == '東京' and surface == 'turf' and np.isfinite(dist) and 1350.0 <= float(dist) <= 1450.0



def _resolve_course_profile(meta: Dict[str, str]) -> tuple[str, str, dict]:
    """metaから競馬場・馬場種別に応じたコースプロファイルを返す。"""
    meta = meta or {}
    venue = ''
    for k in ['racecourse_inferred', 'venue', 'racecourse', 'place_name', 'track_name', 'race', 'course_info']:
        venue = _normalize_racecourse_name(meta.get(k, ''))
        if venue:
            break
    if not venue:
        venue = _normalize_racecourse_name(infer_racecourse_from_meta(meta) or '')

    dist, surface = _meta_distance_surface(meta)
    profile = dict(COURSE_PROFILE_NEUTRAL)
    profile['style_bias'] = dict(COURSE_PROFILE_NEUTRAL.get('style_bias', {}) or {})

    raw = ((JRA_COURSE_PROFILE_DATA.get(venue, {}) or {}).get(surface, {}) or {}) if venue else {}
    if raw:
        for k, v in raw.items():
            if k == 'style_bias':
                sb = dict(profile.get('style_bias', {}) or {})
                sb.update(dict(v or {}))
                profile['style_bias'] = sb
            else:
                try:
                    profile[k] = float(v)
                except Exception:
                    profile[k] = v
    elif surface in {'turf', 'dirt'}:
        profile = _build_generic_course_profile(surface, dist, venue)

    bucket = _course_profile_distance_bucket(dist)
    if venue == '東京' and surface == 'turf' and bucket in {'mile', 'middle', 'long'}:
        _course_profile_adjust(profile, 'straight', 0.05)
        _course_style_adjust(profile, 'REAR', 0.06)
    elif venue == '中山' and surface == 'turf' and bucket in {'mile', 'middle', 'long'}:
        _course_profile_adjust(profile, 'stamina', 0.08)
        _course_profile_adjust(profile, 'corner', 0.06)
    elif venue == '阪神' and surface == 'turf':
        if bucket in {'mile', 'middle', 'long'}:
            _course_profile_adjust(profile, 'straight', 0.08)
            _course_style_adjust(profile, 'REAR', 0.05)
        else:
            _course_profile_adjust(profile, 'corner', 0.06)
            _course_profile_adjust(profile, 'agility', 0.05)
            _course_style_adjust(profile, 'FRONT', 0.08)
    elif venue == '京都' and surface == 'turf':
        if bucket in {'sprint', 'mile'}:
            _course_profile_adjust(profile, 'corner', 0.08)
            _course_profile_adjust(profile, 'agility', 0.08)
            _course_style_adjust(profile, 'FRONT', 0.08)
        else:
            _course_profile_adjust(profile, 'straight', 0.05)
            _course_style_adjust(profile, 'REAR', 0.05)
    elif venue == '新潟' and surface == 'turf' and bucket in {'mile', 'middle', 'long'}:
        _course_profile_adjust(profile, 'straight', 0.10)
        _course_style_adjust(profile, 'REAR', 0.06)
    elif venue == '小倉' and surface == 'turf' and bucket in {'middle', 'long'}:
        _course_profile_adjust(profile, 'corner', 0.05)
        _course_style_adjust(profile, 'MIDDLE', 0.06)
        _course_style_adjust(profile, 'REAR', 0.03)
    elif venue in {'札幌', '函館'} and surface == 'turf':
        _course_profile_adjust(profile, 'power', 0.06)
        _course_profile_adjust(profile, 'agility', 0.04)
    elif venue == '福島' and surface == 'turf':
        _course_profile_adjust(profile, 'corner', 0.04)
        _course_style_adjust(profile, 'MIDDLE', 0.04)

    distance_key, distance_patch = _resolve_course_distance_patch(venue, surface, dist)
    if distance_patch:
        _course_profile_apply_patch(profile, distance_patch)
        profile['distance_patch'] = dict(distance_patch)
        profile['distance_key'] = distance_key
        resolved_course_venue = venue or '汎用'
        profile['course_key'] = f'{resolved_course_venue}_{surface}_{distance_key}' if surface and distance_key else ''
        profile['distance_source'] = str(distance_patch.get('_distance_source', 'exact') or 'exact')
        try:
            profile['distance_confidence'] = clamp(float(distance_patch.get('_distance_confidence', 1.0) or 1.0), 0.35, 1.0)
        except Exception:
            profile['distance_confidence'] = 1.0
        profile['distance_anchor'] = str(distance_patch.get('_distance_anchor', distance_key) or distance_key)
        if '_distance_blend_ratio' in distance_patch:
            try:
                profile['distance_blend_ratio'] = clamp(float(distance_patch.get('_distance_blend_ratio', 0.5) or 0.5), 0.0, 1.0)
            except Exception:
                pass
        if distance_patch.get('draw_bias'):
            profile['draw_bias'] = dict(distance_patch.get('draw_bias', {}) or {})
        if distance_patch.get('label'):
            profile['distance_label'] = str(distance_patch.get('label', '') or '')

    if _is_tokyo_turf_1400(meta):
        rail = _infer_rail_setting(meta) or 'A'
        month = _infer_race_month(meta)
        class_id = _infer_race_class_id(meta)
        rail_bias = TOKYO_TURF_1400_RAIL_BIAS.get(rail, TOKYO_TURF_1400_RAIL_BIAS.get('A', {}))
        _course_style_adjust(profile, 'FRONT', float(rail_bias.get('front_bonus', 0.0) or 0.0))
        _course_style_adjust(profile, 'REAR', float(rail_bias.get('rear_bonus', 0.0) or 0.0))
        _course_profile_adjust(profile, 'gate', float(rail_bias.get('inner_bonus', 0.0) or 0.0) * 0.20)
        _course_profile_adjust(profile, 'straight', float(rail_bias.get('outer_bonus', 0.0) or 0.0) * 0.35)
        if rail == 'B':
            _course_profile_adjust(profile, 'straight', 0.05)
            _course_style_adjust(profile, 'REAR', 0.04)
        elif rail == 'C':
            _course_profile_adjust(profile, 'corner', 0.05)
            _course_profile_adjust(profile, 'agility', 0.05)
            _course_style_adjust(profile, 'FRONT', 0.04)
        if month in {4, 5}:
            _course_profile_adjust(profile, 'straight', 0.06)
            _course_style_adjust(profile, 'REAR', 0.10)
            _course_style_adjust(profile, 'FRONT', -0.08)
        elif month == 6:
            _course_profile_adjust(profile, 'speed', 0.08)
            _course_profile_adjust(profile, 'gate', 0.04)
            _course_style_adjust(profile, 'FRONT', 0.08)
        elif month in {10, 11}:
            _course_profile_adjust(profile, 'speed', 0.05)
            _course_style_adjust(profile, 'FRONT', 0.06)
            _course_style_adjust(profile, 'MIDDLE', 0.03)
        if class_id >= 4:
            _course_profile_adjust(profile, 'straight', 0.06)
            _course_profile_adjust(profile, 'stamina', 0.05)
            _course_style_adjust(profile, 'REAR', 0.08)
        elif class_id >= 2:
            _course_profile_adjust(profile, 'straight', 0.03)
            _course_style_adjust(profile, 'REAR', 0.04)
            _course_style_adjust(profile, 'MIDDLE', 0.02)
        elif class_id in {0, 1}:
            _course_profile_adjust(profile, 'speed', 0.04)
            _course_profile_adjust(profile, 'gate', 0.03)
            _course_style_adjust(profile, 'FRONT', 0.03)
        class_pace_ref = TOKYO_TURF_1400_CLASS_PACE.get(class_id, {})
        if class_pace_ref:
            profile['front3f_ref'] = float(class_pace_ref.get('front3f', np.nan))
            profile['back3f_ref'] = float(class_pace_ref.get('back3f', np.nan))
            profile['pace_dev_ref'] = float(class_pace_ref.get('pace_dev', np.nan))
            profile['f6_ref'] = float(class_pace_ref.get('f6', np.nan))
        profile['rail_setting'] = rail
        profile['class_id'] = float(class_id) if class_id >= 0 else np.nan
        profile['month'] = float(month) if month else np.nan
        profile['tokyo1400'] = 1.0

    # ---- 全競馬場共通: JRA_ALL_COURSE_CLASS_PACE_DATA からクラス別ラップ参照 ----
    # 東京1400m以外でも class_id / front3f_ref / back3f_ref / pace_dev_ref / f6_ref を補完する
    if 'front3f_ref' not in profile or not np.isfinite(float(profile.get('front3f_ref', np.nan))):
        if not hasattr(dist, '__float__'):
            pass
        else:
            try:
                dist_int = int(float(dist)) if (np.isfinite(float(dist)) and float(dist) > 0) else 0
                all_class_id = _infer_race_class_id(meta)
                if dist_int > 0 and venue:
                    all_pace_ref = _lookup_course_class_pace(venue, surface or 'turf', dist_int, all_class_id)
                    if all_pace_ref:
                        profile['front3f_ref']    = float(all_pace_ref.get('front3f', np.nan))
                        profile['back3f_ref']     = float(all_pace_ref.get('back3f',  np.nan))
                        profile['pace_dev_ref']   = float(all_pace_ref.get('pace_dev', np.nan))
                        profile['f6_ref']         = float(all_pace_ref.get('f6', np.nan))
                        profile['race_count_ref'] = int(all_pace_ref.get('race_count', 0))
                        profile['horse_count_ref']= int(all_pace_ref.get('horse_count', 0))
                        if 'class_id' not in profile:
                            profile['class_id'] = float(all_class_id) if all_class_id >= 0 else np.nan
            except Exception:
                pass

    return venue, surface, profile


# =============================================================================
# JRA 全競馬場×クラス別ラップ参照ヘルパー関数 (v1.34)
# =============================================================================

def resolve_class_pace_ref(
    meta: Dict[str, str],
    venue: str = '',
    surface: str = '',
    dist_m: float = 0.0,
    class_id: int = -1,
) -> Dict[str, object]:
    """JRA_ALL_COURSE_CLASS_PACE_DATA からクラス別ラップ統計を返す。

    競馬場・馬場・距離・class_id に一致するエントリを返す。
    距離が完全一致しない場合は最近傍距離のエントリを返す（許容 ±200m）。

    Returns:
        dict: race_count, horse_count, front3f, back3f, pace_dev, f6, note を含む辞書。
              一致なしの場合は空辞書 {} を返す。
    """
    try:
        if not venue:
            venue, surface, _ = _resolve_course_profile(meta)
        if not surface:
            _, surface_tmp, _ = _resolve_course_profile(meta)
            if not surface:
                surface = surface_tmp
        if dist_m <= 0:
            dist_m_tmp, _ = _meta_distance_surface(meta)
            if np.isfinite(dist_m_tmp) and dist_m_tmp > 0:
                dist_m = float(dist_m_tmp)
        if class_id < 0:
            class_id = _infer_race_class_id(meta)

        venue_data = (JRA_ALL_COURSE_CLASS_PACE_DATA.get(venue, {}) or {})
        surface_data = (venue_data.get(surface, {}) or {})
        if not surface_data:
            return {}

        # 距離完全一致 → 最近傍距離
        dist_int = int(round(dist_m))
        if dist_int in surface_data:
            dist_key = dist_int
        else:
            available = [d for d in surface_data.keys() if isinstance(d, int)]
            if not available:
                return {}
            nearest = min(available, key=lambda d: abs(d - dist_int))
            if abs(nearest - dist_int) > 200:
                return {}
            dist_key = nearest

        class_data = surface_data.get(dist_key, {}) or {}
        if class_id in class_data:
            entry = dict(class_data[class_id])
            entry['_venue'] = venue
            entry['_surface'] = surface
            entry['_distance'] = dist_key
            entry['_class_id'] = class_id
            return entry
        # fallback: 最近傍 class_id
        available_cls = [c for c in class_data.keys() if isinstance(c, int)]
        if not available_cls:
            return {}
        nearest_cls = min(available_cls, key=lambda c: abs(c - class_id))
        entry = dict(class_data[nearest_cls])
        entry['_venue'] = venue
        entry['_surface'] = surface
        entry['_distance'] = dist_key
        entry['_class_id'] = nearest_cls
        entry['_class_id_fallback'] = True
        return entry
    except Exception:
        return {}


def resolve_tokyo1400_pace_cluster(
    front3f: Optional[float] = None,
    pace_dev: Optional[float] = None,
    meta: Optional[Dict[str, str]] = None,
) -> str:
    """東京芝1400m ペースクラスタ名を返す。

    TOKYO_TURF_1400_FULL_SPEC['pace_clusters'] の閾値に基づき
    '高圧' / '標準' / '遅延' のいずれかを返す。

    Args:
        front3f: 前半3F タイム（秒）
        pace_dev: ペース乖離値（前半3F - 後半3F）
        meta: 前半3F / pace_dev が取れない場合の補助入力

    Returns:
        str: '高圧' | '標準' | '遅延' | '' (判定不能)
    """
    try:
        clusters = TOKYO_TURF_1400_FULL_SPEC.get('pace_clusters', {}) or {}
        if front3f is None and meta:
            try:
                front3f_raw = float(meta.get('front3f', np.nan))
                if np.isfinite(front3f_raw):
                    front3f = front3f_raw
            except Exception:
                pass
        if pace_dev is None and meta:
            try:
                pd_raw = float(meta.get('pace_dev', np.nan))
                if np.isfinite(pd_raw):
                    pace_dev = pd_raw
            except Exception:
                pass

        if front3f is not None and np.isfinite(float(front3f)):
            f3 = float(front3f)
            # 高圧: front3f <= 33.8 (高圧クラスタ中心33.5)
            # 標準: 33.8 < front3f <= 34.5
            # 遅延: front3f > 34.5
            if f3 <= 33.80:
                return '高圧'
            elif f3 <= 34.50:
                return '標準'
            else:
                return '遅延'
        if pace_dev is not None and np.isfinite(float(pace_dev)):
            pd = float(pace_dev)
            # 高圧: pace_dev <= -2.2
            # 標準: -2.2 < pace_dev <= -0.8
            # 遅延: pace_dev > -0.8
            if pd <= -2.20:
                return '高圧'
            elif pd <= -0.80:
                return '標準'
            else:
                return '遅延'
        return ''
    except Exception:
        return ''


def build_race_feature_vector(
    meta: Dict[str, str],
    row: Optional['pd.Series'] = None,  # type: ignore[name-defined]
    params: Optional[dict] = None,
) -> Dict[str, object]:
    """レース1行分の特徴量ベクトルを辞書で返す（AI学習・スコアリング兼用）。

    TOKYO_TURF_1400_FULL_SPEC の feature_engineering 表に基づき、
    コース / ペース / 枠&騎手 / 馬体重・輸送 / 調教 / 血統 を網羅する。

    Returns:
        dict: 特徴量名 → 値 の辞書。欠損値は np.nan。
    """
    params = params or {}
    meta = meta or {}
    row_data: dict = {}
    if row is not None:
        try:
            row_data = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
        except Exception:
            row_data = {}

    def _g(key: str, default=np.nan):
        """row_data → meta の順で値を探す。"""
        v = row_data.get(key, meta.get(key, default))
        if v is None or (isinstance(v, float) and np.isnan(v)):
            return default
        try:
            return float(v)
        except Exception:
            return v

    # ---- コース特徴量 ----
    venue, surface, profile = _resolve_course_profile(meta)
    dist_m, surf_inferred = _meta_distance_surface(meta)
    class_id = _infer_race_class_id(meta)
    rail = _infer_rail_setting(meta) or 'A'
    month = _infer_race_month(meta)
    going_str = str(meta.get('going', meta.get('track_condition', '')) or '')

    # ---- クラス別ラップ参照 ----
    pace_ref = resolve_class_pace_ref(meta, venue=venue, surface=surface,
                                      dist_m=float(dist_m) if np.isfinite(dist_m) else 0.0,
                                      class_id=class_id)

    # ---- ペースクラスタ（東京1400mのみ） ----
    is_t1400 = bool(_is_tokyo_turf_1400(meta))
    pace_cluster_label = ''
    if is_t1400:
        pace_cluster_label = resolve_tokyo1400_pace_cluster(
            front3f=_g('front3f'),
            pace_dev=_g('pace_dev'),
            meta=meta,
        )

    # ---- 枠番・騎手タイプ ----
    gate_num = _g('gate', _g('gate_num', np.nan))
    gate_inner = 1.0 if (isinstance(gate_num, (int, float)) and np.isfinite(float(gate_num)) and float(gate_num) <= 4) else 0.0

    # ---- 馬体重 ----
    weight_kg = _g('weight', _g('horse_weight', np.nan))
    prev_weight = _g('prev_weight', _g('prev_horse_weight', np.nan))
    weight_delta_pct = np.nan
    if np.isfinite(float(weight_kg)) and np.isfinite(float(prev_weight)) and float(prev_weight) > 0:
        weight_delta_pct = (float(weight_kg) - float(prev_weight)) / float(prev_weight) * 100.0

    # ---- 調教フラグ ----
    final_lap_type = str(meta.get('final_lap_type', row_data.get('final_lap_type', '')) or '')
    final_lap_time = _g('final_lap_time', np.nan)
    mid_run_count = _g('mid_run_count', np.nan)
    aibou_flag = _g('aibou_flag', 0.0)
    training_score = _g('TrainingScore', _g('training_score', np.nan))

    # ---- 血統 ----
    sire_line = str(meta.get('sire_line', row_data.get('sire_line', '')) or '')
    brood_sire = str(meta.get('brood_sire', row_data.get('brood_sire', '')) or '')

    # ---- 重賞検出 ----
    graded_data = _detect_graded_race(meta)
    is_graded = 1.0 if graded_data else 0.0
    graded_grade = str(graded_data.get('grade', '') if graded_data else '')
    graded_stamina = float(graded_data.get('stamina_index', np.nan)) if graded_data else np.nan
    graded_speed = float(graded_data.get('speed_index', np.nan)) if graded_data else np.nan

    fv: Dict[str, object] = {
        # コース
        'venue': venue,
        'surface': surface,
        'distance_m': float(dist_m) if np.isfinite(dist_m) else np.nan,
        'going': going_str,
        'rail_setting': rail,
        'month': float(month) if month else np.nan,
        'class_id': float(class_id) if class_id >= 0 else np.nan,
        # ペース参照
        'pace_ref_front3f': float(pace_ref.get('front3f', np.nan)),
        'pace_ref_back3f': float(pace_ref.get('back3f', np.nan)),
        'pace_ref_pace_dev': float(pace_ref.get('pace_dev', np.nan)),
        'pace_ref_f6': float(pace_ref.get('f6', np.nan)),
        'pace_ref_race_count': float(pace_ref.get('race_count', np.nan)),
        # 実測ラップ（あれば）
        'front3f': _g('front3f'),
        'back3f': _g('back3f'),
        'pace_dev': _g('pace_dev'),
        'f6': _g('f6'),
        # ペースクラスタ
        'pace_cluster': pace_cluster_label,
        'is_tokyo1400': 1.0 if is_t1400 else 0.0,
        # 枠・騎手
        'gate_num': gate_num,
        'gate_inner': gate_inner,
        'jockey_style': str(meta.get('jockey_style', row_data.get('jockey_style', '')) or ''),
        'jockey_hold_rate': _g('jockey_hold_rate'),
        # 馬体重・輸送
        'weight_kg': weight_kg,
        'weight_delta_pct': weight_delta_pct,
        'transport_flag': _g('transport_flag', 0.0),
        'transport_distance_km': _g('transport_distance_km', np.nan),
        # 調教
        'final_lap_type': final_lap_type,
        'final_lap_time': final_lap_time,
        'mid_run_count': mid_run_count,
        'aibou_flag': aibou_flag,
        'training_score': training_score,
        # 血統
        'sire_line': sire_line,
        'brood_sire': brood_sire,
        'di_score': _g('di_score'),
        # 騎手交代
        'jockey_changed': _g('jockey_changed', 0.0),
        'prev_jockey_win_rate': _g('prev_jockey_win_rate'),
        'new_jockey_win_rate': _g('new_jockey_win_rate'),
        # 重賞
        'is_graded': is_graded,
        'graded_grade': graded_grade,
        'graded_stamina_index': graded_stamina,
        'graded_speed_index': graded_speed,
        # コースプロファイル
        'style_bias_front': float((profile.get('style_bias', {}) or {}).get('FRONT', np.nan)),
        'style_bias_middle': float((profile.get('style_bias', {}) or {}).get('MIDDLE', np.nan)),
        'style_bias_rear': float((profile.get('style_bias', {}) or {}).get('REAR', np.nan)),
        'profile_stamina': float(profile.get('stamina', np.nan)),
        'profile_speed': float(profile.get('speed', np.nan)),
        'profile_straight': float(profile.get('straight', np.nan)),
        'profile_corner': float(profile.get('corner', np.nan)),
        'profile_gate': float(profile.get('gate', np.nan)),
    }
    return fv


def build_lgbm_place_skeleton(
    df_train: 'pd.DataFrame',  # type: ignore[name-defined]
    feature_cols: Optional[List[str]] = None,
    target_col: str = 'place_flag',
    cat_cols: Optional[List[str]] = None,
    n_splits: int = 5,
    lgbm_params: Optional[dict] = None,
) -> dict:
    """LightGBM 複勝予測モデルのスケルトン（AI特徴量エンジニアリング表準拠）。

    TOKYO_TURF_1400_FULL_SPEC['feature_engineering'] に基づく特徴量列を使用。
    時系列分割（GroupKFold）で学習し AUC を計算する。

    Args:
        df_train: 学習データ（各行が1頭分の出走データ）
        feature_cols: 使用特徴量列リスト（None の場合はデフォルト列セット）
        target_col: 目的変数列名（1=複勝圏内, 0=圏外）
        cat_cols: カテゴリ列リスト
        n_splits: 時系列 GroupKFold の分割数
        lgbm_params: LightGBM ハイパーパラメータ（None の場合はデフォルト）

    Returns:
        dict: {'model': LGBMClassifier, 'auc': float, 'feature_importance': dict}
    """
    try:
        import lightgbm as lgb  # type: ignore
        from sklearn.model_selection import GroupKFold  # type: ignore
        from sklearn.metrics import roc_auc_score  # type: ignore
    except ImportError as e:
        return {'error': f'LightGBM/sklearn が利用できません: {e}', 'model': None, 'auc': np.nan}

    import pandas as _pd

    if feature_cols is None:
        # デフォルト特徴量列（TOKYO_TURF_1400_FULL_SPEC feature_engineering 準拠）
        feature_cols = [
            'distance_m', 'class_id', 'month', 'gate_num', 'gate_inner',
            'pace_ref_front3f', 'pace_ref_back3f', 'pace_ref_pace_dev', 'pace_ref_f6',
            'weight_kg', 'weight_delta_pct', 'transport_flag',
            'final_lap_time', 'mid_run_count', 'aibou_flag', 'training_score',
            'di_score', 'jockey_hold_rate', 'jockey_changed',
            'style_bias_front', 'style_bias_middle', 'style_bias_rear',
            'profile_stamina', 'profile_speed', 'profile_straight',
            'is_graded', 'graded_stamina_index', 'graded_speed_index',
        ]
    if cat_cols is None:
        cat_cols = ['venue', 'surface', 'going', 'rail_setting',
                    'sire_line', 'brood_sire', 'pace_cluster', 'jockey_style']

    # 利用可能な列のみ絞り込む
    avail_feat = [c for c in feature_cols if c in df_train.columns]
    avail_cat = [c for c in cat_cols if c in df_train.columns]

    if target_col not in df_train.columns:
        return {'error': f'目的変数列 {target_col!r} が見つかりません', 'model': None, 'auc': np.nan}
    if not avail_feat:
        return {'error': '有効な特徴量列がありません', 'model': None, 'auc': np.nan}

    default_lgbm = {
        'num_leaves': 64,
        'learning_rate': 0.05,
        'n_estimators': 800,
        'objective': 'binary',
        'metric': 'auc',
        'subsample': 0.8,
        'colsample_bytree': 0.8,
        'min_child_samples': 20,
        'reg_alpha': 0.1,
        'reg_lambda': 1.0,
        'random_state': 42,
        'n_jobs': -1,
        'verbose': -1,
    }
    if lgbm_params:
        default_lgbm.update(lgbm_params)

    X = df_train[avail_feat].copy()
    y = df_train[target_col].astype(int)
    # カテゴリ列を category 型に変換
    for c in avail_cat:
        if c in X.columns:
            X[c] = X[c].astype('category')

    # race_id 列があれば GroupKFold のグループに使用
    group_col = None
    for gc in ['race_id', 'race_date', 'date']:
        if gc in df_train.columns:
            group_col = gc
            break
    groups = df_train[group_col].values if group_col else np.arange(len(df_train))

    gkf = GroupKFold(n_splits=n_splits)
    auc_scores = []
    models = []
    for fold, (train_idx, val_idx) in enumerate(gkf.split(X, y, groups)):
        X_tr, X_val = X.iloc[train_idx], X.iloc[val_idx]
        y_tr, y_val = y.iloc[train_idx], y.iloc[val_idx]
        model = lgb.LGBMClassifier(**default_lgbm)
        model.fit(
            X_tr, y_tr,
            eval_set=[(X_val, y_val)],
            callbacks=[lgb.early_stopping(50, verbose=False), lgb.log_evaluation(period=-1)],
            categorical_feature=avail_cat,
        )
        pred = model.predict_proba(X_val)[:, 1]
        try:
            auc = float(roc_auc_score(y_val, pred))
        except Exception:
            auc = np.nan
        auc_scores.append(auc)
        models.append(model)

    best_idx = int(np.nanargmax(auc_scores)) if auc_scores else 0
    best_model = models[best_idx] if models else None
    mean_auc = float(np.nanmean(auc_scores)) if auc_scores else np.nan

    feat_imp: dict = {}
    if best_model is not None:
        try:
            imp = best_model.feature_importances_
            feat_imp = {str(c): int(v) for c, v in zip(avail_feat, imp)}
        except Exception:
            pass

    return {
        'model': best_model,
        'auc': mean_auc,
        'auc_scores': auc_scores,
        'feature_cols': avail_feat,
        'cat_cols': avail_cat,
        'feature_importance': feat_imp,
        'lgbm_params': default_lgbm,
    }


def enrich_meta_with_course_profile(meta: Dict[str, str]) -> Dict[str, str]:
    """metaへ競馬場コース特性の補助データを付与する。"""
    meta = dict(meta or {})
    venue, surface, profile = _resolve_course_profile(meta)
    if venue:
        meta['course_profile_venue'] = venue
        meta.setdefault('venue', venue)
    if surface:
        meta['course_profile_surface'] = surface
    if venue and surface:
        meta['course_profile_key'] = f'{venue}_{surface}'
    distance_key = str(profile.get('distance_key', '') or '')
    course_key = str(profile.get('course_key', '') or '')
    distance_label = str(profile.get('distance_label', '') or '')
    if distance_key:
        meta['course_profile_distance_key'] = distance_key
    if course_key:
        meta['course_profile_course_key'] = course_key
    if distance_label:
        meta['course_profile_distance_label'] = distance_label
    distance_source = str(profile.get('distance_source', '') or '')
    if distance_source:
        meta['course_profile_distance_source'] = distance_source
    try:
        distance_confidence = float(profile.get('distance_confidence', np.nan))
        if np.isfinite(distance_confidence):
            meta['course_profile_distance_confidence'] = f"{distance_confidence:.2f}"
    except Exception:
        pass
    distance_anchor = str(profile.get('distance_anchor', '') or '')
    if distance_anchor:
        meta['course_profile_distance_anchor'] = distance_anchor
    if _is_tokyo_turf_1400(meta):
        rail = str(profile.get('rail_setting', '') or _infer_rail_setting(meta))
        class_id = _infer_race_class_id(meta)
        month = _infer_race_month(meta)
        meta['course_profile_tokyo1400'] = '1'
        if rail:
            meta['course_profile_rail'] = rail
        if class_id >= 0:
            meta['course_profile_class_id'] = str(class_id)
        if month:
            meta['course_profile_month'] = str(month)
    try:
        sb = dict(profile.get('style_bias', {}) or {})
        meta['course_profile_style_bias'] = 'F={:.2f},M={:.2f},R={:.2f}'.format(
            float(sb.get('FRONT', 0.0) or 0.0),
            float(sb.get('MIDDLE', 0.0) or 0.0),
            float(sb.get('REAR', 0.0) or 0.0),
        )
        for k in ['straight', 'corner', 'stamina', 'power', 'speed', 'gate', 'agility', 'front3f_ref', 'back3f_ref', 'pace_dev_ref', 'f6_ref']:
            if k in profile:
                try:
                    meta[f'course_profile_{k}'] = f"{float(profile.get(k, 0.0) or 0.0):.2f}"
                except Exception:
                    meta[f'course_profile_{k}'] = str(profile.get(k, ''))
    except Exception:
        pass
    return meta



def infer_racecourse_from_meta(meta: Dict[str, str]) -> Optional[str]:
    """meta内の文字列から競馬場名を推定。

    参照順:
    - meta['venue']
    - meta['race']
    - meta['course_info']

    NOTE: 失敗した場合は None。
    """
    hay = ' '.join([
        str(meta.get('venue', '') or ''),
        str(meta.get('race', '') or ''),
        str(meta.get('course_info', '') or ''),
        str(meta.get('racecourse', '') or ''),
        str(meta.get('place_name', '') or ''),
    ])
    hay = hay.replace('競馬場', '')
    for k in JRA_COURSE_PROFILE_DATA.keys():
        if k and (k in hay):
            return k
    return None


def moisture_to_wetness_score_by_ref(moisture_pct: Optional[float], ref: Dict[str, float]) -> Optional[float]:
    """JRA早見表レンジ(参考)を使い、含水率→濡れスコア(0-100)へ正規化。

    - 0  : 良の上限（good_max）以下
    - 100: 不良の下限（bad_min）以上

    NOTE: Turfは競馬場ごとにレンジが違うため、このスコアは特徴量としてのみ利用する。
    """
    if moisture_pct is None or (not np.isfinite(float(moisture_pct))):
        return None
    lo = float(ref.get('good_max', 0.0))
    hi = float(ref.get('bad_min', lo + 1.0))
    if hi <= lo:
        return 0.0
    return clamp((float(moisture_pct) - lo) / (hi - lo) * 100.0, 0.0, 100.0)


def estimate_going_from_moisture(moisture_pct: Optional[float], ref: Dict[str, float]) -> Optional[str]:
    """JRAの早見表レンジ(参考)から、含水率→馬場状態を推定。

    IMPORTANT:
    - JRA公式にもある通り、馬場状態は含水率で自動決定ではない。
      ここでの推定は、OCR値欠損時の補助/監査用。
    """
    if moisture_pct is None or (not np.isfinite(float(moisture_pct))):
        return None
    x = float(moisture_pct)
    if x >= float(ref.get('bad_min', 1e9)):
        return '不良'
    if x >= float(ref.get('heavy_min', 1e9)):
        return '重'
    if x >= float(ref.get('slightly_min', 1e9)):
        return '稍重'
    return '良'


def enrich_meta_with_jra_moisture_refs(meta: Dict[str, str]) -> Dict[str, str]:
    """metaに含水率がある場合、JRA早見表(参考)で補助特徴量を追加。

    追加するもの:
    - racecourse_inferred: 札幌/函館/... の推定（取れない場合は空）
    - turf_going_est / dirt_going_est: 含水率からの推定（goingが既にあれば出しても上書きしない）
    - wetness_score_*: 早見表レンジ由来のスコア（既存があっても上書き）

    NOTE:
    - wet_mode判定などで使うのは「特徴量としてのwetness_score」であり、
      going自体（芝/ダの良稍重重不良）はOCRで取れたものが最優先。
    """
    meta = dict(meta or {})

    rc = infer_racecourse_from_meta(meta)
    if rc:
        meta['racecourse_inferred'] = rc

    # --- turf ---
    turf_ref = TURF_MOISTURE_REF.get(rc) if rc else None
    # fallback: if unknown, pick a moderate default (Tokyo-like) to avoid extreme scaling
    if turf_ref is None:
        turf_ref = TURF_MOISTURE_REF.get('東京')

    # --- dirt (common) ---
    dirt_ref = DIRT_MOISTURE_REF

    def _get_float(k: str) -> Optional[float]:
        """メタデータ辞書からキー k の値を float に変換する。無効・有限外の場合は None を返す。"""
        try:
            v = float(str(meta.get(k, '')).replace('%','').strip())
            return v if np.isfinite(v) else None
        except Exception:
            return None

    # compute wetness scores from moisture (JRA ref)
    for k, ref in [
        ('moisture_turf_goal', turf_ref),
        ('moisture_turf_4c', turf_ref),
        ('moisture_dirt_goal', dirt_ref),
        ('moisture_dirt_4c', dirt_ref),
    ]:
        v = _get_float(k)
        if v is None:
            continue
        meta[k] = f'{v:.1f}'
        ws = moisture_to_wetness_score_by_ref(v, ref)
        if ws is not None:
            meta[k.replace('moisture_', 'wetness_score_')] = f'{float(ws):.1f}'

    # going estimation (only if OCR going missing)
    if ('turf_going' not in meta) or (str(meta.get('turf_going','')).strip() == ''):
        v = _get_float('moisture_turf_goal') or _get_float('moisture_turf_4c')
        ge = estimate_going_from_moisture(v, turf_ref) if v is not None else None
        if ge:
            meta['turf_going_est'] = ge

    if ('dirt_going' not in meta) or (str(meta.get('dirt_going','')).strip() == ''):
        v = _get_float('moisture_dirt_goal') or _get_float('moisture_dirt_4c')
        ge = estimate_going_from_moisture(v, dirt_ref) if v is not None else None
        if ge:
            meta['dirt_going_est'] = ge

    return meta


def parse_track_conditions_text(txt: str) -> Dict[str, str]:
    """複数スクショのOCR全文から、馬場関連のキーを抽出（テキストベース）。

    ※OCRの揺れが大きいので、単発regexに依存しすぎないようにする。
    """
    s = str(txt)
    out: Dict[str, str] = {}

    # 天候
    m = re.search(r"天候\s*[:：]?\s*(晴|曇|雨|雪)", s)
    if m:
        out["weather"] = m.group(1)

    # 馬場状態（芝/ダ）: OCR誤読（相重など）も吸収
    def _norm_going(g: str) -> str:
        """馬場状態文字列を統一表記に正規化する（例: '稍' → '稍重'）。"""
        g = str(g).strip()
        g = g.replace("相重", "稍重")
        if g == "稍":
            g = "稍重"
        return g

    m = re.search(r"芝\s*[:：]?\s*(良|稍重|相重|稍|重|不良)", s)
    if m:
        out["turf_going"] = _norm_going(m.group(1))

    m = re.search(r"(ダート|ダ)\s*[:：]?\s*(良|稍重|相重|稍|重|不良)", s)
    if m:
        out["dirt_going"] = _norm_going(m.group(2))

    # ラベル無しパターン（例: "天候 : 晴  相重  重" のように2つ並ぶ）
    if "turf_going" not in out or "dirt_going" not in out:
        mm = re.search(r"天候\s*[:：]?\s*(晴|曇|雨|雪)\s+([良稍重相重稍重不良]{1,3})\s+([良稍重相重稍重不良]{1,3})", s)
        if mm:
            # 2つ目=芝, 3つ目=ダ の前提（JRAの表示に合わせる）
            out.setdefault("turf_going", _norm_going(mm.group(2)))
            out.setdefault("dirt_going", _norm_going(mm.group(3)))

    # クッション値: 直後に複数数字が出ることがあるため「6〜12」優先で選ぶ
    if "クッション" in s:
        idx = s.find("クッション")
        win = s[max(0, idx - 40) : idx + 80]
        nums = re.findall(r"([0-9]+(?:\.[0-9]+)?)", win)
        cands: List[float] = []
        for x in nums:
            try:
                cands.append(float(x))
            except Exception:
                pass
        picked = None
        in_range = [v for v in cands if 6.0 <= v <= 12.0]
        # prefer a decimal value (OCRで 8.8 のようなケース)
        decs = [v for v in in_range if abs(v - round(v)) > 1e-6]
        if decs:
            picked = decs[0]
        elif in_range:
            picked = in_range[0]
        elif cands:
            picked = cands[0]
        if picked is not None:
            out["cushion_value"] = f"{picked:.1f}" if abs(picked - round(picked)) > 1e-6 else str(int(round(picked)))

    # 含水率（ゴール前/4コーナー）
    def _moist(key: str, pat: str) -> float:
        """文字列 s に対して pat の正規表現を探し、マッチ時に out[key] へ格納する。"""
        mm = re.search(pat, s)
        if mm:
            out[key] = mm.group(1)

    # 直接表記（最優先）
    _moist("moisture_turf_goal", r"芝\s*ゴール前\s*([0-9]+(?:\.[0-9]+)?)%")
    _moist("moisture_turf_4c", r"芝\s*4コーナー\s*([0-9]+(?:\.[0-9]+)?)%")
    _moist("moisture_dirt_goal", r"(ダート|ダ)\s*ゴール前\s*([0-9]+(?:\.[0-9]+)?)%")
    if "moisture_dirt_goal" in out:
        # 上のパターンはgroup(2)が数値なので補正
        out["moisture_dirt_goal"] = re.search(r"([0-9]+(?:\.[0-9]+)?)", out["moisture_dirt_goal"]).group(1)
    _moist("moisture_dirt_4c", r"(ダート|ダ)\s*4コーナー\s*([0-9]+(?:\.[0-9]+)?)%")
    if "moisture_dirt_4c" in out:
        out["moisture_dirt_4c"] = re.search(r"([0-9]+(?:\.[0-9]+)?)", out["moisture_dirt_4c"]).group(1)

    # 使用コース
    m = re.search(r"(A|B|C)コース", s)
    if m:
        out["rail_course"] = m.group(1)

    # 内柵の移動（例: 内柵3m）
    m = re.search(r"内柵\s*([0-9]+(?:\.[0-9]+)?)\s*m", s)
    if m:
        out["rail_offset_m_text"] = m.group(1)

    # 内側傷み
    if re.search(r"内側に傷み", s):
        out["inside_damage"] = "1"

    # 芝丈（表記ゆれ対応）
    m = re.search(r"野芝\s*([0-9]+)\s*(?:から|〜|～|\-|—|‐)\s*([0-9]+)", s)
    if m:
        out["grass_nosh_cm"] = f"{m.group(1)}-{m.group(2)}"
    m = re.search(r"洋芝\s*([0-9]+)\s*(?:から|〜|～|\-|—|‐)\s*([0-9]+)", s)
    if m:
        out["grass_yosh_cm"] = f"{m.group(1)}-{m.group(2)}"

    return out


def ocr_track_images(track_img_paths: List[str], lang: str = "jpn") -> Dict[str, str]:
    """馬場スクショ群から『数値化した特徴量』をmetaに詰める。

    返す値は meta 辞書にそのまま merge できる形。
    - *_score は 0-100
    - *_pct は % 実数（文字列ではなく数値にしたいが、metaはdict[str,str]前提のため文字列）
    """
    if not track_img_paths:
        return {}

    texts = []
    for p in track_img_paths:
        try:
            pil = Image.open(p)
            img = preprocess_for_ocr(pil)
            t = pytesseract.image_to_string(img, lang=lang, config="--psm 6")
            texts.append(t)
        except Exception:
            pass

    joined = "\n".join(texts)
    raw = parse_track_conditions_text(joined)

    # numeric conversions
    out: Dict[str, str] = dict(raw)

    # goings -> firmness score
    if "turf_going" in raw:
        v = going_to_firmness_score(raw["turf_going"])
        if v is not None:
            out["turf_firmness_score"] = f"{v:.1f}"

    if "dirt_going" in raw:
        v = going_to_firmness_score(raw["dirt_going"])
        if v is not None:
            out["dirt_firmness_score"] = f"{v:.1f}"

    # cushion
    cv = _safe_float(raw.get("cushion_value", "")) if "cushion_value" in raw else None
    if cv is not None:
        out["cushion_score"] = f"{cushion_to_score(cv):.1f}"

    # moisture -> wetness score
    for k in ["moisture_turf_goal", "moisture_turf_4c", "moisture_dirt_goal", "moisture_dirt_4c"]:
        v = _safe_float(raw.get(k, ""))
        if v is None:
            continue
        out[k] = f"{v:.1f}"
        out[k.replace("moisture_", "wetness_score_")] = f"{moisture_to_wetness_score(v):.1f}"

    # inside damage score (0/1 -> 100/80)
    inside_damage = int(str(raw.get("inside_damage", "0")) == "1")
    out["inside_damage"] = str(inside_damage)
    out["inside_quality_score"] = f"{(80.0 if inside_damage else 100.0):.1f}"

    # rail course -> numeric offset meter
    # Bコース（Aから3m外）と画像に出る想定。Cも便宜上 +6m とする。
    rail = raw.get("rail_course", "")
    out["rail_course"] = rail
    rail_offset = {"A": 0.0, "B": 3.0, "C": 6.0}.get(rail)
    if rail_offset is not None:
        out["rail_offset_m"] = f"{rail_offset:.1f}"

    return out




# =========================
# keibabook 調教 OCR (multi-image) + scoring (v1)
# - 全体時計(4F) + 終い(3F/1F) の両方を相対評価で使用
# - 市場データ（市場等）は一切使用しない
# =========================

def _fw_to_hw_digits(text: str) -> str:
    """全角数字や記号を半角へ寄せる（OCR揺れ対策）。"""
    if text is None:
        return ''
    tbl = str.maketrans({
        '０':'0','１':'1','２':'2','３':'3','４':'4','５':'5','６':'6','７':'7','８':'8','９':'9',
        '．':'.','。':'.','，':',','－':'-','ー':'-'
    })
    return str(text).translate(tbl)


def _merge_training_ocr_results(results: list) -> dict:
    """複数ページOCR結果を統合。馬番ごとに works を結合し重複除去する。"""
    out = {'horses': {}, 'meta': {'pages': 0, 'rows': 0}}
    for r in list(results or []):
        if not isinstance(r, dict):
            continue
        out['meta']['pages'] += 1
        horses = r.get('horses', {}) or {}
        for num, ent in horses.items():
            num = str(num)
            if num not in out['horses']:
                out['horses'][num] = {'name': ent.get('name',''), 'works': []}
            out['horses'][num]['works'].extend(list(ent.get('works', []) or []))

    # de-dup works by (date, t4, t3, t1)
    for num, ent in (out.get('horses', {}) or {}).items():
        uniq = []
        seen = set()
        for w in ent.get('works', []) or []:
            try:
                k = (str(w.get('date','')), float(w.get('t4', float('nan'))), float(w.get('t3', float('nan'))), float(w.get('t1', float('nan'))))
            except Exception:
                k = (str(w.get('date','')), str(w.get('t4','')), str(w.get('t3','')), str(w.get('t1','')))
            if k in seen:
                continue
            seen.add(k)
            uniq.append(w)
        ent['works'] = uniq
        out['meta']['rows'] += len(uniq)

    return out


def _ocr_kb_crop(pil) -> object:
    """keibabook OCR 用に画像の UI 余白をクロップして返す。失敗時は元画像をそのまま返す。"""
    try:
        w, h = pil.size
        left   = int(w * 0.00)
        right  = int(w * 1.00)
        top    = int(h * 0.12)
        bottom = int(h * (1.0 - 0.06))
        if right > left and bottom > top:
            return pil.crop((left, top, right, bottom))
    except Exception:
        pass
    return pil


def _ocr_kb_patterns() -> dict:
    """keibabook OCR 用の正規表現パターン辞書を返す。"""
    import re as _re
    return {
        'slope4': _re.compile(
            r'(\d{2,3}\.\d)\s+(\d{2}\.\d)\s+(\d{2}\.\d)\s+(\d{2}\.\d)'
        ),
        'wcw5': _re.compile(
            r'(\d{2,3}\.\d)\s+(\d{2}\.\d)\s+(\d{2}\.\d)\s+(\d{2}\.\d)\s+(\d{2}\.\d)(?:\s+\[(\d)\])?'
        ),
        'f7': _re.compile(
            r'7F\s+(\d{2,3}\.\d)\s+(\d{2}\.\d)\s+(\d{2}\.\d)\s+(\d{2}\.\d)\s+(\d{2}\.\d)(?:\s+\[(\d)\])?'
        ),
        'horse_hdr': _re.compile(
            r'^(\d{1,2})\s+(\d{1,2})\s+(\S+)'
        ),
        'date': _re.compile(r'(\d{1,2})[/\-](\d{1,2})'),
    }

def ocr_training_keibabook_v1(image_path: str, lang: str = 'jpn+eng') -> dict:
    """keibabook調教スクショから馬番ごとの時計を抽出（坂路4点 + W/CW 5点 + 7F対応）。

    対応フォーマット（例）:
    - 坂路: 55.5 39.9 25.6 12.6  -> (t4,t3,t2,t1)
    - W/CW: 83.1 66.7 52.0 37.0 11.9 [5] -> (t6,t5,t4,t3,t1) ※t2なし
    - 7F : 7F 98.2 66.5 51.9 37.2 12.3 [4] -> (t7,t5,t4,t3,t1) ※t2なし

    返却 works は scoring 側で使う (t4,t3,t1) を必ず埋める設計。
    サブ関数: _ocr_kb_crop / _ocr_kb_patterns
    """
    if not image_path:
        return {'horses': {}, 'meta': {'warn': 'no_image'}}

    try:
        pil = Image.open(image_path)
    except Exception as e:
        return {'horses': {}, 'meta': {'warn': f'open_failed:{e}'}}

    # crop UI parts
    pil = _ocr_kb_crop(pil)

    try:
        raw = pytesseract.image_to_string(pil, lang=lang)
    except Exception as e:
        return {'horses': {}, 'meta': {'warn': f'ocr_failed:{e}'}}

    raw_lines = raw.splitlines()
    patterns  = _ocr_kb_patterns()
    pat_slope = patterns['slope4']
    pat_wcw   = patterns['wcw5']
    pat_7f    = patterns['f7']
    pat_horse = patterns['horse_hdr']
    pat_date  = patterns['date']

    horses = {}
    current = None
    fmt     = 'unknown'

    def _join_if_needed(i, raw_lines) -> str:
        """7F / W/CW が行分割された場合に次行を結合して返す。"""
        ln = raw_lines[i]
        if '7F' in ln and len(re.findall(r'\d+\.\d', ln)) < 5:
            if i + 1 < len(raw_lines):
                ln = ln.rstrip() + ' ' + raw_lines[i+1].strip()
        elif any(t in ln for t in ['W','CW']) and len(re.findall(r'\d+\.\d', ln)) == 4:
            if i + 1 < len(raw_lines):
                ln = ln.rstrip() + ' ' + raw_lines[i+1].strip()
        return ln

    for idx, _raw_ln in enumerate(raw_lines):
        ln = _join_if_needed(idx, raw_lines)

        # detect horse header
        mh = pat_horse.match(ln.strip())
        if mh:
            frame_n = mh.group(1)
            horse_n = mh.group(2)
            current = horse_n
            fmt     = 'unknown'
            if current not in horses:
                horses[current] = {'works': [], 'frame': frame_n}
            continue

        if current is None:
            continue

        # date guess
        md = pat_date.search(ln)
        date_str = f"{md.group(1)}/{md.group(2)}" if md else ''

        # parse clock line
        work = None
        m7f = pat_7f.search(ln)
        if m7f:
            t7,t5,t4,t3,t1 = [float(m7f.group(k)) for k in range(1,6)]
            rank = int(m7f.group(6)) if m7f.group(6) else None
            work = {'fmt':'7F','t7':t7,'t5':t5,'t4':t4,'t3':t3,'t1':t1,'rank':rank,'date':date_str}
            fmt  = '7F'
        else:
            mw = pat_wcw.search(ln)
            if mw:
                t6,t5,t4,t3,t1 = [float(mw.group(k)) for k in range(1,6)]
                rank = int(mw.group(6)) if mw.group(6) else None
                work = {'fmt':'W5','t6':t6,'t5':t5,'t4':t4,'t3':t3,'t1':t1,'rank':rank,'date':date_str}
                fmt  = 'W5'
            else:
                ms = pat_slope.search(ln)
                if ms:
                    t4_,t3_,t2_,t1_ = [float(ms.group(k)) for k in range(1,5)]
                    work = {'fmt':'SLOPE4','t4':t4_,'t3':t3_,'t2':t2_,'t1':t1_,'rank':None,'date':date_str}
                    fmt  = 'SLOPE4'

        if work is None:
            continue

        # fill t4/t3/t1 for uniform downstream scoring
        work.setdefault('t4', work.get('t4', None))
        work.setdefault('t3', work.get('t3', None))
        work.setdefault('t1', work.get('t1', None))

        # extract tags for quantitative scoring
        course = 'W' if fmt in ('W5','7F') else 'SLOPE'
        load_m = re.search(r'\b(5[456789]|6[0-9])\b', ln)
        load   = float(load_m.group(0)) if load_m else None
        pair_m = re.search(r'(一[緒同]|併せ|併走)', ln)
        pair   = pair_m.group(0) if pair_m else ''

        horses[current]['works'].append({
            'fmt': fmt,
            'course': course,
            'load': load,
            'pair': pair,
            'raw': ln[:180],
            **{k: v for k, v in work.items() if k not in ('fmt',)},
        })

    return {'horses': horses, 'meta': {'lines': len(raw_lines), 'crop': '0.12/0.06'}}

def ocr_training_keibabook_v1_cached(img_path: str, lang: str, cache_dir: Optional[str], force: bool = False) -> dict:
    """調教ページ画像を OCR しキャッシュ付きで調教データ dict を返す。"""
    key = _ocr_cache_key('training_keibabook', img_path, lang)
    if (not force):
        hit = _ocr_cache_load_json(cache_dir, key)
        if hit is not None and isinstance(hit, dict) and len(hit):
            return hit
    obj = ocr_training_keibabook_v1(img_path, lang=lang)
    _ocr_cache_save_json(cache_dir, key, obj)
    return obj


def _robust_z_from_series(x: pd.Series) -> pd.Series:
    """IQR ベースのロバスト z スコアを計算する。IQR が微小な場合は 0 を返す。"""
    x = _num_series(x, index=getattr(x, 'index', None))
    med = float(np.nanmedian(x.values))
    q1 = float(np.nanpercentile(x.values, 25))
    q3 = float(np.nanpercentile(x.values, 75))
    iqr = float(q3 - q1)
    if not (iqr > 1e-6):
        return pd.Series(np.zeros(len(x)), index=x.index)
    return (med - x) / iqr


def _kbs_raw_workout_score(work: dict, w4: float, w3: float, w1: float) -> float:
    """単回調教 (work dict) の生スコア（0-100基準）を計算して返す。"""
    t4 = work.get('t4') or work.get('t7') or work.get('t6')
    t3 = work.get('t3')
    t1 = work.get('t1')
    if t4 is None or t3 is None or t1 is None:
        return float('nan')
    try:
        # lower is faster; invert to higher=better; anchor at typical baseline
        base = w4 * (55.0 - float(t4)) + w3 * (40.0 - float(t3)) + w1 * (12.5 - float(t1))
        return base
    except Exception:
        return float('nan')


def _kbs_course_normalize(dfa, tr: dict) -> object:
    """コース別ロバスト正規化を dfa に適用して 'WorkoutScore_latest' を更新する。"""
    # import numpy as np
    # import pandas as pd
    try:
        for course_val in dfa['course_latest'].unique():
            mask = dfa['course_latest'] == course_val
            sub  = _num_series(dfa.loc[mask, 'WorkoutScore_latest'], index=dfa.loc[mask].index)
            med  = float(sub.median()) if len(sub) >= 3 else float(sub.mean())
            iqr  = float(sub.quantile(0.75) - sub.quantile(0.25)) if len(sub) >= 3 else 1.0
            iqr  = max(iqr, 1.0)
            dfa.loc[mask, 'WorkoutScore_latest'] = _clip0100(((sub - med) / iqr * 10 + 50))
    except Exception:
        pass
    return dfa


def _kbs_shape_score(dfa) -> object:
    """坂路（加速形）と W/CW（3F配分）の形スコアを計算して dfa に追加する。"""
    import numpy as np
    # import pandas as pd
    try:
        # 坂路: lap復元 (t4,t3,t2,t1 → lap4..lap1)
        for c in ['t4_latest','t3_latest','t2_latest','t1_latest']:
            if c not in dfa.columns:
                dfa[c] = np.nan
        t4 = _num_series(dfa['t4_latest'], index=dfa.index)
        t3 = _num_series(dfa['t3_latest'], index=dfa.index)
        t1 = _num_series(dfa['t1_latest'], index=dfa.index)
        lap1 = t1
        lap3 = t3 - t1
        lap4 = t4 - t3
        # 坂路: 加速（lap3→lap1で速くなるほど良い）
        accel_last  = _clip_series((lap3 - lap1), -5.0, 5.0)
        accel_count = ((lap4 > lap3).astype(float) + (lap3 > lap1).astype(float))
        dfa['shape_latest'] = (accel_last * 0.7 + accel_count * 0.3).fillna(0.0)
    except Exception:
        dfa['shape_latest'] = 0.0
    return dfa

def compute_training_scores_keibabook(entries: pd.DataFrame, ocr_all: dict, params: Optional[dict] = None) -> pd.DataFrame:
    """entries(num) と keibabook OCR結果(horses) から TrainingScore(0-100) と delta_train を算出。

    サブ関数: _kbs_raw_workout_score / _kbs_course_normalize / _kbs_shape_score
    """
    import numpy as np
    params = params or DEFAULT_PARAMS
    tr = (params.get('training_rules', {}) or {})

    max_works = int(tr.get('max_works', 3) or 3)
    w_recent = list(tr.get('recent_weights', [0.55, 0.30, 0.15]) or [0.55, 0.30, 0.15])
    w_recent = [float(x) for x in w_recent[:max_works]]
    sw = sum(w_recent) if sum(w_recent) > 0 else 1.0
    w_recent = [x / sw for x in w_recent]

    w4 = float(tr.get('w_t4', 0.55) or 0.55)
    w3 = float(tr.get('w_t3', 0.27) or 0.27)
    w1 = float(tr.get('w_t1', 0.18) or 0.18)

    _ = float(tr.get('_delta_scale', 0.08) or 0.08)
    _ = float(tr.get('_delta_cap', 3.0) or 3.0)

    horses = (ocr_all or {}).get('horses', {}) or {}

    # ── ベクトル化: iterrows → apply ──────────────────────────────
    def _calc_workout_row(row):
        num = str(row.get('num', ''))
        wrks = horses.get(num, {}).get('works', []) if num in horses else []
        wrks = wrks[:max_works]
        raw_scores = [_kbs_raw_workout_score(w, w4, w3, w1) for w in wrks]
        raw_scores = [s for s in raw_scores if s == s]
        if not raw_scores:
            return {'num': num, 'WorkoutScore_latest': np.nan,
                    't4_latest': np.nan, 't3_latest': np.nan, 't1_latest': np.nan,
                    'shape_latest': 0.0, 'course_latest': '',
                    'load_latest': np.nan, 'pair_latest': '',
                    'TrainingScore': 50.0, 'delta_train': 0.0, 'TrainingRank': 999}
        blended = sum(s * w for s, w in zip(raw_scores, w_recent[:len(raw_scores)]))
        latest = wrks[0] if wrks else {}
        return {
            'num': num,
            'WorkoutScore_latest': blended,
            't4_latest': latest.get('t4', np.nan),
            't3_latest': latest.get('t3', np.nan),
            't1_latest': latest.get('t1', np.nan),
            'course_latest': latest.get('course', ''),
            'load_latest':   latest.get('load', np.nan),
            'pair_latest':   latest.get('pair', ''),
            'shape_latest': 0.0,
        }
    rows = entries.apply(_calc_workout_row, axis=1).tolist()

    if not rows:
        return entries[['num']].copy()

    dfa = pd.DataFrame(rows)

    # course normalization
    dfa = _kbs_course_normalize(dfa, tr)

    # shape score
    dfa = _kbs_shape_score(dfa)

    # 負荷差・併せ差ボーナス
    try:
        load_bonus = np.clip((_num_series(dfa['load_latest'], index=dfa.index).values - 55.0), -2, 3) * 0.5
        pair_bonus = dfa['pair_latest'].astype(str).str.strip().map(lambda p: 1.5 if p else 0.0)
        dfa['WorkoutScore_latest'] = _clip0100((dfa['WorkoutScore_latest'] + load_bonus + pair_bonus))
    except Exception:
        pass

    # 全体TrainingScore
    try:
        dfa['TrainingScore'] = _clip0100((
            0.70 * _num_series(dfa['WorkoutScore_latest'], 50.0, index=dfa.index)
            + 0.30 * _clip0100((_num_series(dfa['shape_latest'], 0.0, index=dfa.index) * 10 + 50))
        ))
    except Exception:
        dfa['TrainingScore'] = 50.0

    # delta (最新 vs 直前)
    try:
        dfa['delta_train'] = 0.0
    except Exception:
        pass

    # rank
    try:
        dfa['TrainingRank'] = _num_series(_num_series(dfa['TrainingScore'], index=dfa.index).rank(method='min', ascending=False), 999, index=dfa.index, dtype=int)
    except Exception:
        dfa['TrainingRank'] = 999

    out_cols = ['num','TrainingScore','TrainingRank','delta_train','WorkoutScore_latest',
                't4_latest','t3_latest','t1_latest','shape_latest',
                'course_latest','load_latest','pair_latest']
    return dfa[[c for c in out_cols if c in dfa.columns]]


# =========================
# Heatmap -> map_summary(F/M/R)
# =========================

def _default_heatmap_roi(img: np.ndarray) -> Tuple[int, int, int, int]:
    """Fallback ROI (x1,y1,x2,y2) as ratios for typical smartphone screenshots."""
    h, w = img.shape[:2]
    x1 = int(w * 0.07)
    x2 = int(w * 0.93)
    y1 = int(h * 0.33)
    y2 = int(h * 0.70)
    return x1, y1, x2, y2


def detect_heatmap_roi(img: np.ndarray) -> Tuple[int, int, int, int]:
    """Detect heatmap region by saturation mask; fallback to default ROI."""
    h, w = img.shape[:2]
    hsv = cv2.cvtColor(img, cv2.COLOR_BGR2HSV)
    # colored region tends to have higher saturation
    sat = hsv[:, :, 1]
    val = hsv[:, :, 2]
    mask = ((sat > 35) & (val > 40)).astype(np.uint8) * 255
    # focus on central area to avoid header/footer
    mask[: int(h * 0.18), :] = 0
    mask[int(h * 0.85) :, :] = 0

    mask = cv2.morphologyEx(mask, cv2.MORPH_OPEN, np.ones((5, 5), np.uint8))
    mask = cv2.morphologyEx(mask, cv2.MORPH_CLOSE, np.ones((11, 11), np.uint8))

    cnts, _ = cv2.findContours(mask, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)
    if not cnts:
        return _default_heatmap_roi(img)

    # pick largest area contour
    cnt = max(cnts, key=cv2.contourArea)
    x, y, ww, hh = cv2.boundingRect(cnt)

    # sanity check: heatmap should be reasonably large
    if ww * hh < (w * h) * 0.05:
        return _default_heatmap_roi(img)

    # pad a bit
    pad_x = int(ww * 0.05)
    pad_y = int(hh * 0.08)
    x1 = max(0, x - pad_x)
    y1 = max(0, y - pad_y)
    x2 = min(w, x + ww + pad_x)
    y2 = min(h, y + hh + pad_y)
    return x1, y1, x2, y2


def extract_map_rates_from_heatmap(
    heatmap_path: str,
    lang: str = "jpn+eng",
    band_mode: str = "thirds",
) -> Tuple[Optional[Dict[str, float]], Dict[str, str]]:
    """Extract FRONT/MIDDLE/REAR rates from heatmap screenshot.

    Spec (practical/fast):
    - detect heatmap ROI
    - OCR percentage texts inside ROI (e.g., 24%) with coordinates
    - aggregate by vertical bands (default: top/middle/bottom thirds)

    Returns:
    - map_rates: {'FRONT': rF, 'MIDDLE': rM, 'REAR': rR} where r in [0,1]
    - meta_additions: {'map_summary': 'F=.. M=.. R=.. (heatmap_ocr)', 'map_roi': 'x1,y1,x2,y2', 'map_points': 'n=..'}

    If extraction fails, returns (None, meta_additions with reason).
    """
    pil = Image.open(heatmap_path).convert("RGB")
    rgb = np.array(pil)
    bgr = cv2.cvtColor(rgb, cv2.COLOR_RGB2BGR)

    x1, y1, x2, y2 = detect_heatmap_roi(bgr)
    roi = rgb[y1:y2, x1:x2]

    # For OCR, avoid hard binarization; just enlarge + mild threshold
    gray = cv2.cvtColor(roi, cv2.COLOR_RGB2GRAY)
    gray = cv2.resize(gray, None, fx=2.0, fy=2.0, interpolation=cv2.INTER_CUBIC)
    gray = cv2.GaussianBlur(gray, (3, 3), 0)
    thr = cv2.adaptiveThreshold(
        gray, 255, cv2.ADAPTIVE_THRESH_GAUSSIAN_C, cv2.THRESH_BINARY, 31, 9
    )

    data = pytesseract.image_to_data(
        thr,
        lang=lang,
        output_type=pytesseract.Output.DATAFRAME,
        config="--psm 6",
    )
    data = data.dropna(subset=["text"])
    data["text"] = data["text"].astype(str).str.strip()
    data = data[data["text"] != ""]

    pts = []  # (y_center, value)
    for _, r in data.iterrows():
        t = str(r["text"]).replace("％", "%")
        m = re.fullmatch(r"(\d{1,3})%", t)
        if not m:
            continue
        v = int(m.group(1))
        if v < 0 or v > 100:
            continue
        y_center = float(r["top"] + r["height"] / 2.0)
        pts.append((y_center, v))

    meta_add = {
        "map_roi": f"{x1},{y1},{x2},{y2}",
        "map_points": f"n={len(pts)}",
    }

    if len(pts) < 3:
        meta_add["map_summary"] = "Unknown (heatmap_ocr_failed)"
        return None, meta_add

    # banding
    roi_h = thr.shape[0]
    if band_mode == "thirds":
        b1 = roi_h / 3.0
        b2 = 2.0 * roi_h / 3.0
        bands = {
            "FRONT": [v for y, v in pts if y < b1],
            "MIDDLE": [v for y, v in pts if b1 <= y < b2],
            "REAR": [v for y, v in pts if y >= b2],
        }
    else:
        # fallback to thirds
        b1 = roi_h / 3.0
        b2 = 2.0 * roi_h / 3.0
        bands = {
            "FRONT": [v for y, v in pts if y < b1],
            "MIDDLE": [v for y, v in pts if b1 <= y < b2],
            "REAR": [v for y, v in pts if y >= b2],
        }

    # fill missing band with overall mean
    all_vals = [v for _, v in pts]
    overall = float(np.mean(all_vals))

    def band_mean(vals: List[int]) -> float:
        """バンド内の値の平均を返す内部ヘルパ。"""
        if len(vals) == 0:
            return overall
        return float(np.mean(vals))

    f = band_mean(bands["FRONT"]) / 100.0
    m_ = band_mean(bands["MIDDLE"]) / 100.0
    r_ = band_mean(bands["REAR"]) / 100.0

    map_rates = {
        "FRONT": clamp(f, 0.0, 1.0),
        "MIDDLE": clamp(m_, 0.0, 1.0),
        "REAR": clamp(r_, 0.0, 1.0),
    }

    meta_add["map_summary"] = f"F={map_rates['FRONT']:.2f} M={map_rates['MIDDLE']:.2f} R={map_rates['REAR']:.2f} (heatmap_ocr)"
    return map_rates, meta_add


