# 2) v1.1 scoring
# =========================

@dataclass
class AuditFlags:
    audit_flag: str
    reason: str


def compute_ai_rear_confirmed(df: pd.DataFrame) -> pd.Series:
    """3コーナー zone が REAR 系であることを確認した boolean Series を返す。"""
    z3 = df["zone_3c"].astype(str).str.upper().str.strip()
    z4 = df["zone_4c"].astype(str).str.upper().str.strip()
    return (z3 == "REAR") & (z4 == "REAR")


# ──────────────────────────────────────────────────────────────────────
# R27: 走法分類ロジック  classify_running_style
# ──────────────────────────────────────────────────────────────────────

def _rsc_zone_score_row(row: "pd.Series", weights: dict) -> dict:
    """1頂の zone 列値から各ラベルの加重和を返す。

    Returns:
        {'FRONT': float, 'MIDDLE': float, 'REAR': float}
    """
    scores = {'FRONT': 0.0, 'MIDDLE': 0.0, 'REAR': 0.0}
    total_w = 0.0
    for col, w in weights.items():
        if col not in row.index:
            continue
        z = normalize_zone_token(str(row[col]))
        if z in scores:
            scores[z] += w
            total_w += w
    if total_w > 0:
        for k in scores:
            scores[k] /= total_w
    else:
        scores['MIDDLE'] = 1.0
    return scores


def _rsc_apply_pred_boost(
    scores: dict,
    row: "pd.Series",
    pf_rank: int,
    pl_rank: int,
    n: int,
    cfg: dict,
) -> dict:
    """pred_first3f / pred_last3f の順位に応じて FRONT/REAR スコアを補正する。"""
    top_f = int(cfg.get('first3f_top_n', 3))
    top_l = int(cfg.get('last3f_top_n', 3))
    boost_f = float(cfg.get('first3f_front_boost', 0.15))
    boost_l = float(cfg.get('last3f_rear_boost', 0.10))
    # pred_first3f 順位が top_f 以内 → FRONT 補正
    if pf_rank is not None and pf_rank <= top_f:
        scores['FRONT'] = min(1.0, scores['FRONT'] + boost_f)
    # pred_last3f 順位が top_l 以内 → REAR 補正
    if pl_rank is not None and pl_rank <= top_l:
        scores['REAR'] = min(1.0, scores['REAR'] + boost_l)
    return scores


def _rsc_label_from_scores(scores: dict, cfg: dict) -> tuple:
    """scores 辞書から (label, confidence) を返す。

    Returns:
        label: 'FRONT' | 'MIDDLE' | 'REAR'
        confidence: 'HIGH' | 'MEDIUM' | 'LOW'
    """
    front_thr = float(cfg.get('front_threshold', 0.45))
    rear_thr  = float(cfg.get('rear_threshold',  0.40))
    high_min  = float(cfg.get('high_confidence_min_score', 0.60))
    best      = max(scores, key=scores.get)
    best_val  = scores[best]
    if best == 'FRONT' and best_val >= front_thr:
        label = 'FRONT'
    elif best == 'REAR' and best_val >= rear_thr:
        label = 'REAR'
    else:
        label = 'MIDDLE'
    confidence = 'HIGH' if best_val >= high_min else ('MEDIUM' if best_val >= 0.40 else 'LOW')
    return label, confidence


def classify_running_style(
    df: "pd.DataFrame",
    params: Optional[dict] = None,
) -> "pd.DataFrame":
    """R27: 過去 zone 履歴 + pred_first3f/last3f の順位から走法分類を行う。

    出力列名:
        RunningStyleLabel: 'FRONT' | 'MIDDLE' | 'REAR'
        RunningStyleConf:  'HIGH' | 'MEDIUM' | 'LOW'
        RunningStyleScore: FRONT スコア (0-100, 高いほど先行傾向)

    利用列:
        zone_4c, zone_3c, zone_2c, zone_1c  (存在する列のみ使用)
        pred_first3f, pred_last3f            (存在する場合のみ利用)
    """
    cfg = ((params or {}).get('running_style_classify', {}) or {})
    if not bool(cfg.get('enabled', True)):
        df['RunningStyleLabel'] = 'MIDDLE'
        df['RunningStyleConf']  = 'LOW'
        df['RunningStyleScore'] = 50.0
        return df

    weights_cfg = cfg.get('zone_weights',
        {'zone_4c': 0.40, 'zone_3c': 0.30, 'zone_2c': 0.20, 'zone_1c': 0.10})
    # 存在する zone 列のみ使用（總和を再正規化するため _rsc_zone_score_row 内で実施済み）
    active_weights = {c: w for c, w in weights_cfg.items() if c in df.columns}
    if not active_weights:
        active_weights = {'zone_4c': 1.0} if 'zone_4c' in df.columns else {}

    # pred_first3f / pred_last3f の順位を事先計算（小さいほど速い = 順位高い）
    n = len(df)
    pf_ser = _num_series(df.get('pred_first3f', pd.Series([np.nan] * n, index=df.index)), np.nan, index=df.index)
    pl_ser = _num_series(df.get('pred_last3f',  pd.Series([np.nan] * n, index=df.index)), np.nan, index=df.index)
    pf_rank_ser = pf_ser.rank(method='min', ascending=True) if pf_ser.notna().sum() > 1 else pd.Series([None] * n, index=df.index)
    pl_rank_ser = pl_ser.rank(method='min', ascending=True) if pl_ser.notna().sum() > 1 else pd.Series([None] * n, index=df.index)

    # ── ベクトル化: for idx ループ → apply ─────────────────────
    def _classify_row(row):
        idx = row.name
        sc = _rsc_zone_score_row(row, active_weights)
        pf_r = int(pf_rank_ser.loc[idx]) if pd.notna(pf_rank_ser.loc[idx]) else None
        pl_r = int(pl_rank_ser.loc[idx]) if pd.notna(pl_rank_ser.loc[idx]) else None
        sc = _rsc_apply_pred_boost(sc, row, pf_r, pl_r, n, cfg)
        lbl, conf = _rsc_label_from_scores(sc, cfg)
        front_raw = sc.get('FRONT', 0.0) - sc.get('REAR', 0.0)
        fscore = float(np.clip(50.0 + front_raw * 100.0, 0.0, 100.0))
        return pd.Series({'_lbl': lbl, '_conf': conf, '_fs': fscore})

    _cls_results = df.apply(_classify_row, axis=1)
    df['RunningStyleLabel'] = _cls_results['_lbl'].values
    df['RunningStyleConf']  = _cls_results['_conf'].values
    df['RunningStyleScore'] = _cls_results['_fs'].values
    return df


@lru_cache(maxsize=8)
def compute_position_fit_v1_1(zone_4c: str) -> float:
    """ベースの位置取り適性（天候補正なし）。"""
    z = normalize_zone_token(zone_4c)
    if z == "FRONT":
        return 90.0
    if z == "MIDDLE":
        return 85.0
    if z == "REAR":
        return 35.0
    return 85.0


@lru_cache(maxsize=8)
def compute_winshape_v1_1(zone_4c: str) -> float:
    """ベースの勝ち形（天候補正なし）。"""
    z = normalize_zone_token(zone_4c)
    if z == "FRONT":
        return 95.0
    if z == "MIDDLE":
        return 85.0
    if z == "REAR":
        return 60.0
    return 85.0


def _track_context(meta: Dict[str, str]) -> Dict[str, float]:
    """metaから天候・馬場の数値特徴を取り出して返す（欠損はnan）。"""
    # キャッシュがあれば即返す
    if '_cached_ctx' in meta:
        return meta['_cached_ctx']
    def _f(k: str) -> float:
        """meta 辞書からキー k の値を float に変換するショートハンド。失敗時は nan。"""
        try:
            return float(str(meta.get(k, "")).strip())
        except Exception:
            return float("nan")

    inside_damage = 1.0 if str(meta.get("inside_damage", "0")) == "1" else 0.0
    cushion_score = _f("cushion_score")
    turf_firm = _f("turf_firmness_score")
    dirt_firm = _f("dirt_firmness_score")

    return {
        "inside_damage": inside_damage,
        "cushion_score": cushion_score,
        "turf_firmness_score": turf_firm,
        "dirt_firmness_score": dirt_firm,
    }


def _track_draw_zone(df: pd.DataFrame) -> pd.Series:
    """枠/馬番系の列から内中外の簡易ゾーンを返す。"""
    draw_raw = pd.Series([np.nan] * len(df), index=df.index, dtype=float)
    for c in ['frame', 'waku', 'draw', 'draw_num', 'post_position']:
        if c in df.columns:
            cand = pd.to_numeric(df[c], errors='coerce')
            if cand.notna().sum() > 0:
                draw_raw = cand
                break
    draw_zone = pd.Series(['middle'] * len(df), index=df.index, dtype=object)
    if draw_raw.notna().sum() > 0:
        if float(draw_raw.max(skipna=True)) <= 8.5:
            draw_zone = draw_raw.apply(lambda x: 'inner' if np.isfinite(x) and x <= 4.0 else ('outer' if np.isfinite(x) and x >= 5.0 else 'middle'))
        else:
            draw_zone = draw_raw.apply(lambda x: 'inner' if np.isfinite(x) and x <= 6.0 else ('outer' if np.isfinite(x) and x >= 13.0 else 'middle'))
    return draw_zone.astype(str)


def _resolve_dynamic_track_variant(meta: Dict[str, str]) -> float:
    """当日の高速/低速馬場を表す補正値（-20〜+20）を解決する。"""
    meta = meta or {}
    score = _meta_float(meta, ['today_track_speed_score', 'track_speed_score', 'surface_speed_score'], default=float('nan'))
    if np.isfinite(score):
        return float(np.clip(score - 50.0, -25.0, 25.0))

    diff = _meta_float(meta, ['day_track_variant', 'track_variant', 'baba_diff', 'baba_delta', 'clock_bias', 'track_speed_bias', 'speed_bias'], default=float('nan'))
    if np.isfinite(diff):
        return float(np.clip(-diff * 10.0, -25.0, 25.0))

    dist, surface = _meta_distance_surface(meta)
    avg_sf = _meta_float(meta, ['today_avg_sec_per_furlong', 'day_avg_sec_per_furlong', 'avg_sec_per_furlong', 'avg_seconds_per_furlong', 'avg_furlong_sec'], default=float('nan'))

    base_sf = 12.10
    if surface == 'turf':
        base_sf = 12.05
    elif surface == 'dirt':
        base_sf = 12.20

    if np.isfinite(dist):
        if dist <= 1400:
            base_sf -= 0.10
        elif dist >= 2000:
            base_sf += 0.06

    sec_delta_score = 0.0
    if np.isfinite(avg_sf):
        sec_delta_score = float(np.clip((base_sf - avg_sf) * 55.0, -12.0, 12.0))

    cushion_score = _meta_float(meta, ['cushion_score'], default=float('nan'))
    cushion_delta = ((cushion_score - 50.0) / 50.0) * 6.0 if np.isfinite(cushion_score) else 0.0

    firmness_key = 'turf_firmness_score' if surface == 'turf' else 'dirt_firmness_score'
    firmness_score = _meta_float(meta, [firmness_key], default=float('nan'))
    firmness_delta = ((firmness_score - 50.0) / 50.0) * 5.0 if np.isfinite(firmness_score) else 0.0

    wet_keys = ['wetness_score_turf_goal', 'wetness_score_turf_4c'] if surface == 'turf' else ['wetness_score_dirt_goal', 'wetness_score_dirt_4c']
    wet_vals = []
    for k in wet_keys:
        v = _meta_float(meta, [k], default=float('nan'))
        if np.isfinite(v):
            wet_vals.append(float(v))

    wet_delta = 0.0
    if wet_vals:
        wet_mean = float(np.mean(wet_vals))
        if surface == 'turf':
            wet_delta = -float(np.clip((wet_mean - 35.0) / 65.0 * 8.0, -8.0, 8.0))
        else:
            wet_delta = -float(np.clip((wet_mean - 30.0) / 70.0 * 4.0, -4.0, 4.0))

    return float(np.clip(sec_delta_score + 0.55 * cushion_delta + 0.35 * firmness_delta + wet_delta, -20.0, 20.0))


def _resolve_dynamic_lane_bias(meta: Dict[str, str]) -> float:
    """当日の内外バイアスを表す補正値（内有利=正、外有利=負）を返す。"""
    meta = meta or {}
    combined = ' '.join(str(meta.get(k, '')) for k in ['bias', 'map_summary', 'course_info', 'rail_course'])

    inner = 0.0
    outer = 0.0
    if re.search(r'内有利|イン有利|内伸び|最内有利|ロスなく', combined):
        inner += 1.0
    if re.search(r'外有利|外伸び|外差し|差し有利|大外', combined):
        outer += 1.0
    if re.search(r'フラット|内外同等|内外なし', combined):
        inner *= 0.25
        outer *= 0.25

    inside_damage = 1.0 if str(meta.get('inside_damage', '0')) == '1' else 0.0
    if inside_damage >= 1.0:
        outer += 0.8
        inner -= 0.4

    rail_offset = _meta_float(meta, ['rail_offset_m', 'rail_offset_m_text'], default=float('nan'))
    if np.isfinite(rail_offset) and rail_offset > 0.0 and inside_damage < 1.0:
        inner += min(0.7, float(rail_offset) / 6.0 * 0.7)

    if _is_wet_track(meta) and inside_damage >= 1.0:
        outer += 0.3

    return float(np.clip(inner - outer, -1.5, 1.5))


def apply_dynamic_track_bias_features_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> pd.DataFrame:
    """当日の馬場差・内外バイアス・時計の出やすさを馬ごとの適性へ落とし込む。"""
    if df is None or len(df) == 0:
        return df

    d = df.copy()
    z = d.get('zone_4c', pd.Series(['MIDDLE'] * len(d), index=d.index)).astype(str).map(normalize_zone_token)
    draw_zone = _track_draw_zone(d)
    lane_balance = _resolve_dynamic_lane_bias(meta)
    variant = _resolve_dynamic_track_variant(meta)

    d['DynamicTrackLaneBiasScore'] = float(np.clip(50.0 + lane_balance * 20.0, 0.0, 100.0))
    d['DynamicTrackSpeedScore'] = float(np.clip(50.0 + variant * 2.0, 0.0, 100.0))
    d['DynamicTrackVariant'] = float(variant)

    inner_mask = (draw_zone == 'inner')
    outer_mask = (draw_zone == 'outer')
    middle_mask = ~(inner_mask | outer_mask)

    lane_bonus = pd.Series([0.0] * len(d), index=d.index, dtype=float)
    if lane_balance >= 0.0:
        lane_bonus = lane_bonus + inner_mask.astype(float) * abs(lane_balance) * 12.0
        lane_bonus = lane_bonus + middle_mask.astype(float) * abs(lane_balance) * 3.5
        lane_bonus = lane_bonus + (z == 'FRONT').astype(float) * abs(lane_balance) * 2.5
        lane_bonus = lane_bonus - outer_mask.astype(float) * abs(lane_balance) * 4.0
    else:
        lane_bonus = lane_bonus + outer_mask.astype(float) * abs(lane_balance) * 12.0
        lane_bonus = lane_bonus + middle_mask.astype(float) * abs(lane_balance) * 3.5
        lane_bonus = lane_bonus + (z == 'REAR').astype(float) * abs(lane_balance) * 2.5
        lane_bonus = lane_bonus - inner_mask.astype(float) * abs(lane_balance) * 4.0
    d['DynamicTrackLaneSuit'] = _clip0100((50.0 + lane_bonus))

    ability = _num_series(d.get('Ability', 50.0), 50.0, index=d.index)
    tf = _num_series(d.get('TimeFit', 50.0), 50.0, index=d.index)
    ff = _num_series(d.get('FactorFit', 50.0), 50.0, index=d.index)
    mich = _num_series(d.get('MichiakuFit', ff), 50.0, index=d.index)
    cons = _num_series(d.get('Consist', 50.0), 50.0, index=d.index)
    cc = _num_series(d.get('CommentCondition', 50.0), 50.0, index=d.index)
    pace = _num_series(d.get('PaceFit', 50.0), 50.0, index=d.index)
    pf = _num_series(d.get('pred_first3f', np.nan), np.nan, index=d.index)

    if pf.notna().sum() > 1 and float(pf.max()) != float(pf.min()):
        early_fast01 = _clip_series(((float(pf.max()) - pf) / (float(pf.max()) - float(pf.min()))), 0.0, 1.0)
    else:
        early_fast01 = pd.Series([0.5] * len(d), index=d.index, dtype=float)

    fast_track_fit = _clip0100((0.42 * ability + 0.26 * tf + 0.18 * (early_fast01 * 100.0) + 0.14 * pace))
    slow_track_fit = _clip0100((0.32 * ff + 0.28 * mich + 0.22 * cons + 0.18 * cc))
    neutral_track_fit = _clip0100((0.50 * fast_track_fit + 0.50 * slow_track_fit))

    fast_w = float(np.clip(variant / 20.0, 0.0, 1.0))
    slow_w = float(np.clip(-variant / 20.0, 0.0, 1.0))
    neutral_w = float(np.clip(1.0 - max(fast_w, slow_w), 0.0, 1.0))
    d['DynamicTrackSpeedSuit'] = _clip0100((neutral_w * neutral_track_fit + fast_w * fast_track_fit + slow_w * slow_track_fit))

    mapfit = _num_series(d.get('MapFit', 50.0), 50.0, index=d.index)
    posfit = _num_series(d.get('PosFit', 50.0), 50.0, index=d.index)
    d['DynamicTrackConditionAdvantage'] = _clip0100((
        0.34 * cc
        + 0.18 * mapfit
        + 0.16 * posfit
        + 0.18 * d['DynamicTrackLaneSuit']
        + 0.14 * d['DynamicTrackSpeedSuit']
    ))
    return d


def compute_position_fit_adjusted(zone_4c: str, meta: Dict[str, str]) -> float:
    """位置取り(PosFit)を天候/馬場で補正。

    目的: ユーザー要望の「馬場/天候に関わる所は補正」
    - 道悪: 先行有利寄り（REARは減点）
    - 内側傷み: 内を避けられる想定で MIDDLE を上げる（枠が無いのでゾーンで近似）

    ※補正は小さめにして破壊しない。
    """
    base = compute_position_fit_v1_1(zone_4c)
    z = normalize_zone_token(zone_4c)

    wet_mode = _is_wet_track(meta)
    ctx = _track_context(meta)

    delta = 0.0
    if wet_mode:
        if z == "FRONT":
            delta += 3.0
        elif z == "MIDDLE":
            delta += 1.0
        else:  # REAR
            delta -= 5.0

    if ctx.get("inside_damage", 0.0) >= 1.0:
        if z == "FRONT":
            delta -= 3.0
        elif z == "MIDDLE":
            delta += 3.0

    return clamp(base + delta, 0.0, 100.0)


def compute_winshape_adjusted(zone_4c: str, meta: Dict[str, str]) -> float:
    """勝ち形(WinShape)を天候/馬場で補正。"""
    base = compute_winshape_v1_1(zone_4c)
    z = normalize_zone_token(zone_4c)

    wet_mode = _is_wet_track(meta)
    ctx = _track_context(meta)

    delta = 0.0
    if wet_mode:
        if z == "FRONT":
            delta += 3.0
        elif z == "MIDDLE":
            delta += 1.0
        else:
            delta -= 5.0

    if ctx.get("inside_damage", 0.0) >= 1.0:
        if z == "FRONT":
            delta -= 2.0
        elif z == "MIDDLE":
            delta += 2.0

    return clamp(base + delta, 0.0, 100.0)


def compute_consistency_from_speed_hist(df: pd.DataFrame) -> pd.Series:
    """過去速度ヒストリから安定性スコア (0–100) の Series を返す。"""
    n = len(df)
    ranges_arr = np.full(n, np.nan)
    counts_arr = np.zeros(n, dtype=int)
    for i, s in enumerate(df["speed_hist"].tolist()):
        vals = parse_speed_hist(s)
        counts_arr[i] = len(vals)
        if len(vals) >= 2:
            ranges_arr[i] = max(vals) - min(vals)

    # R36: 全要素 NaN の場合 np.nanmax が RuntimeWarning を出すため事前にガード
    finite_mask = np.isfinite(ranges_arr)
    rmax = float(np.nanmax(ranges_arr[finite_mask])) if finite_mask.any() else np.nan

    # ベクトル化: ループなし
    out_arr = np.full(n, 70.0)
    if np.isfinite(rmax) and rmax > 0:
        valid = (counts_arr > 0) & finite_mask
        out_arr[valid] = 100.0 * (1.0 - ranges_arr[valid] / rmax)
    return _make_series(np.clip(out_arr, 0.0, 100.0), df.index)


def parse_map_summary_to_rates(map_summary: str) -> Optional[Dict[str, float]]:
    """ポジションマップサマリ文字列をゾーン比率 dict に変換する。解析失敗時は None。"""
    if map_summary is None:
        return None
    s = str(map_summary).strip()
    if s == "" or s.lower() == "unknown":
        return None

    rates: Dict[str, float] = {}
    patterns = {
        "FRONT": r"(FRONT|F)\s*[:=]\s*([0-9]+(?:\.[0-9]+)?)",
        "MIDDLE": r"(MIDDLE|M)\s*[:=]\s*([0-9]+(?:\.[0-9]+)?)",
        "REAR": r"(REAR|R)\s*[:=]\s*([0-9]+(?:\.[0-9]+)?)",
    }
    for k, pat in patterns.items():
        m = re.search(pat, s, flags=re.IGNORECASE)
        if m:
            v = float(m.group(2))
            if v > 1.0:
                v = v / 100.0
            rates[k] = v

    return rates if len(rates) else None


def compute_mapfit_v1_1(
    df: pd.DataFrame,
    map_summary: str,
    map_rates: Optional[Dict[str, float]] = None,
) -> pd.Series:
    """MapFit (v1.1)

    Priority:
    1) map_rates (from heatmap extraction): {'FRONT':0..1,'MIDDLE':0..1,'REAR':0..1}
    2) parse from map_summary text like 'F=0.24 M=0.30 R=0.19'
    3) Unknown fallback: FRONT/MIDDLE=80, REAR=30
    """
    rates = map_rates if map_rates is not None else parse_map_summary_to_rates(map_summary)
    # zone_4c はすでに normalize_zone_token で正規化済み（compute_scores_v1_1 先頭で処理済み）
    z4_vals = df["zone_4c"].values  # ndarray: 'FRONT'/'MIDDLE'/'REAR'

    if rates is None:
        # REAR=30, それ以外=80 を np.where で高速計算
        result = np.where(z4_vals == "REAR", 30.0, 80.0).astype(float)
        return _make_series(result, df.index)

    # rates が 0..100 の場合は 0..1 に正規化
    rates_01 = {k: (v / 100.0 if v > 1.0 else float(v)) for k, v in rates.items()}
    mid_rate = rates_01.get("MIDDLE", 0.20)
    # np.select でゾーン→スコア変換（pandas .map を排除）
    front_s = float(np.clip(100.0 * rates_01.get("FRONT",  mid_rate), 0.0, 100.0))
    mid_s   = float(np.clip(100.0 * rates_01.get("MIDDLE", mid_rate), 0.0, 100.0))
    rear_s  = float(np.clip(100.0 * rates_01.get("REAR",   mid_rate), 0.0, 100.0))
    result = np.select(
        [z4_vals == "FRONT", z4_vals == "MIDDLE", z4_vals == "REAR"],
        [front_s,            mid_s,               rear_s],
        default=mid_s,
    ).astype(float)
    return _make_series(result, df.index)


def compute_timefit_v1_1(df: pd.DataFrame) -> pd.Series:
    """前後3Fタイム予測値からタイムフィットスコア (0–100) を計算する。"""
    f = _num_series(df, 'pred_first3f', np.nan, index=df.index)
    l = _num_series(df, 'pred_last3f', np.nan, index=df.index)
    # ── ベクトル化: ループ廃止 ────────────────────────────────
    valid_mask = f.notna() & l.notna()
    diff = (f - l).abs()
    score = (100.0 * np.exp(-diff)).where(valid_mask, 0.0)
    return score.fillna(0.0).astype(float)


def compute_upside_v1_1(speed_max: pd.Series) -> pd.Series:
    """最高速度 Series からアップサイドスコア (0–100) を計算する。"""
    s = _num_series(speed_max, index=getattr(speed_max, 'index', None))
    order = s.rank(ascending=False, method="average")
    n = len(s)
    if n <= 1:
        return pd.Series([50.0] * n, index=s.index, dtype=float)
    return ((n - order) / (n - 1) * 100.0).fillna(50.0).astype(float)


def _meta_distance_surface(meta: Dict[str, str]) -> tuple[float, str]:
    """    メタデータ辞書から距離（float）と馬場種別文字列を取り出す。

    Returns:
        tuple[float, str]: (distance_m, surface)  surface は 'turf'/'dirt'/'障害' 等。

    """
    meta = meta or {}
    # キャッシュがあれば即返す
    if '_cached_dist' in meta:
        return meta['_cached_dist'], meta.get('_cached_surface', 'unknown')
    dist = float('nan')
    try:
        dist = float(meta.get('distance', np.nan))
    except Exception:
        try:
            s = ' '.join(str(meta.get(k, '')) for k in ['race', 'course_info', 'surface'])
            m = re.search(r'(\d{3,4})\s*m', s, flags=re.IGNORECASE)
            if not m:
                m = re.search(r'(\d{3,4})', s)
            if m:
                dist = float(m.group(1))
        except Exception:
            dist = float('nan')
    surface_txt = ' '.join(str(meta.get(k, '')) for k in ['surface', 'race', 'course_info']).lower()
    if ('ダート' in surface_txt) or ('ダ' in surface_txt):
        surface = 'dirt'
    elif ('芝' in surface_txt) or ('turf' in surface_txt):
        surface = 'turf'
    else:
        surface = 'unknown'
    return dist, surface


def compute_gatefit_v1_1(df: pd.DataFrame, meta: Dict[str, str]) -> pd.Series:
    """ゲート適性スコア (0–100) を計算する。コメントゲート評価とコース条件を合算。"""
    cg = _num_series(df, 'CommentGate', 50.0)
    f = _num_series(df, 'pred_first3f', np.nan, index=df.index)
    if f.notna().sum() > 1 and float(f.max()) != float(f.min()):
        f01 = _clip_series(((float(f.max()) - f) / (float(f.max()) - float(f.min()))), 0.0, 1.0)
    else:
        f01 = pd.Series([0.5] * len(df), index=df.index, dtype=float)
    dist, surface = _meta_distance_surface(meta)
    if surface == 'dirt' and np.isfinite(dist) and dist <= 1200:
        gate_mult = 1.60
        w_comment = 0.88
    elif surface == 'dirt' and np.isfinite(dist) and dist <= 1400:
        gate_mult = 1.35
        w_comment = 0.84
    else:
        gate_mult = 1.00
        w_comment = 0.72
    gate_base = _clip0100((50.0 + (cg - 50.0) * gate_mult))
    out = _clip0100((w_comment * gate_base + (1.0 - w_comment) * (f01 * 100.0)))
    return _num_series(out, 50.0, index=df.index)


def compute_conditionfit_v1_1(df: pd.DataFrame, meta: Dict[str, str]) -> pd.Series:
    """馬場・距離条件適性スコア (0–100) を計算する。"""
    cc = _num_series(df, 'CommentCondition', 50.0)
    mf = _num_series(df, 'MapFit', 50.0)
    pf = _num_series(df, 'PosFit', 50.0)
    ff = _num_series(df, 'FactorFit', 50.0)
    dyn_lane = _num_series(df, 'DynamicTrackLaneSuit', 50.0)
    dyn_speed = _num_series(df, 'DynamicTrackSpeedSuit', 50.0)
    dyn_adv = _num_series(df, 'DynamicTrackConditionAdvantage', 50.0)
    dist, surface = _meta_distance_surface(meta)

    base = 0.43 * cc + 0.19 * mf + 0.14 * pf + 0.16 * dyn_adv + 0.08 * dyn_speed
    base = base + 0.06 * (dyn_lane - 50.0)
    if _is_wet_track(meta):
        base = base + 0.05 * (ff - 50.0) + 0.06 * (dyn_adv - 50.0)
    if surface == 'dirt' and np.isfinite(dist) and dist <= 1200:
        base = base + 0.16 * (cc - 50.0) + 0.04 * (dyn_speed - 50.0)
    elif surface == 'dirt' and np.isfinite(dist) and dist <= 1400:
        base = base + 0.08 * (cc - 50.0) + 0.03 * (dyn_speed - 50.0)
    return _num_series(base, 50.0, index=df.index, lower=0.0, upper=100.0)



def _pedigree_pick_series(df: pd.DataFrame, candidates: list[str], default='') -> pd.Series:
    """候補列から最初に見つかった列を返す。見つからなければ default 値の Series を返す。"""
    for c in candidates:
        if c in df.columns:
            return df[c]
    return pd.Series([default] * len(df), index=df.index)


def _pedigree_parse_num_list(val: object) -> list[float]:
    """文字列から数値列を抽出して返す。Dosage や 4x4 表記の簡易解析に使う。"""
    if val is None:
        return []
    s = str(val).strip()
    if not s or s.lower() in {'nan', 'none'}:
        return []
    try:
        return [float(x) for x in re.findall(r'-?\d+(?:\.\d+)?', s)]
    except Exception:
        return []


def _pedigree_text_key(val: object) -> str:
    """血統カテゴリ文字列の粗い正規化キーを返す。"""
    s = '' if val is None else str(val)
    s = s.upper().replace('　', ' ').replace('_', ' ')
    s = re.sub(r'[\s,;|]+', ' ', s)
    return s.strip()


def _pedigree_category_counts_from_text(val: object) -> dict:
    """Brilliant / Intermediate / Classic / Solid / Professional を文字列から抽出する。"""
    s = _pedigree_text_key(val)
    out = {'b': 0.0, 'i': 0.0, 'c': 0.0, 's': 0.0, 'p': 0.0}
    if not s:
        return out
    label_patterns = {
        'b': [r'BRILLIANT', r'(^|[ /&,+-])B([ /&,+-]|$)'],
        'i': [r'INTERMEDIATE', r'(^|[ /&,+-])I([ /&,+-]|$)'],
        'c': [r'CLASSIC', r'(^|[ /&,+-])C([ /&,+-]|$)'],
        's': [r'(^|[ /&,+-])SOLID([ /&,+-]|$)', r'(^|[ /&,+-])S([ /&,+-]|$)'],
        'p': [r'PROFESSIONAL', r'(^|[ /&,+-])P([ /&,+-]|$)'],
    }
    for k, pats in label_patterns.items():
        if any(re.search(p, s) for p in pats):
            out[k] = 1.0
    return out


def _pedigree_pct_value(val: object) -> float:
    """0-1 or 0-100 を 0-100 スケールに揃えて返す。"""
    try:
        x = float(val)
    except Exception:
        return float('nan')
    if not np.isfinite(x):
        return float('nan')
    if abs(x) <= 1.5:
        x *= 100.0
    return float(clamp(x, 0.0, 100.0))


def _pedigree_profile_fit_from_points(
    brilliant: float,
    intermediate: float,
    classic: float,
    solid: float,
    professional: float,
    dist: float,
    surface: str,
    is_tokyo1400: bool = False,
) -> float:
    """Dosage / Chef profile を距離・コース条件に対する適性スコアへ変換する。"""
    b = max(0.0, float(brilliant or 0.0))
    i = max(0.0, float(intermediate or 0.0))
    c = max(0.0, float(classic or 0.0))
    s = max(0.0, float(solid or 0.0))
    p = max(0.0, float(professional or 0.0))
    raw_total = b + i + c + s + p
    if raw_total <= 0.0:
        return 50.0
    total = max(1e-9, raw_total)
    speed_share = (1.30 * b + 1.00 * i + 0.55 * c) / total
    classic_share = c / total
    stamina_share = (1.25 * p + 1.00 * s + 0.45 * c) / total
    if surface == 'dirt':
        if np.isfinite(dist) and dist <= 1400:
            target_speed, target_classic = 0.62, 0.20
        elif np.isfinite(dist) and dist <= 1800:
            target_speed, target_classic = 0.54, 0.24
        else:
            target_speed, target_classic = 0.46, 0.28
    else:
        if np.isfinite(dist) and dist <= 1400:
            target_speed, target_classic = 0.64, 0.24
        elif np.isfinite(dist) and dist <= 1800:
            target_speed, target_classic = 0.56, 0.29
        elif np.isfinite(dist) and dist <= 2200:
            target_speed, target_classic = 0.47, 0.31
        else:
            target_speed, target_classic = 0.38, 0.28
    base = 100.0 - abs(speed_share - target_speed) * 120.0 - abs(classic_share - target_classic) * 60.0
    excess_stamina = max(0.0, stamina_share - (1.0 - target_speed + 0.08))
    base -= excess_stamina * 35.0
    if is_tokyo1400:
        base += 8.0 * classic_share + 4.0 * speed_share - 2.0 * stamina_share
    confidence = min(1.0, raw_total / 12.0)
    base = 50.0 + (base - 50.0) * (0.42 + 0.58 * confidence)
    return float(clamp(base, 0.0, 100.0))


def add_high_granularity_pedigree_features(
    df: pd.DataFrame,
    meta: Dict[str, str],
    params: Optional[dict] = None,
) -> pd.DataFrame:
    """高粒度血統特徴を計算して Pedigree* 列を付与する。未入力時は中立 50 に寄せる。"""
    _ = params or {}
    d = df.copy()
    if d is None or len(d) == 0:
        return d

    dist, surface = _meta_distance_surface(meta)
    is_tokyo1400 = _is_tokyo_turf_1400(meta)

    dosage_cols = ['dosage_brilliant', 'dosage_intermediate', 'dosage_classic', 'dosage_solid', 'dosage_professional']
    chef_flag_cols = ['chef_brilliant_flag', 'chef_intermediate_flag', 'chef_classic_flag', 'chef_solid_flag', 'chef_professional_flag']
    tokyo_emb_cols = [
        'tokyo1400_slope_lap_rank_emb1', 'tokyo1400_slope_lap_rank_emb2',
        'tokyo1400_slope_lap_rank_emb3', 'tokyo1400_slope_lap_rank_emb4',
        'tokyo1400_lap_rank_emb1', 'tokyo1400_lap_rank_emb2',
        'tokyo1400_lap_rank_emb3', 'tokyo1400_lap_rank_emb4',
    ]

    # ── 完全ベクトル化: 行処理を列操作に変換 ──────────────────────
    _dist, _surface, _is_tok = dist, surface, is_tokyo1400
    _target_depth = (3.9 if (np.isfinite(_dist) and _dist <= 1400) else
                     4.2 if (np.isfinite(_dist) and _dist <= 1800) else
                     4.6 if (np.isfinite(_dist) and _dist <= 2200) else 4.9)
    n_rows = len(d)

    # ── 1) Dosage profile (ベクトル化) ──
    _dosage_mat = np.full((n_rows, 5), np.nan, dtype=float)
    for j, c in enumerate(dosage_cols):
        if c in d.columns:
            _dosage_mat[:, j] = pd.to_numeric(d[c], errors='coerce').values
    # 有効な行（2列以上 finite かつ合計>0）
    _dosage_valid = (np.sum(np.isfinite(_dosage_mat), axis=1) >= 2) & (np.nansum(np.where(np.isfinite(_dosage_mat), _dosage_mat, 0.0), axis=1) > 0)
    _dosage_mat_clipped = np.where(np.isfinite(_dosage_mat), np.maximum(0.0, _dosage_mat), 0.0)
    dosage_scores = []
    for i in range(n_rows):
        if _dosage_valid[i]:
            b, ii, c0, s0, p0 = _dosage_mat_clipped[i]
        else:
            _dp = str(d.iloc[i].get('dosage_profile', '') or '') if hasattr(d.iloc[i], 'get') else ''
            nums = _pedigree_parse_num_list(_dp)
            if len(nums) >= 5:
                b, ii, c0, s0, p0 = [max(0.0, float(x)) for x in nums[:5]]
            else:
                b = ii = c0 = s0 = p0 = 0.0
        dosage_scores.append(_pedigree_profile_fit_from_points(b, ii, c0, s0, p0, _dist, _surface, is_tokyo1400=_is_tok))

    # ── 2) Chef-de-race (ベクトル化) ──
    _chef_mat = np.full((n_rows, 5), np.nan, dtype=float)
    for j, c in enumerate(chef_flag_cols):
        if c in d.columns:
            _chef_mat[:, j] = pd.to_numeric(d[c], errors='coerce').values
    _chef_flag_mat = np.where(np.isfinite(_chef_mat), (_chef_mat >= 0.5).astype(float), np.nan)
    _chef_has_data = np.sum(np.isfinite(_chef_flag_mat), axis=1) > 0
    chef_scores = []
    for i in range(n_rows):
        if _chef_has_data[i]:
            cf = np.where(np.isfinite(_chef_flag_mat[i]), _chef_flag_mat[i], 0.0)
            b, ii, c0, s0, p0 = cf
        else:
            _row_i = d.iloc[i]
            _txt = ' '.join([str(_row_i.get('chef_race_class', '') or ''),
                             str(_row_i.get('chef_de_race', '') or ''),
                             str(_row_i.get('chef_flags', '') or '')]).strip()
            parsed = _pedigree_category_counts_from_text(_txt)
            if sum(parsed.values()) > 0.0:
                b, ii, c0, s0, p0 = parsed['b'], parsed['i'], parsed['c'], parsed['s'], parsed['p']
            else:
                b = ii = c0 = s0 = p0 = 0.0
        chef_scores.append(
            _pedigree_profile_fit_from_points(b, ii, c0, s0, p0, _dist, _surface, is_tokyo1400=_is_tok)
            if (b + ii + c0 + s0 + p0) > 0.0 else 50.0
        )

    # ── 3) BM-Sire2 (ベクトル化) ──
    _bm_rate_cols = ['bm_sire2_tokyo1400_rate', 'bm_sire2_course_rate', 'bm_sire2_distance_rate']
    _bm_rates_mat = np.full((n_rows, 3), np.nan, dtype=float)
    for j, c in enumerate(_bm_rate_cols):
        if c in d.columns:
            _bm_rates_mat[:, j] = pd.to_numeric(d[c], errors='coerce').values
    _bm_text_cols = ['bm_sire2', 'bm_sire2_profile', 'bm_sire2_type']
    bm_scores = []
    for i in range(n_rows):
        _row_i = d.iloc[i]
        bm_text = ' '.join([str(_row_i.get(c, '') or '') for c in _bm_text_cols]).strip()
        bm_rates_valid = [float(v) for v in _bm_rates_mat[i] if np.isfinite(v)]
        bm_counts = _pedigree_category_counts_from_text(bm_text)
        bm_profile_fit = (_pedigree_profile_fit_from_points(
            bm_counts['b'], bm_counts['i'], bm_counts['c'], bm_counts['s'], bm_counts['p'],
            _dist, _surface, is_tokyo1400=_is_tok)
            if sum(bm_counts.values()) > 0.0 else 50.0)
        bm_fit = (0.60 * float(np.mean(bm_rates_valid)) + 0.40 * bm_profile_fit) if bm_rates_valid else bm_profile_fit
        bm_scores.append(float(clamp(bm_fit, 0.0, 100.0)))

    # ── 4) Cross depth (ベクトル化可能な部分のみ) ──
    _cd_col = 'cross_depth'
    _cross_depth_vec = pd.to_numeric(d[_cd_col], errors='coerce').values if _cd_col in d.columns else np.full(n_rows, np.nan)
    cross_scores = []
    for i in range(n_rows):
        if np.isfinite(_cross_depth_vec[i]):
            avg_depth = float(_cross_depth_vec[i])
            density = 1.0
        else:
            _row_i = d.iloc[i]
            raw_cross = ' '.join([str(_row_i.get(c, '') or '') for c in ['cross_depth', 'cross_pattern', 'inbreed_depth', 'inbreed_pattern']]).strip()
            nums = _pedigree_parse_num_list(raw_cross)
            if len(nums) >= 2 and (('X' in raw_cross.upper()) or ('×' in raw_cross)):
                pair_vals = [(nums[k] + nums[k + 1]) / 2.0 for k in range(0, len(nums) - 1, 2)]
                avg_depth = float(np.mean(pair_vals)) if pair_vals else float('nan')
                density = float(len(pair_vals))
            elif nums:
                avg_depth = float(np.mean(nums[:min(4, len(nums))]))
                density = float(len(nums[:min(4, len(nums))]))
            else:
                avg_depth = float('nan')
                density = 0.0
        if np.isfinite(avg_depth):
            cross_fit = 100.0 - abs(avg_depth - _target_depth) * 18.0 - max(0.0, density - 3.0) * 4.0
            if _is_tok and 3.5 <= avg_depth <= 4.5:
                cross_fit += 6.0
            cross_scores.append(float(clamp(cross_fit, 0.0, 100.0)))
        else:
            cross_scores.append(50.0)

    # ── 5) Tokyo 1400 embedding (ベクトル化) ──
    _emb_mat = np.full((n_rows, len(tokyo_emb_cols)), np.nan, dtype=float)
    for j, c in enumerate(tokyo_emb_cols):
        if c in d.columns:
            _emb_mat[:, j] = pd.to_numeric(d[c], errors='coerce').values
    _emb_valid_counts = np.sum(np.isfinite(_emb_mat), axis=1)
    # stat cols for fallback
    _stat_cols = ['tokyo1400_slope_lap_rank_mean', 'tokyo1400_slope_lap_rank_median',
                  'tokyo1400_slope_lap_rank_top3_rate', 'tokyo1400_slope_lap_rank_top5_rate']
    _stat_mat = np.full((n_rows, 4), np.nan, dtype=float)
    for j, c in enumerate(_stat_cols):
        if c in d.columns:
            _stat_mat[:, j] = pd.to_numeric(d[c], errors='coerce').values
    tokyo_scores = []
    for i in range(n_rows):
        emb_valid = [float(v) for v in _emb_mat[i] if np.isfinite(v)]
        if emb_valid:
            emb4 = emb_valid[:4] + [0.0] * max(0, 4 - len(emb_valid[:4]))
            tokyo_fit = 50.0 + 18.0 * emb4[0] + 12.0 * emb4[1] - 8.0 * abs(emb4[2]) + 6.0 * emb4[3]
        else:
            mean_rank = _pedigree_pct_value(_stat_mat[i, 0])
            median_rank = _pedigree_pct_value(_stat_mat[i, 1])
            top3_rate = _pedigree_pct_value(_stat_mat[i, 2])
            top5_rate = _pedigree_pct_value(_stat_mat[i, 3])
            stat_parts = []
            if np.isfinite(mean_rank) and mean_rank > 1.5:
                stat_parts.append(clamp(100.0 - (mean_rank - 1.0) * 100.0 / 17.0, 0.0, 100.0))
            if np.isfinite(median_rank) and median_rank > 1.5:
                stat_parts.append(clamp(100.0 - (median_rank - 1.0) * 100.0 / 17.0, 0.0, 100.0))
            if np.isfinite(top3_rate):
                stat_parts.append(top3_rate)
            if np.isfinite(top5_rate):
                stat_parts.append(0.8 * top5_rate)
            if stat_parts:
                tokyo_fit = float(np.mean(stat_parts))
            elif _is_tok:
                tokyo_fit = 0.55 * dosage_scores[i] + 0.25 * bm_scores[i] + 0.20 * cross_scores[i]
            else:
                tokyo_fit = 50.0
        if not _is_tok:
            tokyo_fit = 50.0 + (float(tokyo_fit) - 50.0) * 0.55
        tokyo_scores.append(float(clamp(tokyo_fit, 0.0, 100.0)))

    d['PedigreeBmSire2Fit'] = _num_series(pd.Series(bm_scores, index=d.index), 50.0, index=d.index, lower=0.0, upper=100.0)
    d['PedigreeCrossDepthFit'] = _num_series(pd.Series(cross_scores, index=d.index), 50.0, index=d.index, lower=0.0, upper=100.0)
    d['PedigreeDosageFit'] = _num_series(pd.Series(dosage_scores, index=d.index), 50.0, index=d.index, lower=0.0, upper=100.0)
    d['PedigreeChefRaceFit'] = _num_series(pd.Series(chef_scores, index=d.index), 50.0, index=d.index, lower=0.0, upper=100.0)
    d['PedigreeTokyo1400LapFit'] = _num_series(pd.Series(tokyo_scores, index=d.index), 50.0, index=d.index, lower=0.0, upper=100.0)

    if is_tokyo1400:
        fine_w = {'bm': 0.18, 'cross': 0.18, 'dosage': 0.22, 'chef': 0.14, 'tokyo': 0.28}
    else:
        fine_w = {'bm': 0.20, 'cross': 0.20, 'dosage': 0.28, 'chef': 0.18, 'tokyo': 0.14}
    pedigree_fine = (
        fine_w['bm'] * d['PedigreeBmSire2Fit']
        + fine_w['cross'] * d['PedigreeCrossDepthFit']
        + fine_w['dosage'] * d['PedigreeDosageFit']
        + fine_w['chef'] * d['PedigreeChefRaceFit']
        + fine_w['tokyo'] * d['PedigreeTokyo1400LapFit']
    ) / max(1e-9, float(sum(fine_w.values())))
    signal_count = (
        (d['PedigreeBmSire2Fit'].sub(50.0).abs() >= 1.0).astype(float)
        + (d['PedigreeCrossDepthFit'].sub(50.0).abs() >= 1.0).astype(float)
        + (d['PedigreeDosageFit'].sub(50.0).abs() >= 1.0).astype(float)
        + (d['PedigreeChefRaceFit'].sub(50.0).abs() >= 1.0).astype(float)
        + (d['PedigreeTokyo1400LapFit'].sub(50.0).abs() >= 1.0).astype(float)
    )
    confidence_scale = _clip_series((0.45 + 0.11 * signal_count), 0.45, 1.0)
    d['PedigreeFineFit'] = _num_series(50.0 + (pedigree_fine - 50.0) * confidence_scale, 50.0, index=d.index, lower=0.0, upper=100.0)
    d['PedigreeFineDelta'] = _clip_series((d['PedigreeFineFit'] - 50.0), -20.0, 20.0).astype(float)
    return d


def add_course_profile_features(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> pd.DataFrame:
    """競馬場コース特性を既存特徴量へ落とし込み、CourseProfileFit 系列を付与する。"""
    _ = params or {}
    d = df.copy()
    if d is None or len(d) == 0:
        return d
    d = add_high_granularity_pedigree_features(d, meta, params)
    venue, surface, profile = _resolve_course_profile(meta)
    dist, _ = _meta_distance_surface(meta)
    style_bias = dict(profile.get('style_bias', {}) or {})
    distance_key = str(profile.get('distance_key', '') or '')
    distance_patch = dict(profile.get('distance_patch', {}) or {})
    distance_style_bias = dict(distance_patch.get('style_bias', {}) or {})
    distance_draw_bias = dict(distance_patch.get('draw_bias', {}) or {})
    distance_source = str(profile.get('distance_source', '') or '') if distance_key else ''
    try:
        distance_confidence = clamp(float(profile.get('distance_confidence', 1.0) or 1.0), 0.35, 1.0) if distance_key else 0.0
    except Exception:
        distance_confidence = 1.0 if distance_key else 0.0
    is_tokyo1400 = _is_tokyo_turf_1400(meta)
    rail_setting = str(profile.get('rail_setting', '') or _infer_rail_setting(meta) or '')
    class_id = _infer_race_class_id(meta)
    class_ref = TOKYO_TURF_1400_CLASS_PACE.get(class_id, {}) if is_tokyo1400 else {}
    month = _infer_race_month(meta)
    bucket = _course_profile_distance_bucket(dist)

    if 'RunningStyleLabel' in d.columns:
        style_col = d['RunningStyleLabel'].astype(str).map(normalize_zone_token)
    else:
        style_col = (d['zone_4c'] if 'zone_4c' in d.columns else pd.Series('MIDDLE', index=d.index)).astype(str).map(normalize_zone_token)

    style_fit = style_col.map(
        lambda z: clamp(50.0 + 24.0 * float(style_bias.get(z, 0.0) or 0.0), 0.0, 100.0)
    ).astype(float)

    pf = _num_series(d, 'pred_first3f', np.nan) if 'pred_first3f' in d.columns else pd.Series(np.nan, index=d.index, dtype=float)
    pl = _num_series(d, 'pred_last3f', np.nan) if 'pred_last3f' in d.columns else pd.Series(np.nan, index=d.index, dtype=float)
    early_speed = (_series_norm01(pf, lower_is_better=True, neutral=0.5) * 100.0).astype(float)
    late_speed = (_series_norm01(pl, lower_is_better=True, neutral=0.5) * 100.0).astype(float)

    ability = _num_series(d, 'Ability', 50.0) if 'Ability' in d.columns else _s50.copy()
    posfit = _num_series(d, 'PosFit', 50.0) if 'PosFit' in d.columns else _s50.copy()
    mapfit = _num_series(d, 'MapFit', 50.0) if 'MapFit' in d.columns else _s50.copy()
    gatefit = _num_series(d, 'GateFit', 50.0) if 'GateFit' in d.columns else _s50.copy()
    pacefit = _num_series(d, 'PaceFit', 50.0) if 'PaceFit' in d.columns else _s50.copy()
    condfit = _num_series(d, 'ConditionFit', 50.0) if 'ConditionFit' in d.columns else _s50.copy()
    factorfit = _num_series(d, 'FactorFit', 50.0) if 'FactorFit' in d.columns else _s50.copy()
    michfit = _num_series(d, 'MichiakuFit', 50.0) if 'MichiakuFit' in d.columns else factorfit
    consist = _num_series(d, 'Consist', 50.0) if 'Consist' in d.columns else _s50.copy()
    comment_trend = _num_series(d, 'CommentTrend', 50.0) if 'CommentTrend' in d.columns else _s50.copy()
    lap_shape_meta = _lap_shape_meta_features(meta)
    try:
        start_to_corner_dist = float(lap_shape_meta.get('start_to_corner_dist', float('nan')))
    except Exception:
        start_to_corner_dist = float('nan')
    try:
        straight_len = float(lap_shape_meta.get('straight_len', float('nan')))
    except Exception:
        straight_len = float('nan')
    if not np.isfinite(start_to_corner_dist):
        base_start = 280.0 if surface == 'dirt' else 300.0
        if np.isfinite(dist):
            if dist <= 1400:
                base_start = 230.0 if surface == 'dirt' else 260.0
            elif dist <= 1800:
                base_start = 360.0
            elif dist <= 2400:
                base_start = 440.0
            else:
                base_start = 520.0
        start_to_corner_dist = float(np.clip(base_start + (0.55 - float(profile.get('corner', 0.5) or 0.5)) * 170.0 + (float(profile.get('gate', 0.5) or 0.5) - 0.50) * 70.0, 140.0, 650.0))
    if not np.isfinite(straight_len):
        base_straight = 300.0 if surface == 'dirt' else 330.0
        if np.isfinite(dist):
            if dist <= 1400:
                base_straight += 10.0
            elif dist >= 2400:
                base_straight += 25.0
        straight_len = float(np.clip(base_straight + (float(profile.get('straight', 0.5) or 0.5) - 0.50) * 240.0, 220.0, 720.0))
    start_corner_norm = float(np.clip((start_to_corner_dist - 180.0) / 420.0, 0.0, 1.0)) if np.isfinite(start_to_corner_dist) else 0.5
    straight_len_norm = float(np.clip((straight_len - 260.0) / 320.0, 0.0, 1.0)) if np.isfinite(straight_len) else 0.5
    start_short_bias = float(np.clip((0.50 - start_corner_norm) * 2.0, -1.0, 1.0))
    straight_long_bias = float(np.clip((straight_len_norm - 0.50) * 2.0, -1.0, 1.0))

    _didx = d.index
    straight_fit = _wsum0100(_didx, (0.56, late_speed), (0.24, ability), (0.10, pacefit), (0.10, comment_trend))
    corner_fit   = _wsum0100(_didx, (0.44, posfit), (0.30, mapfit), (0.16, gatefit), (0.10, pacefit))
    stamina_fit  = _wsum0100(_didx, (0.46, consist), (0.30, condfit), (0.14, factorfit), (0.10, ability))
    power_fit    = _wsum0100(_didx, (0.40, condfit), (0.30, factorfit), (0.20, ability), (0.10, michfit))
    speed_fit    = _wsum0100(_didx, (0.42, ability), (0.28, early_speed), (0.20, pacefit), (0.10, gatefit))
    agility_fit  = _wsum0100(_didx, (0.36, posfit), (0.34, mapfit), (0.20, gatefit), (0.10, late_speed))

    if _is_wet_track(meta):
        wet_boost = 3.5 + 2.5 * float(profile.get('power', 0.5) or 0.5)
        power_fit = _clip0100((power_fit + ((michfit - 50.0) / 50.0) * wet_boost + ((factorfit - 50.0) / 50.0) * 2.0))
    if venue in {'札幌', '函館'} and surface == 'turf':
        power_fit = _clip0100((power_fit + 0.10 * (factorfit - 50.0)))
    if venue == '東京' and surface == 'turf':
        straight_fit = _clip0100((straight_fit + 0.08 * (late_speed - 50.0)))
    if venue == '中山' and surface == 'turf':
        stamina_fit = _clip0100((stamina_fit + 0.08 * (consist - 50.0)))
    if venue in {'福島', '小倉', '札幌', '函館'}:
        agility_fit = _clip0100((agility_fit + 0.08 * (mapfit - 50.0)))
    if surface == 'dirt' and np.isfinite(dist) and dist <= 1400:
        speed_fit = _clip0100((0.60 * speed_fit + 0.40 * early_speed))

    draw_raw = pd.Series(np.nan, index=d.index, dtype=float)
    for c in ['frame', 'waku', 'draw', 'draw_num', 'post_position']:
        if c in d.columns:
            cand = pd.to_numeric(d[c], errors='coerce')
            if cand.notna().sum() > 0:
                draw_raw = cand
                break
    draw_zone = pd.Series('middle', index=d.index, dtype=object)
    if draw_raw.notna().sum() > 0:
        _draw_vals = draw_raw.values
        _draw_max = float(np.nanmax(_draw_vals)) if np.any(np.isfinite(_draw_vals)) else np.nan
        if np.isfinite(_draw_max):
            if _draw_max <= 8.5:
                draw_zone = pd.Series(
                    np.where(~np.isfinite(_draw_vals), 'middle',
                             np.where(_draw_vals <= 4.0, 'inner',
                                      np.where(_draw_vals >= 5.0, 'outer', 'middle'))),
                    index=d.index, dtype=object)
            else:
                draw_zone = pd.Series(
                    np.where(~np.isfinite(_draw_vals), 'middle',
                             np.where(_draw_vals <= 6.0, 'inner',
                                      np.where(_draw_vals >= 13.0, 'outer', 'middle'))),
                    index=d.index, dtype=object)

    # 一括スカラーSeries初期化（50.0）
    _s50 = pd.Series(50.0, index=d.index, dtype=float)
    rail_bias_fit = _s50.copy()
    class_pace_fit = _s50.copy()
    tokyo1400_fit = _s50.copy()
    course_special_fit = _s50.copy()
    course_runup_fit = _s50.copy()
    course_straight_shape_fit = _s50.copy()
    course_shape_fit = _s50.copy()
    distance_style_fit = _s50.copy()
    distance_draw_fit = _s50.copy()
    distance_specific_fit = _s50.copy()
    pedigree_bm_fit = _num_series(d.get('PedigreeBmSire2Fit', 50.0), 50.0, index=d.index)
    _ = _num_series(d.get('PedigreeCrossDepthFit', 50.0), 50.0, index=d.index)
    pedigree_dosage_fit = _num_series(d.get('PedigreeDosageFit', 50.0), 50.0, index=d.index)
    _ = _num_series(d.get('PedigreeChefRaceFit', 50.0), 50.0, index=d.index)
    pedigree_tokyo1400_fit = _num_series(d.get('PedigreeTokyo1400LapFit', 50.0), 50.0, index=d.index)
    pedigree_fine_fit = _num_series(d.get('PedigreeFineFit', 50.0), 50.0, index=d.index)

    runup_style_bonus = style_col.map(
        lambda z: (6.0 * start_short_bias if z == 'FRONT' else (1.8 * start_short_bias if z == 'MIDDLE' else -4.8 * start_short_bias))
    ).astype(float)
    straight_style_bonus = style_col.map(
        lambda z: (6.0 * straight_long_bias if z == 'REAR' else (1.8 * straight_long_bias if z == 'MIDDLE' else -4.8 * straight_long_bias))
    ).astype(float)
    _es = early_speed.values; _gf = gatefit.values; _af = agility_fit.values
    _ls = late_speed.values; _rsb = runup_style_bonus.values
    _w_es = 0.28 + max(start_short_bias, 0.0) * 0.30
    _w_gf = 0.20 + max(start_short_bias, 0.0) * 0.20
    _w_ls_neg = max(-start_short_bias, 0.0) * 0.26
    course_runup_fit = _make_series(np.clip(
        50.0 + (_es - 50.0) * _w_es + (_gf - 50.0) * _w_gf
             + (_af - 50.0) * 0.18 + (_ls - 50.0) * _w_ls_neg + _rsb,
        0.0, 100.0), _didx)
    _sf = straight_fit.values; _ssb = straight_style_bonus.values
    _w_ls2 = 0.30 + max(straight_long_bias, 0.0) * 0.34
    _w_es2 = 0.16 + max(-straight_long_bias, 0.0) * 0.22
    course_straight_shape_fit = _make_series(np.clip(
        50.0 + (_ls - 50.0) * _w_ls2 + (_sf - 50.0) * 0.24
             + (_es - 50.0) * _w_es2 + _ssb,
        0.0, 100.0), _didx)
    course_shape_fit = _wsum0100(_didx, (0.52, course_runup_fit), (0.48, course_straight_shape_fit))

    if distance_key:
        if distance_style_bias:
            distance_style_fit = style_col.map(
                lambda z: clamp(50.0 + 30.0 * float(distance_style_bias.get(z, 0.0) or 0.0), 0.0, 100.0)
            ).astype(float)
        if distance_draw_bias:
            distance_draw_fit = _clip0100((distance_draw_fit + draw_zone.map(
                lambda z: 100.0 * float(distance_draw_bias.get(z, 0.0) or 0.0)
            ).astype(float)))
        dsw_style = 0.18 + (0.10 * max([abs(float(v)) for v in distance_style_bias.values()] or [0.0]))
        dsw_straight = 0.10 + 0.40 * max(float(distance_patch.get('straight', 0.0) or 0.0), 0.0)
        dsw_corner = 0.10 + 0.40 * max(float(distance_patch.get('corner', 0.0) or 0.0), 0.0)
        dsw_stamina = 0.10 + 0.40 * max(float(distance_patch.get('stamina', 0.0) or 0.0), 0.0)
        dsw_power = 0.08 + 0.40 * max(float(distance_patch.get('power', 0.0) or 0.0), 0.0)
        dsw_speed = 0.08 + 0.40 * max(float(distance_patch.get('speed', 0.0) or 0.0), 0.0)
        dsw_gate = 0.06 + 0.40 * max(float(distance_patch.get('gate', 0.0) or 0.0), 0.0)
        dsw_agility = 0.08 + 0.40 * max(float(distance_patch.get('agility', 0.0) or 0.0), 0.0)
        dsw_draw = ((0.08 + 0.04 * max([abs(float(v)) for v in distance_draw_bias.values()] or [0.0])) * distance_confidence) if distance_draw_bias else 0.0
        dsw_total = dsw_style + dsw_straight + dsw_corner + dsw_stamina + dsw_power + dsw_speed + dsw_gate + dsw_agility + dsw_draw
        distance_specific_fit = (
            dsw_style * distance_style_fit
            + dsw_straight * straight_fit
            + dsw_corner * corner_fit
            + dsw_stamina * stamina_fit
            + dsw_power * power_fit
            + dsw_speed * speed_fit
            + dsw_gate * gatefit
            + dsw_agility * agility_fit
            + dsw_draw * distance_draw_fit
        ) / max(1e-9, float(dsw_total))
        if _is_wet_track(meta) and float(distance_patch.get('power', 0.0) or 0.0) > 0.0:
            distance_specific_fit = _clip0100((
                distance_specific_fit
                + (0.08 + 0.20 * float(distance_patch.get('power', 0.0) or 0.0)) * (power_fit - 50.0)
                + 0.03 * (michfit - 50.0)
            ))
        if distance_source in {'blend', 'nearest', 'heuristic'}:
            if distance_source == 'blend':
                confidence_scale = min(0.68 + 0.32 * distance_confidence, 0.94)
            elif distance_source == 'nearest':
                confidence_scale = min(0.68 + 0.32 * distance_confidence, 0.88)
            else:
                confidence_scale = min(0.60 + 0.24 * distance_confidence, 0.82)
            distance_specific_fit = _clip0100((50.0 + (distance_specific_fit - 50.0) * confidence_scale))

    rail_bias_fit = _wsum0100(_didx, (0.42, distance_draw_fit), (0.24, gatefit), (0.20, style_fit), (0.14, agility_fit))
    if surface == 'turf':
        straight_corner_gap = float(profile.get('straight', 0.5) or 0.5) - float(profile.get('corner', 0.5) or 0.5)
        if rail_setting == 'B':
            rail_bias_fit = _clip0100((
                rail_bias_fit
                + draw_zone.map(lambda z: 3.0 if z == 'outer' else (-2.0 if z == 'inner' else 0.8)).astype(float)
                + style_col.map(
                    lambda z: 2.5 if (straight_corner_gap >= -0.02 and z == 'REAR') else (1.0 if z == 'MIDDLE' else -1.2)
                ).astype(float)
            ))
        elif rail_setting == 'C':
            rail_bias_fit = _clip0100((
                rail_bias_fit
                + draw_zone.map(lambda z: 3.0 if z == 'inner' else (-2.0 if z == 'outer' else 0.8)).astype(float)
                + style_col.map(
                    lambda z: 2.5 if (straight_corner_gap < 0.02 and z == 'FRONT') else (1.2 if z == 'MIDDLE' else -0.8)
                ).astype(float)
            ))
        elif rail_setting == 'A':
            rail_bias_fit = _clip0100((rail_bias_fit + draw_zone.map(lambda z: 1.0 if z == 'middle' else 0.0).astype(float)))

    if surface == 'dirt':
        if np.isfinite(dist) and dist <= 1400:
            cp_early_w, cp_late_w, cp_stamina_w, cp_power_w, cp_style_w = 0.38, 0.12, 0.10, 0.18, 0.22
        elif np.isfinite(dist) and dist <= 1800:
            cp_early_w, cp_late_w, cp_stamina_w, cp_power_w, cp_style_w = 0.30, 0.16, 0.16, 0.18, 0.20
        else:
            cp_early_w, cp_late_w, cp_stamina_w, cp_power_w, cp_style_w = 0.22, 0.20, 0.24, 0.18, 0.16
    else:
        if np.isfinite(dist) and dist <= 1400:
            cp_early_w, cp_late_w, cp_stamina_w, cp_power_w, cp_style_w = 0.32, 0.22, 0.12, 0.10, 0.24
        elif np.isfinite(dist) and dist <= 1800:
            cp_early_w, cp_late_w, cp_stamina_w, cp_power_w, cp_style_w = 0.26, 0.26, 0.18, 0.10, 0.20
        elif np.isfinite(dist) and dist <= 2400:
            cp_early_w, cp_late_w, cp_stamina_w, cp_power_w, cp_style_w = 0.20, 0.28, 0.24, 0.12, 0.16
        else:
            cp_early_w, cp_late_w, cp_stamina_w, cp_power_w, cp_style_w = 0.16, 0.28, 0.30, 0.14, 0.12

    class_pace_fit = _wsum0100(_didx, (cp_early_w, early_speed), (cp_late_w, late_speed), (cp_stamina_w, stamina_fit), (cp_power_w, power_fit), (cp_style_w, style_fit))
    if class_id >= 4:
        class_pace_fit = _clip0100((class_pace_fit + 0.10 * (late_speed - 50.0) + 0.06 * (stamina_fit - 50.0)))
    elif class_id >= 2:
        class_pace_fit = _clip0100((class_pace_fit + 0.05 * (late_speed - 50.0) + 0.03 * (style_fit - 50.0)))
    elif class_id in {0, 1}:
        class_pace_fit = _clip0100((class_pace_fit + 0.10 * (early_speed - 50.0) + 0.04 * (gatefit - 50.0)))

    if is_tokyo1400:
        rail_bias = TOKYO_TURF_1400_RAIL_BIAS.get(rail_setting or 'A', TOKYO_TURF_1400_RAIL_BIAS.get('A', {}))
        rail_bias_fit = rail_bias_fit + draw_zone.map(
            lambda z: 100.0 * float(rail_bias.get('outer_bonus', 0.0) or 0.0) if z == 'outer' else (100.0 * float(rail_bias.get('inner_bonus', 0.0) or 0.0) if z == 'inner' else 0.0)
        ).astype(float)
        rail_bias_fit = rail_bias_fit + style_col.map(
            lambda z: 100.0 * float(rail_bias.get('front_bonus', 0.0) or 0.0) if z == 'FRONT' else (100.0 * float(rail_bias.get('rear_bonus', 0.0) or 0.0) if z == 'REAR' else 0.0)
        ).astype(float)
        if month in {4, 5}:
            rail_bias_fit = rail_bias_fit + style_col.map(lambda z: 5.0 if z == 'REAR' else (-4.0 if z == 'FRONT' else 1.0)).astype(float)
        elif month == 6:
            rail_bias_fit = rail_bias_fit + style_col.map(lambda z: 4.0 if z == 'FRONT' else (1.5 if z == 'MIDDLE' else -1.0)).astype(float)
        elif month in {10, 11}:
            rail_bias_fit = rail_bias_fit + style_col.map(lambda z: 3.0 if z == 'FRONT' else (1.0 if z == 'MIDDLE' else 0.0)).astype(float)
        rail_bias_fit = _clip0100(rail_bias_fit)

        if class_ref:
            target_front = float(class_ref.get('front3f', np.nan))
            target_back = float(class_ref.get('back3f', np.nan))
            target_dev = float(class_ref.get('pace_dev', np.nan))
            pace_dev = (pf - pl).astype(float)
            early_pen = (pf - target_front).abs() * 18.0
            late_pen = (pl - target_back).abs() * 15.0
            dev_pen = (pace_dev - target_dev).abs() * 12.0
            class_pace_fit = _clip0100((100.0 - early_pen - late_pen - dev_pen))
            if class_id >= 4:
                class_pace_fit = _clip0100((class_pace_fit + style_col.map(lambda z: 4.0 if z == 'REAR' else (1.5 if z == 'MIDDLE' else -2.5)).astype(float)))
            elif class_id >= 2:
                class_pace_fit = _clip0100((class_pace_fit + style_col.map(lambda z: 2.0 if z == 'REAR' else (1.0 if z == 'MIDDLE' else -1.0)).astype(float)))
            elif class_id in {0, 1}:
                class_pace_fit = _clip0100((class_pace_fit + style_col.map(lambda z: 3.0 if z == 'FRONT' else (1.0 if z == 'MIDDLE' else -1.5)).astype(float)))

        tokyo1400_fit = _wsum0100(_didx,
            (0.24, rail_bias_fit), (0.26, class_pace_fit), (0.12, late_speed),
            (0.08, speed_fit), (0.07, straight_fit), (0.07, power_fit),
            (0.10, pedigree_tokyo1400_fit), (0.04, pedigree_dosage_fit), (0.02, pedigree_bm_fit),
        )
        if _is_wet_track(meta):
            tokyo1400_fit = _clip0100((tokyo1400_fit + 0.14 * (power_fit - 50.0) + 0.06 * (michfit - 50.0)))

    course_special_fit = _wsum0100(_didx,
        (0.17, rail_bias_fit), (0.20, class_pace_fit), (0.18, distance_specific_fit),
        (0.10, straight_fit), (0.08, corner_fit), (0.07, power_fit), (0.05, gatefit),
        (0.08, course_runup_fit), (0.07, course_straight_shape_fit),
    )
    if surface == 'dirt' and np.isfinite(dist) and dist <= 1400:
        course_special_fit = _clip0100((course_special_fit + 0.06 * (speed_fit - 50.0) + 0.04 * (early_speed - 50.0)))
    elif bucket == 'long':
        course_special_fit = _clip0100((course_special_fit + 0.06 * (stamina_fit - 50.0) + 0.04 * (late_speed - 50.0)))
    if distance_source in {'blend', 'nearest', 'heuristic'} and distance_key:
        if distance_source == 'heuristic':
            special_scale = 0.66 + 0.20 * distance_confidence
        else:
            special_scale = 0.74 + 0.26 * distance_confidence
        course_special_fit = _clip0100((50.0 + (course_special_fit - 50.0) * special_scale))
    if is_tokyo1400:
        course_special_fit = _clip0100((0.72 * course_special_fit + 0.28 * tokyo1400_fit))

    style_w = 0.22
    straight_w = 0.12 + 0.10 * float(profile.get('straight', 0.5) or 0.5)
    corner_w = 0.10 + 0.10 * float(profile.get('corner', 0.5) or 0.5)
    stamina_w = 0.10 + 0.08 * float(profile.get('stamina', 0.5) or 0.5)
    power_w = 0.08 + 0.08 * float(profile.get('power', 0.5) or 0.5) + (0.03 if _is_wet_track(meta) else 0.0)
    speed_w = 0.08 + 0.08 * float(profile.get('speed', 0.5) or 0.5)
    gate_w = 0.05 + 0.05 * float(profile.get('gate', 0.5) or 0.5)
    agility_w = 0.07 + 0.08 * float(profile.get('agility', 0.5) or 0.5)
    shape_w = 0.05 + 0.03 * max(abs(start_short_bias), abs(straight_long_bias))
    distance_w = (0.07 + 0.04 * distance_confidence) if distance_key else 0.0
    special_w = (0.06 + 0.04 * max(distance_confidence, 0.45)) if distance_key else 0.06
    pedigree_w = 0.07
    pedigree_tokyo_w = 0.03 if is_tokyo1400 else 0.0
    rail_w = 0.05 if is_tokyo1400 else 0.0
    classpace_w = 0.06 if is_tokyo1400 else 0.0
    tokyo_w = 0.08 if is_tokyo1400 else 0.0
    total_w = style_w + straight_w + corner_w + stamina_w + power_w + speed_w + gate_w + agility_w + shape_w + distance_w + special_w + pedigree_w + pedigree_tokyo_w + rail_w + classpace_w + tokyo_w

    d['CourseStyleFit'] = style_fit
    d['CourseStraightFit'] = straight_fit
    d['CourseCornerFit'] = corner_fit
    d['CourseStaminaFit'] = stamina_fit
    d['CoursePowerFit'] = power_fit
    d['CourseSpeedFit'] = speed_fit
    d['CourseAgilityFit'] = agility_fit
    d['CourseStartToCornerDist'] = float(start_to_corner_dist) if np.isfinite(start_to_corner_dist) else np.nan
    d['CourseStraightLen'] = float(straight_len) if np.isfinite(straight_len) else np.nan
    d['CourseRunupFit'] = course_runup_fit
    d['CourseStraightShapeFit'] = course_straight_shape_fit
    d['CourseShapeFit'] = course_shape_fit
    d['CourseDistanceStyleFit'] = distance_style_fit
    d['CourseDistanceDrawFit'] = distance_draw_fit
    d['CourseDistanceSpecificFit'] = distance_specific_fit
    d['CourseSpecialFit'] = course_special_fit
    d['CoursePedigreeFineFit'] = pedigree_fine_fit
    d['CoursePedigreeTokyo1400Fit'] = pedigree_tokyo1400_fit
    d['CourseRailBiasFit'] = rail_bias_fit
    d['CourseClassPaceFit'] = class_pace_fit
    d['CourseTokyo1400Fit'] = tokyo1400_fit
    _tw = max(1e-9, float(total_w))
    d['CourseProfileFit'] = _make_series(np.clip((
        style_w * d['CourseStyleFit'].values
        + straight_w * d['CourseStraightFit'].values
        + corner_w * d['CourseCornerFit'].values
        + stamina_w * d['CourseStaminaFit'].values
        + power_w * d['CoursePowerFit'].values
        + speed_w * d['CourseSpeedFit'].values
        + gate_w * gatefit.values
        + agility_w * d['CourseAgilityFit'].values
        + shape_w * d['CourseShapeFit'].values
        + distance_w * d['CourseDistanceSpecificFit'].values
        + special_w * d['CourseSpecialFit'].values
        + pedigree_w * d['CoursePedigreeFineFit'].values
        + pedigree_tokyo_w * d['CoursePedigreeTokyo1400Fit'].values
        + rail_w * d['CourseRailBiasFit'].values
        + classpace_w * d['CourseClassPaceFit'].values
        + tokyo_w * d['CourseTokyo1400Fit'].values
    ) / _tw, 0.0, 100.0), d.index)
    d['CourseBiasDelta'] = _clip_series((d['CourseProfileFit'] - 50.0), -20.0, 20.0).astype(float)
    d['CourseProfileVenue'] = venue if venue else ''
    d['CourseProfileSurface'] = surface if surface else ''
    d['CourseDistanceKey'] = distance_key if distance_key else ''
    d['CourseDistanceConfidence'] = float(distance_confidence) if distance_key else 0.0
    d['CourseDistanceSource'] = distance_source if distance_key else ''
    return d


def _resolve_pace_mix(
    pace: str, front_count: int, good_pos_count: int, can_hold_count: int,
    lead_gap: float, n: int, lap_meta: dict, wp: dict,
) -> tuple[dict, str]:
    """ペース区分・頭数条件から pace_mix と pace_eval_mode を決定する。"""
    high_gap = float(wp.get('pace_high_fixed_gap_threshold', 0.25) or 0.25)
    human_mid_goodpos_thr = max(4, int(np.ceil(n * 0.38))) if n > 0 else 4
    human_hold_thr = max(3, int(np.ceil(n * 0.22))) if n > 0 else 3
    lap_closing_bias = float(lap_meta.get('closing_bias', 0.0) or 0.0)
    lap_goodpos_bias = float(lap_meta.get('goodpos_bias', 0.0) or 0.0)

    pace_mix = {'M': 1.0}
    pace_eval_mode = 'mid'

    if pace == 'H':
        if (front_count >= 3) and (good_pos_count < human_mid_goodpos_thr) and (can_hold_count <= human_hold_thr) and (not np.isfinite(lead_gap) or lead_gap <= high_gap):
            pace_mix = {'H': 0.62, 'M': 0.30, 'S': 0.08}
            pace_eval_mode = 'high'
        elif (front_count >= 2) and (can_hold_count <= max(4, int(np.ceil(n * 0.28)))):
            pace_mix = {'H': 0.46, 'M': 0.40, 'S': 0.14}
            pace_eval_mode = 'high-mid'
        else:
            pace_mix = {'M': 0.64, 'H': 0.24, 'S': 0.12}
            pace_eval_mode = 'mid'
        if (good_pos_count >= human_mid_goodpos_thr) and (can_hold_count >= human_hold_thr):
            pace_mix = {'M': 0.68, 'H': 0.20, 'S': 0.12}
            pace_eval_mode = 'mid'
    elif pace == 'S':
        pace_mix = {'S': 0.68, 'M': 0.24, 'H': 0.08}
        pace_eval_mode = 'slow'
    else:
        if (front_count >= 3) and (good_pos_count <= max(3, int(np.ceil(n * 0.32)))) and (can_hold_count <= human_hold_thr):
            pace_mix = {'H': 0.34, 'M': 0.54, 'S': 0.12}
            pace_eval_mode = 'high-mid'
        else:
            pace_mix = {'M': 0.74, 'H': 0.16, 'S': 0.10}
            pace_eval_mode = 'mid'

    if lap_goodpos_bias >= 3.0 and pace_eval_mode in {'high', 'high-mid'}:
        pace_mix = {'M': max(0.52, pace_mix.get('M', 0.0)), 'H': min(0.34, pace_mix.get('H', 0.0) + 0.0), 'S': max(0.08, pace_mix.get('S', 0.0))}
        total = sum(pace_mix.values())
        pace_mix = {k: v / total for k, v in pace_mix.items()}
        pace_eval_mode = 'high-mid' if pace_eval_mode == 'high' else pace_eval_mode
    if lap_closing_bias >= 3.0 and pace_eval_mode == 'mid' and pace == 'H':
        pace_mix = {'H': 0.42, 'M': 0.42, 'S': 0.16}
        pace_eval_mode = 'high-mid'

    if wp and pace in {'M', 'S'}:
        mw = max(0.0, float(wp.get('long_maiden_pace_m_weight', 0.65) or 0.65))
        sw = max(0.0, float(wp.get('long_maiden_pace_s_weight', 0.35) or 0.35))
        if wp.get('_long_maiden_mode'):
            denom = mw + sw
            if denom > 0:
                pace_mix = {'M': mw / denom, 'S': sw / denom}
                pace_eval_mode = 'long-maiden-mix'

    return pace_mix, pace_eval_mode


def _write_pace_meta(
    meta: dict,
    pace_eval_mode: str,
    pace_mix: dict,
    front_count: int,
    good_pos_count: int,
    can_hold_count: int,
    lead_gap: float,
    lap_meta: dict,
) -> None:
    """ペース評価結果を meta dict に書き込む。"""
    try:
        human_line = (
            f"front={front_count},goodpos={good_pos_count},hold={can_hold_count},lead_gap={lead_gap:.3f}"
            if np.isfinite(lead_gap)
            else f"front={front_count},goodpos={good_pos_count},hold={can_hold_count}"
        )
        meta['pace_eval_mode'] = str(pace_eval_mode)
        meta['pace_mix_detail'] = ','.join(f"{k}:{float(v):.2f}" for k, v in pace_mix.items())
        meta['pace_front_count'] = str(front_count)
        meta['pace_goodpos_count'] = str(good_pos_count)
        meta['pace_can_hold_count'] = str(can_hold_count)
        meta['pace_lead_gap'] = '' if not np.isfinite(lead_gap) else f"{lead_gap:.3f}"
        meta['pace_human_check'] = human_line
        if lap_meta.get('laps'):
            meta['lap_shape_detail'] = ','.join(f"{x:.1f}" for x in lap_meta['laps'])
        if np.isfinite(float(lap_meta.get('avg_sf', float('nan')))):
            meta['avg_sec_per_furlong'] = f"{float(lap_meta['avg_sf']):.2f}"
    except Exception:
        pass


def _score_one_horse_pacefit(
    zz: str,
    ff: float,
    lf: float,
    pace_mix: dict,
    pace_eval_mode: str,
    base_map: dict,
    long_maiden_mode: bool,
    maiden_zone_bias: dict,
    lap_goodpos_bias: float,
    lap_closing_bias: float,
    sustain_bias: float,
    is_leader: bool,
    good_reaccel: bool,
    lead_gap: float,
    front_count: int,
    leader_bonus_mid: float,
    leader_bonus_high_mid: float,
    leader_relief: float,
    lead_gap_relief_thr: float,
    reaccel_bonus_mid: float,
    reaccel_bonus_highmid: float,
) -> float:
    """1頭分のペースフィットスコアを計算する。"""
    sc = 0.0
    for pk, w in pace_mix.items():
        bm = base_map.get(pk, {'FRONT': 62.0, 'MIDDLE': 70.0, 'REAR': 64.0})
        part = float(bm.get(zz, 68.0))
        if pk == 'H':
            if zz == 'FRONT':
                part -= 8.0 * ff
            elif zz == 'MIDDLE':
                part += 7.5 * ff + 2.0 * lf + max(0.0, lap_goodpos_bias) * 0.45
            else:
                part += 4.0 * (1.0 - abs(ff - 0.50) * 1.1) + max(0.0, lap_closing_bias) * 0.55
        elif pk == 'S':
            if zz == 'FRONT':
                part += 8.0 * ff + max(0.0, lap_goodpos_bias) * 0.30
            elif zz == 'REAR':
                part -= 6.0 * (1.0 - ff)
            else:
                part += 2.5 * lf
        else:
            if zz == 'MIDDLE':
                part += 5.2 * (1.0 - abs(ff - 0.55) * 1.6) + 3.2 * lf + max(0.0, lap_goodpos_bias) * 0.55
            elif zz == 'FRONT':
                part += 3.2 * ff + 1.2 * lf + max(0.0, lap_goodpos_bias) * 0.20
            else:
                part += 2.0 * lf + max(0.0, lap_closing_bias) * 0.40
        sc += float(w) * float(clamp(part, 0.0, 100.0))

    leader_bonus = 0.0
    if zz == 'FRONT' and is_leader:
        if pace_eval_mode == 'mid':
            leader_bonus += leader_bonus_mid
        elif pace_eval_mode == 'high-mid':
            leader_bonus += leader_bonus_high_mid
        if np.isfinite(lead_gap) and lead_gap >= lead_gap_relief_thr:
            leader_bonus += leader_relief
        if front_count <= 1:
            leader_bonus += 2.0
    if good_reaccel:
        if pace_eval_mode == 'mid':
            leader_bonus += reaccel_bonus_mid
        elif pace_eval_mode == 'high-mid':
            leader_bonus += reaccel_bonus_highmid

    if long_maiden_mode:
        sc += maiden_zone_bias.get(zz, 0.0)
    sc += leader_bonus + sustain_bias * (0.12 if zz in {'FRONT', 'MIDDLE'} else 0.08)
    return float(clamp(sc, 0.0, 100.0))


def compute_pacefit_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> pd.Series:
    """ペース区分・ゾーン・ラップ形状からペースフィットスコア (0–100) の Series を返す。
    
    サブ関数 _resolve_pace_mix / _write_pace_meta / _score_one_horse_pacefit を呼び出す。
    """
    meta = meta or {}
    wp = ((params or {}).get('win_pattern_rules', {}) or {})
    pace = str(meta.get('pace', '') or '').upper().strip()[:1]
    z = df.get('zone_4c', pd.Series(['MIDDLE'] * len(df), index=df.index)).astype(str).map(normalize_zone_token)
    f = _num_series(df, 'pred_first3f', np.nan)
    l = _num_series(df, 'pred_last3f', np.nan)
    st = _num_series(df, ['StabilityComposite', 'SAS'], 50.0)
    pos = _num_series(df, 'PosFit', 50.0)
    gate = _num_series(df, 'GateFit', 50.0)
    lap_meta = _lap_shape_meta_features(meta)

    n = int(len(df))
    if f.notna().sum() > 1 and float(f.max()) != float(f.min()):
        f01 = _clip_series(((float(f.max()) - f) / (float(f.max()) - float(f.min()))), 0.0, 1.0)
    else:
        f01 = pd.Series([0.5] * len(df), index=df.index, dtype=float)
    if l.notna().sum() > 1 and float(l.max()) != float(l.min()):
        l01 = _clip_series(((float(l.max()) - l) / (float(l.max()) - float(l.min()))), 0.0, 1.0)
    else:
        l01 = pd.Series([0.5] * len(df), index=df.index, dtype=float)
    pf_rank = f.rank(method='min', ascending=True)
    pl_rank = l.rank(method='min', ascending=True)

    long_maiden_mode = _is_long_maiden_race(meta, df)

    front_count = int((z == 'FRONT').sum()) if len(z) else 0
    good_pos_mask = z.isin(['FRONT', 'MIDDLE'])
    good_pos_count = int(good_pos_mask.sum()) if len(good_pos_mask) else 0
    can_hold_mask = good_pos_mask & (((pl_rank <= max(3, int(np.ceil(n * 0.35)))) | (st >= 56.0) | (pos >= 58.0) | (gate >= 58.0))).fillna(False)
    can_hold_count = int(can_hold_mask.sum()) if len(can_hold_mask) else 0
    fs = _num_series(f, index=f.index).dropna().sort_values()
    lead_gap = float(fs.iloc[min(len(fs) - 1, 1)] - fs.iloc[0]) if len(fs) >= 2 else float('nan')

    _wp_lm = dict(wp)
    _wp_lm['_long_maiden_mode'] = long_maiden_mode
    pace_mix, pace_eval_mode = _resolve_pace_mix(
        pace, front_count, good_pos_count, can_hold_count, lead_gap, n, lap_meta, _wp_lm,
    )

    _write_pace_meta(meta, pace_eval_mode, pace_mix, front_count, good_pos_count, can_hold_count, lead_gap, lap_meta)

    base_map = {
        'H': {'FRONT': 46.0, 'MIDDLE': 81.0, 'REAR': 67.0},
        'M': {'FRONT': 67.0, 'MIDDLE': 79.0, 'REAR': 59.0},
        'S': {'FRONT': 80.0, 'MIDDLE': 72.0, 'REAR': 54.0},
    }
    maiden_zone_bias = {
        'FRONT': float(wp.get('long_maiden_pace_front_bias', -3.0) or -3.0),
        'MIDDLE': float(wp.get('long_maiden_pace_middle_bias', 2.0) or 2.0),
        'REAR': float(wp.get('long_maiden_pace_rear_bias', 4.0) or 4.0),
    }
    leader_bonus_mid = float(wp.get('pace_front_auto_promote_bonus', 5.0) or 5.0)
    leader_bonus_high_mid = float(wp.get('pace_front_keep_bonus', 3.0) or 3.0)
    leader_relief = float(wp.get('pace_high_front_lead_gap_relief', 4.0) or 4.0)
    leader_rank_max = int(wp.get('pace_front_auto_promote_rank_max', 2) or 2)
    reaccel_bonus_mid = float(wp.get('pace_reaccel_goodpos_bonus_mid', 5.5) or 5.5)
    reaccel_bonus_highmid = float(wp.get('pace_reaccel_goodpos_bonus_highmid', 3.0) or 3.0)
    lead_gap_relief_thr = float(wp.get('pace_high_front_lead_gap_threshold', 0.45) or 0.45)
    lap_closing_bias = float(lap_meta.get('closing_bias', 0.0) or 0.0)
    lap_goodpos_bias = float(lap_meta.get('goodpos_bias', 0.0) or 0.0)
    sustain_bias = float(lap_meta.get('sustain_bias', 0.0) or 0.0)

    out = []
    for i in df.index:
        zz = z.loc[i] if i in z.index else 'MIDDLE'
        ff = float(f01.loc[i]) if i in f01.index and np.isfinite(f01.loc[i]) else 0.5
        lf = float(l01.loc[i]) if i in l01.index and np.isfinite(l01.loc[i]) else 0.5
        try:
            is_leader = bool(np.isfinite(pf_rank.loc[i]) and float(pf_rank.loc[i]) <= float(leader_rank_max))
        except Exception:
            is_leader = False
        try:
            good_reaccel = bool(zz in {'FRONT', 'MIDDLE'} and np.isfinite(pl_rank.loc[i]) and float(pl_rank.loc[i]) <= float(max(5, int(np.ceil(n * 0.45)))))
        except Exception:
            good_reaccel = False
        sc = _score_one_horse_pacefit(
            zz, ff, lf, pace_mix, pace_eval_mode, base_map,
            long_maiden_mode, maiden_zone_bias,
            lap_goodpos_bias, lap_closing_bias, sustain_bias,
            is_leader, good_reaccel, lead_gap, front_count,
            leader_bonus_mid, leader_bonus_high_mid, leader_relief, lead_gap_relief_thr,
            reaccel_bonus_mid, reaccel_bonus_highmid,
        )
        out.append(sc)
    return pd.Series(out, index=df.index, dtype=float)

def detect_tight_race_v1_1(df: pd.DataFrame) -> tuple[bool, float]:
    """前半タイムの分散からハイペース競合レースを検出する。
    
    Returns:
        (is_tight: bool, lead_gap: float)
    """
    f = _num_series(df, 'pred_first3f', np.nan, index=df.index)
    l = _num_series(df, 'pred_last3f', np.nan, index=df.index)
    total = _num_series(f + l, index=df.index)
    total = total[total.notna() & np.isfinite(total)]
    if len(total) < 3:
        return False, float('nan')
    top = total.sort_values().head(4)
    spread = float(top.max() - top.min()) if len(top) >= 2 else float('nan')
    return bool(np.isfinite(spread) and spread <= 0.50), spread


def _series_norm01(x: pd.Series, lower_is_better: bool = False, neutral: float = 0.5) -> pd.Series:
    """    系列 x を [0, 1] の範囲に最小最大正規化する。
    lower_is_better=True の場合は反転する。有効値が 1 以下の場合は neutral を返す。
    """
    v = _num_series(x, index=getattr(x, 'index', None))
    ok = v.notna() & np.isfinite(v)
    if int(ok.sum()) <= 1:
        return pd.Series([neutral] * len(v), index=v.index, dtype=float)
    lo = float(v[ok].min())
    hi = float(v[ok].max())
    if not (hi > lo):
        return pd.Series([neutral] * len(v), index=v.index, dtype=float)
    out = ((hi - v) / (hi - lo)) if lower_is_better else ((v - lo) / (hi - lo))
    return _num_series(out, neutral, index=v.index, lower=0.0, upper=1.0)


def _comment_tag_mask(series: pd.Series, keywords: list[str]) -> pd.Series:
    """コメントタグ系列 series に対し、keywords の少なくとも 1 語を含む行を True にしたマスクを返す。"""
    if series is None or len(series) == 0:
        return pd.Series([], dtype=bool)
    keys = [str(k) for k in (keywords or []) if str(k).strip()]
    if not keys:
        return pd.Series([False] * len(series), index=series.index, dtype=bool)
    pat = '|'.join(re.escape(k) for k in keys)
    return series.astype(str).str.contains(pat, regex=True, na=False)


def _meta_race_text(meta: Optional[Dict[str, str]]) -> str:
    """meta dict からレース関連テキストフィールドを連結して返す。"""
    meta = meta or {}
    parts = []
    for k in ['race', 'course_info', 'surface', 'class', 'race_name', 'note']:
        try:
            v = str(meta.get(k, '') or '').strip()
        except Exception:
            v = ''
        if v:
            parts.append(v)
    return ' '.join(parts)


def _is_young_maiden_race(meta: Optional[Dict[str, str]], df: Optional[pd.DataFrame] = None) -> bool:
    """3歳未勝利・新馬戦かどうかを判定する。"""
    txt = _meta_race_text(meta)
    try:
        txt += ' ' + ' '.join(str(c) for c in (df.columns.tolist() if isinstance(df, pd.DataFrame) else []))
    except Exception:
        pass
    txt = str(txt)
    is_age3 = ('3歳' in txt) or ('三歳' in txt) or ('3才' in txt)
    is_maiden = ('未勝利' in txt) or ('新馬' in txt)
    return bool(is_age3 and is_maiden)



def _is_long_maiden_race(meta: Optional[Dict[str, str]], df: Optional[pd.DataFrame] = None) -> bool:
    """3歳未勝利 1800–2000m の長距離未勝利戦かどうかを判定する。"""
    if not _is_young_maiden_race(meta, df):
        return False
    dist, _surface = _meta_distance_surface(meta or {})
    return bool(np.isfinite(dist) and 1800.0 <= float(dist) <= 2000.0)


def compute_distance_comment_profile_v1_1(df: pd.DataFrame) -> tuple[pd.Series, pd.Series]:
    """コメントと距離条件からフロント・リアプロファイルスコアを返す。
    
    Returns:
        (score: pd.Series, risk: pd.Series)
    """
    short = df.get('comment_short', pd.Series([''] * len(df), index=df.index)).infer_objects(copy=False).fillna('').astype(str)
    tags = df.get('comment_tags', pd.Series([''] * len(df), index=df.index)).infer_objects(copy=False).fillna('').astype(str)
    txt = (short + ' ' + tags).astype(str)
    pos_pat = r'折り合いスムーズ|折り合い面に進境|距離延長歓迎|しまい確実|余力|持続|リズム良|バテない|長く脚'
    neg_pat = (r'終い甘い|かかる|力む|行きたがる|単調|直線で甘い|距離課題|最後苦しく|距離長'
              r'|折り合い難|折り合い課題'
              r'|もう少し短め|短めの距離|距離長い印象|距離が長い'  # R19追加
              r'|1400あたりが|1600あたりが|1800あたりが|このくらいが上限'
              r'|短距離向き|マイラー向き|短めが向')
    pos_hits = txt.str.count(pos_pat).infer_objects(copy=False).fillna(0.0).astype(float)
    neg_hits = txt.str.count(neg_pat).infer_objects(copy=False).fillna(0.0).astype(float)
    score = _clip0100((50.0 + 8.0 * pos_hits - 7.0 * neg_hits))
    risk = _clip_series((2.2 * neg_hits), 0.0, 8.0)
    return _num_series(score, 50.0, index=df.index), _num_series(risk, 0.0, index=df.index)


def compute_distance_suit_score_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> pd.Series:
    """距離適性スコア (0–100) を ConditionFit / CommentDistance 等から計算する。"""
    cc = _num_series(df, 'ConditionFit', 50.0)
    mf = _num_series(df, 'MapFit', 50.0)
    pf = _num_series(df, 'PosFit', 50.0)
    tf = _num_series(df, 'TimeFit', 50.0)
    tr = _num_series(df, 'TrainingScore', 50.0)
    dcs = _num_series(df, 'DistanceCommentScore', 50.0)
    out = 0.28 * cc + 0.18 * mf + 0.18 * pf + 0.18 * tf + 0.08 * tr + 0.10 * dcs
    if _is_long_maiden_race(meta, df):
        pl = _num_series(df, 'pred_last3f', np.nan)
        if pl.notna().sum() > 1 and float(pl.max()) != float(pl.min()):
            l01 = _clip_series(((float(pl.max()) - pl) / (float(pl.max()) - float(pl.min()))), 0.0, 1.0)
        else:
            l01 = pd.Series([0.5] * len(df), index=df.index, dtype=float)
        out = out + 6.0 * (l01 - 0.5)
    return _num_series(out, 50.0, index=df.index, lower=0.0, upper=100.0)

def compute_stability_composite_v1_1(df: pd.DataFrame, params: Optional[dict] = None) -> pd.Series:
    """安定性複合スコア (0–100) を Consist / SAS 等から計算する。"""
    cs = _num_series(df, 'Consist', 50.0)
    pf = _num_series(df, 'PosFit', 50.0)
    ab = _num_series(df, 'Ability', 50.0)
    ds = _num_series(df, 'DistanceSuitScore', 50.0)
    cf = _num_series(df, 'CommentFit', 50.0)
    out = 0.30 * cs + 0.25 * pf + 0.20 * ab + 0.15 * ds + 0.10 * cf
    return _num_series(out, 50.0, index=df.index, lower=0.0, upper=100.0)

def compute_long_front_fade_risk_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> pd.Series:
    """長距離未勝利戦における先行馬の失速リスクスコアを返す。非対象レースは 0 埋め。"""
    if not _is_long_maiden_race(meta, df):
        return pd.Series([0.0] * len(df), index=df.index, dtype=float)
    wp = ((params or {}).get('win_pattern_rules', {}) or {})
    base_pen = float(wp.get('long_maiden_frontfade_base_penalty', 6.0) or 6.0)
    extra_pen = float(wp.get('long_maiden_frontfade_extra_penalty', 2.0) or 2.0)
    z = df.get('zone_4c', pd.Series(['MIDDLE'] * len(df), index=df.index)).astype(str).map(normalize_zone_token)
    pf = _num_series(df, 'pred_first3f', np.nan)
    pl = _num_series(df, 'pred_last3f', np.nan)
    tf = _num_series(df, 'TimeFit', 50.0)
    ct = _num_series(df, 'CommentTrend', 50.0)
    cr = _num_series(df, 'CommentRisk', 0.0)
    pf_rank = pf.rank(method='min', ascending=True)
    pl_rank = pl.rank(method='min', ascending=True)
    out = pd.Series([0.0] * len(df), index=df.index, dtype=float)
    mask = (z == 'FRONT') & (pf_rank <= 2.0) & ((pl_rank >= 6.0) | (tf < 52.0))
    out.loc[mask] += base_pen
    extra_mask = mask & ((ct < 50.0) | (cr > 55.0))
    out.loc[extra_mask] += extra_pen
    severe_mask = mask & (tf < 48.0) & (pl_rank >= 7.0)
    out.loc[severe_mask] += 1.0
    return _num_series(out, 0.0, index=df.index, lower=0.0, upper=9.0)

def compute_distance_stamina_risk_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> pd.Series:
    """長距離未勝利戦における距離スタミナリスクスコアを返す。非対象レースは 0 埋め。"""
    if not _is_long_maiden_race(meta, df):
        return pd.Series([0.0] * len(df), index=df.index, dtype=float)
    z = df.get('zone_4c', pd.Series(['MIDDLE'] * len(df), index=df.index)).astype(str).map(normalize_zone_token)
    tf = _num_series(df, 'TimeFit', 50.0)
    dcr = _num_series(df, 'DistanceCommentRisk', 0.0)
    pl = _num_series(df, 'pred_last3f', np.nan)
    pl_rank = pl.rank(method='min', ascending=True)
    late_weak = _clip_series(((55.0 - tf) / 4.5), 0.0, 4.0)
    late_weak = late_weak + (pl_rank >= 6.0).astype(float) * 2.0
    late_weak = late_weak + ((z == 'FRONT') & (pl_rank >= 6.0)).astype(float) * 1.0
    out = 0.55 * dcr + 0.45 * late_weak
    return _num_series(out, 0.0, index=df.index, lower=0.0, upper=8.0)

def compute_recovery_signal_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> tuple[pd.Series, pd.Series, pd.Series, pd.Series]:
    """回復シグナル関連の4系列を返す。非対象レースは全て 0 埋め。
    
    Returns:
        (signal, insurance_count, front_fade, stamina_risk)
    """
    if not _is_long_maiden_race(meta, df):
        z = pd.Series([0] * len(df), index=df.index, dtype=int)
        f = pd.Series([0.0] * len(df), index=df.index, dtype=float)
        return z, z, f, f
    wp = ((params or {}).get('win_pattern_rules', {}) or {})
    dist_sig = (_num_series(df, 'DistanceSuitScore', 50.0) >= 60.0).astype(int)
    train_sig = (_num_series(df, 'TrainingScore', 50.0) >= 58.0).astype(int)
    delta_sig = (_num_series(df, 'delta_train', 0.0) >= 1.0).astype(int)
    trend_sig = (_num_series(df, 'CommentTrend', 50.0) >= 55.0).astype(int)
    count = (dist_sig + train_sig + delta_sig + trend_sig).astype(int)
    flag = (count >= 3).astype(int)
    rating_rank = _num_series(df, 'rating', np.nan).rank(method='min', ascending=False)
    low_rank_thr = float(wp.get('long_maiden_recovery_rating_rank_threshold', 5) or 5)
    low_rank = (rating_rank > low_rank_thr).fillna(True)
    win_bonus_lo = float(wp.get('long_maiden_recovery_bonus_win', 3.5) or 3.5)
    place_bonus_lo = float(wp.get('long_maiden_recovery_bonus_place', 5.0) or 5.0)
    win_bonus_hi = float(wp.get('long_maiden_recovery_bonus_win_core', 1.5) or 1.5)
    place_bonus_hi = float(wp.get('long_maiden_recovery_bonus_place_core', 2.5) or 2.5)
    bonus_win = pd.Series(0.0, index=df.index, dtype=float)
    bonus_place = pd.Series(0.0, index=df.index, dtype=float)
    bonus_win.loc[flag > 0] = np.where(low_rank.loc[flag > 0], win_bonus_lo, win_bonus_hi)
    bonus_place.loc[flag > 0] = np.where(low_rank.loc[flag > 0], place_bonus_lo, place_bonus_hi)
    return count.astype(int), flag.astype(int), _num_series(bonus_win, 0.0, index=df.index), _num_series(bonus_place, 0.0, index=df.index)

def compute_maintenance_run_relief_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> tuple[pd.Series, pd.Series]:
    """メンテナンス出走緩和フラグと理由文字列 Series を返す。
    
    Returns:
        (flag: pd.Series[int], reason: pd.Series[str])
    """
    _ = ((params or {}).get('favorite_logic_rules', {}) or {})
    dist = _num_series(df, 'DistanceSuitScore', 50.0)
    tr = _num_series(df, 'TrainingScore', 50.0)
    dt = _num_series(df, 'delta_train', 0.0)
    ct = _num_series(df, 'CommentTrend', 50.0)
    rf = _num_series(df, 'RecentFormScore', 50.0)
    short = df.get('comment_short', pd.Series([''] * len(df), index=df.index)).infer_objects(copy=False).fillna('').astype(str)
    tags = df.get('comment_tags', pd.Series([''] * len(df), index=df.index)).infer_objects(copy=False).fillna('').astype(str)
    txt = (short + ' ' + tags).astype(str)
    maintain_tag = txt.str.contains(r'ひと叩き|叩いて|叩き良化|良化余地|軽め|維持|次走|上積み', regex=True, na=False)
    base = ((dist >= 60.0) & (tr >= 55.0) & (dt >= -0.30) & (rf >= 49.0)).astype(float)
    bonus = _clip_series((base * 1.2 + maintain_tag.astype(float) * 1.0 + ((ct >= 55.0) & (dist >= 58.0)).astype(float) * 0.8), 0.0, 4.0)
    reason = pd.Series([''] * len(df), index=df.index, dtype=str)
    reason.loc[bonus >= 1.0] = '軽い前走でも維持・上積み型'
    return _num_series(bonus, 0.0, index=df.index), reason

def compute_development_wait_risk_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> tuple[pd.Series, pd.Series]:
    """成長待ちリスクフラグと理由文字列 Series を返す。
    
    Returns:
        (flag: pd.Series[int], reason: pd.Series[str])
    """
    ab = _num_series(df, 'AbilityBaseScore', 50.0)
    rc = _num_series(df, 'RaceConditionScore', 50.0)
    rf = _num_series(df, 'RecentFormScore', 50.0)
    pf = _num_series(df, 'PaceFit', 50.0)
    ct = _num_series(df, 'CommentTrend', 50.0)
    pos = _num_series(df, 'PosFit', 50.0)
    risk = (np.maximum(ab.values - rc.values - 4.0, 0.0) / 4.5) + (np.maximum(ab.values - rf.values - 2.0, 0.0) / 7.0)
    risk = risk + ((pf < 58.0) & (ct < 53.0)).astype(float) * 1.2 + ((pos < 56.0) & (ab >= 58.0)).astype(float) * 0.8
    risk = _num_series(risk, 0.0, index=df.index, lower=0.0, upper=6.0)
    reason = pd.Series([''] * len(df), index=df.index, dtype=str)
    reason.loc[risk >= 3.0] = '展開待ち・相手向き'
    reason.loc[(risk >= 1.5) & (risk < 3.0)] = '勝ち切りは展開待ち'
    return risk, reason

def compute_favorite_score_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> tuple[pd.Series, pd.Series, pd.Series]:
    """人気馬スコア・オーバーライドフラグ・理由文字列を返す。
    
    Returns:
        (score: pd.Series[float], override_flag: pd.Series[int], reason: pd.Series[str])
    """
    fr = ((params or {}).get('favorite_logic_rules', {}) or {})
    ab = _num_series(df, 'AbilityBaseScore', 50.0)
    rf = _num_series(df, 'RecentFormScore', 50.0)
    tr = _num_series(df, 'TrainingScore', 50.0)
    cf = _num_series(df, 'CommentFit', 50.0)
    ct = _num_series(df, 'CommentTrend', 50.0)
    wps = _num_series(df, 'WPS', 50.0)
    st = _num_series(df, ['StabilityComposite', 'SAS'], 50.0)
    sr = _num_series(df, 'StartRiskShort', 0.0)
    pf = _num_series(df, 'PaceFit', 50.0)
    pos = _num_series(df, 'PosFit', 50.0)
    rc = _num_series(df, 'RaceConditionScore', 50.0)
    dwr = _num_series(df, 'DevelopmentWaitRisk', 0.0)

    race_txt = _meta_race_text(meta)
    large_field_thr = int(fr.get('favorite_large_field_threshold', 16) or 16)
    graded_or_large = bool((len(df) >= large_field_thr) or re.search(r'G\s*[1-3]|GIII|GII|GI|重賞|オープン', race_txt, flags=re.I))

    mismatch_thr = float(fr.get('favorite_mismatch_threshold', 56.0) or 56.0)
    mismatch_scale_val = float(fr.get('favorite_mismatch_half_scale', 0.5) or 0.5)
    _mm = (pf.values < mismatch_thr) | (pos.values < mismatch_thr) | (rc.values < mismatch_thr)
    _ms_arr = np.where(_mm, mismatch_scale_val, 1.0)
    mismatch_scale = _make_series(_ms_arr, df.index)

    train_cap = float(fr.get('favorite_training_push_cap', 12.0) or 12.0)
    comment_cap = float(fr.get('favorite_comment_push_cap', 10.0) or 10.0)
    _ms = _ms_arr  # already numpy array
    # All pure numpy from here
    _ab = ab.values; _rf = rf.values; _tr = tr.values; _cf = cf.values
    _ct = ct.values; _wps = wps.values; _st = st.values; _sr = sr.values
    _pf = pf.values; _pos = pos.values; _rc = rc.values; _dwr = dwr.values
    tr_adj_arr = 50.0 + np.clip(_tr - 50.0, -10.0, train_cap) * _ms
    cf_adj_arr = 50.0 + np.clip(_cf - 50.0, -10.0, comment_cap) * _ms
    ct_adj_arr = 50.0 + np.clip(_ct - 50.0, -10.0, comment_cap) * _ms

    win_axis_arr = 0.34 * _ab + 0.22 * _pf + 0.16 * _pos + 0.14 * _st + 0.14 * _rc
    overall_arr = 0.46 * win_axis_arr + 0.18 * _rf + 0.10 * tr_adj_arr + 0.08 * cf_adj_arr + 0.06 * ct_adj_arr + 0.12 * _wps
    # rank requires Series
    overall_rank = _make_series(overall_arr, df.index).rank(method='min', ascending=False).values

    _min_recent = float(fr.get('favorite_override_min_recent', 58.0) or 58.0)
    _min_train = float(fr.get('favorite_override_min_training', 58.0) or 58.0)
    _min_comment = float(fr.get('favorite_override_min_comment', 55.0) or 55.0)
    override_recent = (_rf >= _min_recent) & (_tr >= _min_train) & ((_cf >= _min_comment) | (_ct >= _min_comment))
    override_support = (_pf >= 58.0) & (_pos >= 58.0) & (_st >= 56.0)
    if graded_or_large:
        override_arr = ((overall_rank <= 1.0) & override_recent & override_support & (_tr >= 62.0) & ((_cf >= 56.0) | (_ct >= 56.0))).astype(float)
    else:
        override_arr = ((overall_rank <= 1.0) & override_recent & override_support).astype(float)

    start_scale = float(fr.get('favorite_start_penalty_scale', 0.60) or 0.60)
    start_cap = float(fr.get('favorite_start_penalty_cap', 1.8) or 1.8)
    top_bonus = float(fr.get('favorite_top_bonus', 3.2) or 3.2)
    if graded_or_large:
        top_bonus *= 0.55

    score_arr = np.clip(
        0.42 * win_axis_arr
        + 0.18 * _rf
        + 0.10 * tr_adj_arr
        + 0.08 * cf_adj_arr
        + 0.06 * ct_adj_arr
        + 0.08 * _wps
        + 0.08 * _st
        + override_arr * top_bonus
        - np.clip(_sr * start_scale, 0.0, start_cap)
        - 0.75 * _dwr
        - ((_ms < 0.99) & (_tr >= 60.0)).astype(float) * 0.8,
        0.0, 100.0
    )
    score = _make_series(score_arr, df.index)
    override = _make_series(override_arr.astype(np.int64), df.index)

    reason_arr = np.full(len(df), '', dtype=object)
    reason_arr[override_arr > 0] = '能力×展開×位置取り一致で本命維持'
    reason_arr[(override_arr <= 0) & (_ms < 0.99)] = '展開不一致で調教・コメント加点を半減'
    reason = pd.Series(reason_arr, index=df.index, dtype=str)
    return score, override, reason

def compute_popularity_danger_v1_1(df: pd.DataFrame, params: Optional[dict] = None) -> tuple[pd.Series, pd.Series, pd.Series]:
    """人気馬危険度スコア・フラグ・理由を返す。
    
    Returns:
        (danger_score: pd.Series, flag: pd.Series[int], reason: pd.Series[str])
    """
    fr = ((params or {}).get('favorite_logic_rules', {}) or {})
    place_axis = _num_series(df, 'PlaceAxisScore', 50.0)
    win_through = _num_series(df, ['WinThroughScore', 'WinCandidateScore'], 50.0)
    dwr = _num_series(df, 'DevelopmentWaitRisk', 0.0)
    fav = _num_series(df, 'FavoriteScore', 50.0)
    gap = _make_series(np.maximum(place_axis.values - win_through.values, 0.0), df.index)
    score = _clip_series((1.1 * dwr + 0.22 * gap + ((fav >= 60.0) & (gap >= 3.0)).astype(float) * 1.0), 0.0, 10.0)
    thr = float(fr.get('danger_flag_threshold', 3.0) or 3.0)
    flag = (score >= thr).astype(int)
    _flag_arr = flag.values
    _score_arr = score.values
    _reason_arr = np.full(len(df), '', dtype=object)
    _reason_arr[_flag_arr > 0] = '人気先行リスクあり'
    _reason_arr[(_score_arr >= (thr * 0.66)) & (_flag_arr <= 0)] = '相手向き止まり注意'
    reason = pd.Series(_reason_arr, index=df.index, dtype=str)
    return score, flag, reason

def compute_value_hole_flags_v1_1(df: pd.DataFrame, params: Optional[dict] = None) -> tuple[pd.Series, pd.Series, pd.Series]:
    """穴馬フラグ・スコア・理由文字列を返す。
    
    Returns:
        (flag: pd.Series[int], score: pd.Series[float], reason: pd.Series[str])
    """
    fr = ((params or {}).get('favorite_logic_rules', {}) or {})
    idx = df.index
    N = len(df)
    # All numpy from the start
    _place = _arr(df, 'PlaceAxisScore', 50.0)
    _dist  = _arr(df, 'DistanceSuitScore', 50.0)
    _tr    = _arr(df, 'TrainingScore', 50.0)
    _ct    = _arr(df, 'CommentTrend', 50.0)
    _rel   = _arr(df, 'MaintenanceRunRelief', 0.0)
    _rec   = _arr(df, 'RecoverySignal', 0.0)
    _temp  = _arr(df, 'TemperamentRisk', 0.0)
    # win: WinThroughScore or WinCandidateScore
    if 'WinThroughScore' in df.columns:
        _win = _arr(df, 'WinThroughScore', 50.0)
    else:
        _win = _arr(df, 'WinCandidateScore', 50.0)
    # pace: PaceScenarioAdvantage or PaceFit
    if 'PaceScenarioAdvantage' in df.columns:
        _pace = _arr(df, 'PaceScenarioAdvantage', 50.0)
    else:
        _pace = _arr(df, 'PaceFit', 50.0)
    _pos = _arr(df, 'PosFit', 50.0)
    z4_raw = df.get('zone_4c', pd.Series(['MIDDLE'] * N, index=idx)).astype(str)
    zone_arr = np.array([normalize_zone_token(v) for v in z4_raw], dtype=object)
    pf_arr = _arr(df, 'pred_first3f', np.nan)
    pl_arr = _arr(df, 'pred_last3f', np.nan)
    pf_rank_arr = _make_series(pf_arr, idx).rank(method='min', ascending=True).values
    pl_rank_arr = _make_series(pl_arr, idx).rank(method='min', ascending=True).values

    front_signal = ((zone_arr == 'FRONT') & (pf_rank_arr <= 3.0)).astype(float)
    rear_signal  = ((zone_arr != 'FRONT') & (pl_rank_arr <= 5.0)).astype(float)
    win_over_place = (_win >= _place + 4.0).astype(float)

    front_score_arr = np.clip(
        0.34 * _place + 0.18 * _pace + 0.14 * _pos + 0.12 * _dist
        + 0.10 * _tr + 0.06 * _ct
        + 1.2 * _rel + 0.8 * _rec
        + front_signal * 4.0
        - 0.22 * _temp
        - win_over_place * 1.8,
        0.0, 100.0
    )
    rear_score_arr = np.clip(
        0.34 * _place + 0.18 * _dist + 0.14 * _pace
        + 0.10 * _tr + 0.10 * _ct
        + 0.8 * _rel + 1.2 * _rec
        + rear_signal * 4.0
        + (pl_rank_arr <= 3.0).astype(float) * 2.0
        - 0.24 * _temp
        - win_over_place * 1.6,
        0.0, 100.0
    )

    choose_front = front_score_arr >= rear_score_arr
    score_arr = np.where(choose_front, front_score_arr, rear_score_arr)
    thr = float(fr.get('value_hole_score_min', 58.0) or 58.0)
    flag_arr = ((score_arr >= thr) & (_win <= _place + 4.0)).astype(np.int64)
    reason_arr = np.full(N, '', dtype=object)
    reason_arr[(flag_arr > 0) & choose_front] = '前残り穴条件に合致'
    reason_arr[(flag_arr > 0) & (~choose_front)] = '差し込み穴条件に合致'
    reason_arr[(flag_arr <= 0) & choose_front & (front_score_arr >= thr * 0.92)] = '前残り穴候補'
    reason_arr[(flag_arr <= 0) & (~choose_front) & (rear_score_arr >= thr * 0.92)] = '差し込み穴候補'
    return _make_series(score_arr, idx), _make_series(flag_arr, idx), pd.Series(reason_arr, index=idx, dtype=str)

def _nrr_load_weights(nr: dict) -> tuple[float, ...]:
    """next_run_rules から8つの重みを読んで正規化し、タプルで返す。

    Returns: (aw, rw, sw, dw, tw, cw, uw, pw) — 合計1.0に正規化済み
    """
    aw = float(nr.get('ability_weight',      0.22) or 0.22)
    rw = float(nr.get('recent_weight',       0.18) or 0.18)
    sw = float(nr.get('stability_weight',    0.16) or 0.16)
    dw = float(nr.get('distance_weight',     0.14) or 0.14)
    tw = float(nr.get('training_weight',     0.12) or 0.12)
    cw = float(nr.get('comment_trend_weight',0.08) or 0.08)
    uw = float(nr.get('upside_weight',       0.06) or 0.06)
    pw = float(nr.get('place_axis_weight',   0.04) or 0.04)
    ws = aw + rw + sw + dw + tw + cw + uw + pw
    if ws <= 0:
        aw, rw, sw, dw, tw, cw, uw, pw = 0.22, 0.18, 0.16, 0.14, 0.12, 0.08, 0.06, 0.04
        ws = 1.0
    return tuple(x / ws for x in (aw, rw, sw, dw, tw, cw, uw, pw))


def _nrr_compute_score(
    df: pd.DataFrame,
    meta: dict,
    nr: dict,
    weights: tuple,
    stability: 'pd.Series',
    distance: 'pd.Series',
    training: 'pd.Series',
    trend: 'pd.Series',
    recovery: 'pd.Series',
    insurance_count: 'pd.Series',
    train_rank: 'pd.Series',
    delta_train: 'pd.Series',
    front_fade: 'pd.Series',
    start_risk: 'pd.Series',
    temperament: 'pd.Series',
    stamina_risk: 'pd.Series',
) -> 'pd.Series':
    """ベーススコア + ボーナス/ペナルティ → score Series (0–100) を計算する。"""
    aw, rw, sw, dw, tw, cw, uw, pw = weights

    base = (
        aw * _num_series(df, 'AbilityBaseScore', 50.0)
        + rw * _num_series(df, 'RecentFormScore', 50.0)
        + sw * stability
        + dw * distance
        + tw * training
        + cw * trend
        + uw * _num_series(df, 'Upside', 50.0)
        + pw * _num_series(df, ['PlaceAxisScore', 'SAS'], 50.0)
    )

    recovery_bonus        = recovery.astype(float) * float(nr.get('recovery_signal_bonus',        4.0) or 4.0)
    insurance_bonus       = _make_series(np.maximum(np.maximum(insurance_count.values, 0.0) - 1.0, 0.0) * float(nr.get('insurance_signal_bonus', 1.2) or 1.2), df.index)
    train_rank_bonus      = (train_rank <= 3.0).astype(float) * float(nr.get('training_rank_bonus',  2.0) or 2.0)
    delta_bonus           = (delta_train >= 1.0).astype(float) * float(nr.get('delta_train_bonus',   1.0) or 1.0)
    start_issue_bonus     = ((start_risk > 0.0) & (base >= 58.0)).astype(float) * float(nr.get('start_issue_bonus',     1.5) or 1.5)
    temperament_relief_bonus = (
        (temperament.between(2.0, 8.0, inclusive='both')) & (trend >= 55.0)
    ).astype(float) * float(nr.get('temperament_relief_bonus', 1.0) or 1.0)

    pace_mismatch_bonus = pd.Series([0.0] * len(df), index=df.index, dtype=float)
    if _is_long_maiden_race(meta, df):
        pace_mismatch_bonus = (
            ((front_fade > 0.0) | (stamina_risk > 2.0)) & (base >= 60.0)
        ).astype(float) * float(nr.get('pace_mismatch_bonus', 2.0) or 2.0)

    severe_temp_pen    = _make_series(np.maximum(temperament.values - 10.0, 0.0) * float(nr.get('severe_temp_penalty_scale',    1.2) or 1.2), df.index)
    severe_stamina_pen = _make_series(np.maximum(stamina_risk.values  -  6.0, 0.0) * float(nr.get('severe_stamina_penalty_scale', 1.0) or 1.0), df.index)

    return _clip0100((
        base
        + recovery_bonus + insurance_bonus + train_rank_bonus + delta_bonus
        + pace_mismatch_bonus + start_issue_bonus + temperament_relief_bonus
        - severe_temp_pen - severe_stamina_pen
    ))


def _nrr_build_reason_tags(
    df: pd.DataFrame,
    stability: 'pd.Series',
    distance: 'pd.Series',
    training: 'pd.Series',
    train_rank: 'pd.Series',
    trend: 'pd.Series',
    recovery: 'pd.Series',
    insurance_count: 'pd.Series',
    front_fade: 'pd.Series',
    start_risk: 'pd.Series',
    stamina_risk: 'pd.Series',
) -> tuple[list, list]:
    """馬ごとに理由タグと短文コメントリストを構築して返す。

    Returns: (reason_tags, reason_short) — df.index 順の list[str]
    """
    reason_tags: list[str] = []
    reason_short: list[str] = []
    for i in df.index:
        tags: list[str] = []
        short: list[str] = []
        if float(stability.loc[i]) >= 60.0:
            tags.append('安定')
        if float(distance.loc[i]) >= 60.0:
            tags.append('距離')
        if float(training.loc[i]) >= 60.0 or float(train_rank.loc[i]) <= 3.0:
            tags.append('調教')
        if float(trend.loc[i]) >= 55.0:
            tags.append('上昇')
        if int(recovery.loc[i]) > 0:
            tags.append('回復')
        if int(insurance_count.loc[i]) >= 3:
            tags.append('保険')
        if float(front_fade.loc[i]) > 0.0:
            short.append('今回前受け過信禁物→次走条件替わり注目')
        if float(start_risk.loc[i]) > 0.0:
            short.append('発馬ひとつで前進余地')
        if float(stamina_risk.loc[i]) > 2.0:
            short.append('距離・流れ替わりで見直し')
        if not short:
            if tags:
                short.append('基礎点が高く次走も継続注目')
            else:
                short.append('総合点ベースで次走注意')
        reason_tags.append('・'.join(tags[:6]))
        reason_short.append(' / '.join(short[:2]))
    return reason_tags, reason_short


def compute_next_run_recommendation_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> tuple[pd.Series, pd.Series, pd.Series, pd.Series, pd.Series]:
    """次走推奨スコアとフラグ・理由を返す。
    
    Returns:
        (score, main_flag, watch_flag, reason_tags, reason_short)
    """
    nr = ((params or {}).get('next_run_rules', {}) or {})
    if not bool(nr.get('enabled', True)):
        zf = pd.Series([0.0] * len(df), index=df.index, dtype=float)
        zi = pd.Series([0]   * len(df), index=df.index, dtype=int)
        zs = pd.Series(['']  * len(df), index=df.index, dtype=str)
        return zf, zi, zi, zs, zs

    weights = _nrr_load_weights(nr)

    stability       = _num_series(df, ['StabilityComposite', 'SAS'], 50.0)
    distance        = _num_series(df, ['DistanceSuitScore', 'ConditionFit'], 50.0)
    training        = _num_series(df, 'TrainingScore',        50.0)
    trend           = _num_series(df, 'CommentTrend',         50.0)
    recovery        = _num_series(df, 'RecoverySignal',        0.0)
    insurance_count = _num_series(df, 'InsuranceSignalCount',  0.0)
    train_rank      = _num_series(df, 'TrainingRank',        999.0)
    delta_train     = _num_series(df, 'delta_train',           0.0)
    front_fade      = _num_series(df, 'LongFrontFadeRisk',     0.0)
    start_risk      = _num_series(df, 'StartRiskShort',        0.0)
    temperament     = _num_series(df, 'TemperamentRisk',       0.0)
    stamina_risk    = _num_series(df, 'DistanceStaminaRisk',   0.0)

    score = _nrr_compute_score(
        df, meta, nr, weights,
        stability, distance, training, trend, recovery,
        insurance_count, train_rank, delta_train,
        front_fade, start_risk, temperament, stamina_risk,
    )

    main_min   = float(nr.get('main_score_min',  62.0) or 62.0)
    watch_min  = float(nr.get('watch_score_min', 57.0) or 57.0)
    main_flag  = (score >= main_min).astype(int)
    watch_flag = (score >= watch_min).astype(int)

    reason_tags, reason_short = _nrr_build_reason_tags(
        df, stability, distance, training, train_rank, trend,
        recovery, insurance_count, front_fade, start_risk, stamina_risk,
    )

    return (
        _num_series(score,      0.0, index=df.index),
        _num_series(main_flag,  0,   index=df.index, dtype=int),
        _num_series(watch_flag, 0,   index=df.index, dtype=int),
        pd.Series(reason_tags,  index=df.index, dtype=str),
        pd.Series(reason_short, index=df.index, dtype=str),
    )

def compute_ability_base_score_v1_1(df: pd.DataFrame, params: Optional[dict] = None) -> pd.Series:
    """能力ベーススコア (0–100) を時計・安定・主軸評価から計算する。"""
    wp = ((params or {}).get('win_pattern_rules', {}) or {})
    aw_time = float(wp.get('ability_time_weight', 0.18) or 0.18)
    aw_cons = float(wp.get('ability_consist_weight', 0.12) or 0.12)
    aw_main = float(max(0.0, 1.0 - aw_time - aw_cons))
    ab = _num_series(df, 'Ability', 50.0)
    tf = _num_series(df, 'TimeFit', 50.0)
    cs = _num_series(df, 'Consist', 50.0)
    out = _clip0100((aw_main * ab + aw_time * tf + aw_cons * cs))
    return _num_series(out, 50.0, index=df.index)


def compute_recent_form_score_v1_1(df: pd.DataFrame, params: Optional[dict] = None) -> pd.Series:
    """近走フォームスコア (0–100) を計算する。"""
    wp = ((params or {}).get('win_pattern_rules', {}) or {})
    wt = float(wp.get('recent_training_weight', 0.46) or 0.46)
    wr = float(wp.get('recent_trend_weight', 0.22) or 0.22)
    wd = float(wp.get('recent_delta_weight', 0.12) or 0.12)
    wa = float(wp.get('recent_training_adjustment_weight', 0.20) or 0.20)
    s = wt + wr + wd + wa
    if s <= 0:
        wt, wr, wd, wa = 0.46, 0.22, 0.12, 0.20
        s = 1.0
    wt, wr, wd, wa = wt / s, wr / s, wd / s, wa / s
    tr = _num_series(df, 'TrainingScore', 50.0)
    ct = _num_series(df, 'CommentTrend', 50.0)
    dt = _num_series(df, 'delta_train', 0.0)
    ta = _num_series(df, 'TrainingAdjustmentScore', 50.0)
    dt01 = _clip0100((50.0 + 12.0 * dt))
    out = _clip0100((wt * tr + wr * ct + wd * dt01 + wa * ta))
    return _num_series(out, 50.0, index=df.index)


def _training_method_bucket(value) -> str:
    s = str(value or '').strip()
    if not s:
        return ''
    upper = s.upper()
    if re.search(r'坂路|坂', s):
        return 'slope'
    if re.search(r'ウッド|CW|CWコース|Wコース|南W|美W|栗W|WOOD', upper):
        return 'wood'
    if re.search(r'ポリ|ダート|芝|プール', s):
        return 'other'
    return ''


def _normalize_training_rank_score(series_like, index) -> pd.Series:
    """調教時計順位・上位率のような値を 0-100 スコアへ正規化して返す。小さいほど高評価。"""
    s = _num_series(series_like, np.nan, index=index)
    s = pd.to_numeric(s, errors='coerce')
    s = s.where((~np.isfinite(s)) | (s < 900.0), np.nan)
    finite = s[np.isfinite(s)]
    if len(finite) == 0:
        return pd.Series([50.0] * len(index), index=index, dtype=float)
    max_abs = float(finite.abs().max())
    if max_abs <= 1.2:
        score = 100.0 * (1.0 - _clip_series(s, 0.0, 1.0))
    elif max_abs <= 100.0:
        score = 100.0 * (1.0 - (_clip0100(s) / 100.0))
    else:
        score = 100.0 - 18.0 * np.log1p((np.clip(s.values, 1.0, None) - 1.0))
    return _clip0100(score).fillna(50.0).astype(float)


def _extract_weeks_since_last(df: pd.DataFrame) -> pd.Series:
    """前走間隔を週単位で推定して返す。直接列、日数列、日付差、コメント表現を順に利用する。"""
    idx = df.index
    weeks = _num_series(_first_existing_series(df, [
        'weeks_since_last', 'weeks_since_prev', 'weeks_since_run', 'interval_weeks',
        'layoff_weeks', 'rest_weeks', '前走間隔週', '中間隔週数', '休養週'
    ]), np.nan, index=idx)
    days = _num_series(_first_existing_series(df, [
        'days_since_last', 'days_since_prev', 'days_since_run', 'interval_days',
        'last_interval_days', 'layoff_days', 'rest_days', '前走間隔日数', '休養日数'
    ]), np.nan, index=idx)
    weeks = weeks.where(np.isfinite(weeks), days / 7.0)

    if 'race_date' in df.columns:
        prev_date = _first_existing_series(df, ['prev_date', 'last_race_date', 'latest_race_date', '前走日'], default=np.nan)
        try:
            race_date = pd.to_datetime(df['race_date'], errors='coerce')
            prev_dt = pd.to_datetime(prev_date, errors='coerce')
            delta_weeks = (race_date - prev_dt).dt.days / 7.0
            weeks = weeks.where(np.isfinite(weeks), delta_weeks)
        except Exception:
            pass

    comments = (
        df.get('comment_short', pd.Series([''] * len(df), index=idx)).infer_objects(copy=False).fillna('').astype(str)
        + ' '
        + df.get('comment_tags', pd.Series([''] * len(df), index=idx)).infer_objects(copy=False).fillna('').astype(str)
    )
    week_text = pd.to_numeric(comments.str.extract(r'中\s*([0-9]{1,2})\s*週', expand=False), errors='coerce')
    weeks = weeks.where(np.isfinite(weeks), week_text)
    return weeks.astype(float)


def _normalize_count_score(series_like, index, *, max_count: float = 8.0) -> pd.Series:
    """本数系の値を 0-100 スコアへ正規化して返す。"""
    s = _num_series(series_like, np.nan, index=index, lower=0.0)
    finite = s[np.isfinite(s)]
    if len(finite) == 0:
        return pd.Series([50.0] * len(index), index=index, dtype=float)
    max_ref = max(float(max_count), float(finite.max()), 1.0)
    _arr = np.where(np.isfinite(s.values), np.clip(s.values, 0.0, max_ref) / max_ref * 100.0, 50.0)
    return _make_series(np.clip(_arr, 0.0, 100.0), s.index)


def add_training_adjustment_features(
    df: pd.DataFrame,
    meta: Optional[Dict[str, str]] = None,
    params: Optional[dict] = None,
) -> pd.DataFrame:
    """外厩帰り・調教時計順位・調教方法に加えて、休み明け負荷質と装蹄コメントも数値化する。"""
    _ = meta, params
    if df is None or len(df) == 0:
        return df

    out = df.copy()
    idx = out.index
    weeks = _extract_weeks_since_last(out)
    gaikyu_text = _first_existing_series(out, [
        'gaikyu_name', '外厩先', '放牧先', '外厩', '帰厩先'
    ], default='').infer_objects(copy=False).fillna('').astype(str)
    comment_text = (
        out.get('comment_short', pd.Series([''] * len(out), index=idx)).infer_objects(copy=False).fillna('').astype(str)
        + ' '
        + out.get('comment_tags', pd.Series([''] * len(out), index=idx)).infer_objects(copy=False).fillna('').astype(str)
    )
    gaikyu_pattern = r'天栄|しがらき|山元|チャンピオンヒルズ|大山ヒルズ|ノーザンファーム|ノーザンF|外厩'
    has_gaikyu = gaikyu_text.str.contains(gaikyu_pattern, regex=True, na=False) | comment_text.str.contains(gaikyu_pattern, regex=True, na=False)

    gaikyu_raw = _first_existing_series(out, ['is_gaikyu_return', '外厩帰り', '外厩帰りフラグ', 'gaikyu_return_flag'], default=np.nan)
    gaikyu_num = pd.to_numeric(gaikyu_raw, errors='coerce')
    gaikyu_text_flag = gaikyu_raw.infer_objects(copy=False).fillna('').astype(str).str.contains(r'1|true|yes|あり|有|帰厩', case=False, regex=True, na=False)
    gaikyu_return_flag = ((gaikyu_num >= 0.5) | gaikyu_text_flag | (has_gaikyu & (weeks >= 10.0))).astype(int)

    _gaikyu_arr = np.full(len(out), 50.0, dtype=np.float64)
    _hg_arr = has_gaikyu.values
    _wk_arr = weeks.values
    _grf_arr = gaikyu_return_flag.values
    _hg_w6 = _hg_arr & (_wk_arr >= 6.0)
    _gaikyu_arr[_hg_w6] = 58.0
    _grf_mask = _grf_arr > 0
    _gaikyu_arr[_grf_mask] = 68.0
    _gaikyu_boost_arr = np.clip(np.where(np.isfinite(_wk_arr), _wk_arr - 10.0, 0.0), 0.0, 8.0) * 1.25
    _gaikyu_arr[_grf_mask] = np.clip(68.0 + _gaikyu_boost_arr[_grf_mask], 0.0, 80.0)
    gaikyu_score = _make_series(_gaikyu_arr, idx)

    train_rank_raw = _first_existing_series(out, [
        'training_time_rank', '調教時計順位', '追い切り時計順位', '追切時計順位',
        '追い切り順位', '追切順位', '調教順位', '調教時計上位率', '追い切り上位率',
        '追切上位率', 'TrainingRank'
    ], default=np.nan)
    training_rank_score = _normalize_training_rank_score(train_rank_raw, idx)
    training_rank_score = _wsum0100(idx, (0.65, training_rank_score), (0.35, _num_series(out, 'TrainingScore', 50.0)))

    method_text = _first_existing_series(out, [
        'training_method', '調教方法', '追い切り方法', '追切方法', '追い切りコース',
        '追切コース', '調教コース', 'course_latest'
    ], default='').infer_objects(copy=False).fillna('').astype(str)
    trainer_pref_text = _first_existing_series(out, [
        'trainer_training_method_pattern', 'trainer_preferred_training_method',
        '調教師調教パターン', '厩舎調教パターン', 'trainer_course_pattern'
    ], default='').infer_objects(copy=False).fillna('').astype(str)
    method_bucket = method_text.apply(_training_method_bucket)
    pref_bucket = trainer_pref_text.apply(_training_method_bucket)

    training_method_score = pd.Series([50.0] * len(out), index=idx, dtype=float)
    training_method_score.loc[method_bucket == 'slope'] = 58.0
    training_method_score.loc[method_bucket == 'wood'] = 56.0
    training_method_score.loc[method_bucket == 'other'] = 52.0
    training_method_score.loc[(method_bucket != '') & (pref_bucket != '') & (method_bucket == pref_bucket)] = 72.0
    training_method_score.loc[(method_bucket != '') & (pref_bucket != '') & (method_bucket != pref_bucket)] = 38.0

    mid_work_raw = _first_existing_series(out, [
        'mid_work_count', 'middle_work_count', 'intermediate_work_count',
        '中間追い切り本数', '中間追切本数', '中間本数', '追い切り本数', '追切本数', '中間調教本数'
    ], default=np.nan)
    finish_work_raw = _first_existing_series(out, [
        'finish_work_count', 'final_work_count', '仕上げ本数', '最終追い切り本数',
        '最終追切本数', '1週前追い本数', '一週前追い本数', '最終追い本数'
    ], default=np.nan)
    cw_index_raw = _first_existing_series(out, [
        'cw_index', 'CW指数', 'CW指標', 'ウッド指数', 'cw_score', 'clock_index',
        '1週前追い指数', '一週前追い指数', '追い切り負荷指数'
    ], default=np.nan)
    mid_work_count = _num_series(mid_work_raw, np.nan, index=idx, lower=0.0)
    finish_work_count = _num_series(finish_work_raw, np.nan, index=idx, lower=0.0)
    cw_index = _num_series(cw_index_raw, np.nan, index=idx, lower=0.0)
    mid_work_count = mid_work_count.where(
        np.isfinite(mid_work_count),
        pd.to_numeric(comment_text.str.extract(r'中間[^0-9]{0,6}([0-9]{1,2})本', expand=False), errors='coerce'),
    )
    finish_work_count = finish_work_count.where(
        np.isfinite(finish_work_count),
        pd.to_numeric(comment_text.str.extract(r'(?:1週前|一週前|最終)[^0-9]{0,6}([0-9]{1,2})本', expand=False), errors='coerce'),
    )
    cw_comment_flag = (
        method_text.str.contains(r'CW|Wコース|南W|美W|栗W|ウッド', case=False, regex=True, na=False)
        | comment_text.str.contains(r'CW|南W|美W|栗W|ウッド', case=False, regex=True, na=False)
    )
    cw_index = cw_index.where(np.isfinite(cw_index), cw_comment_flag.astype(float) * 1.8)
    _mwc_arr = np.where(np.isfinite(mid_work_count.values), mid_work_count.values, 0.0)
    _fwc_arr = np.where(np.isfinite(finish_work_count.values), finish_work_count.values, 0.0)
    prep_load = (
        0.55 * _mwc_arr
        + 1.05 * _fwc_arr
        + 1.65 * np.log1p(np.clip(np.where(np.isfinite(cw_index.values), cw_index.values, 0.0), 0.0, None))
    )
    rest_need = np.log1p(np.clip(np.where(np.isfinite(weeks.values), weeks.values, 0.0), 0.0, None))
    rest_load_score = np.clip(50.0 + 18.0 * (prep_load - 1.35 * rest_need), 0.0, 100.0)
    _long_rest = _wk_arr >= 10.0
    _lru = (_long_rest & (prep_load < (rest_need + 0.8))).astype(float)
    _lrs = (_long_rest & (prep_load >= (rest_need + 1.5))).astype(float)
    rest_load_score = np.clip(rest_load_score - 10.0 * _lru + 4.0 * _lrs, 0.0, 100.0)
    _rest_present = (np.isfinite(mid_work_count.values) | np.isfinite(finish_work_count.values) | np.isfinite(cw_index.values) | np.isfinite(_wk_arr) | cw_comment_flag.values).astype(float)
    _rls_arr = rest_load_score.copy()
    _rls_arr[_rest_present <= 0.0] = 50.0
    rest_load_score = _make_series(_rls_arr, idx)

    shoe_raw = _first_existing_series(out, [
        'shoe_change_comment', 'shoeing_comment', 'shoe_change', '蹄鉄変更', '蹄鉄コメント',
        '装蹄コメント', '装蹄', '蹄鉄', 'shoe_change_note', 'plate_change_comment'
    ], default='').infer_objects(copy=False).fillna('').astype(str)
    track_text = _first_existing_series(out, [
        'track_condition', '馬場状態', 'baba_condition', 'condition', '馬場', 'weather_track'
    ], default='').infer_objects(copy=False).fillna('').astype(str)
    muddy_signal = (
        (_num_series(out, 'MichiakuFit', 50.0, index=idx) >= 55.0)
        | track_text.str.contains(r'重|不良|稍重|道悪', regex=True, na=False)
        | comment_text.str.contains(r'道悪|渋馬場|力の要る馬場|時計かか', regex=True, na=False)
    )
    shoe_text = (shoe_raw + ' ' + comment_text).astype(str)
    aluminum_to_steel = shoe_text.str.contains(r'アルミ\s*[→>\-／/]\s*スチール|アルミからスチール|アルミ.*スチール', regex=True, na=False)
    steel_to_aluminum = shoe_text.str.contains(r'スチール\s*[→>\-／/]\s*アルミ|スチールからアルミ', regex=True, na=False)
    shoe_change_flag = shoe_text.str.contains(r'蹄鉄|装蹄|アルミ|スチール', regex=True, na=False)
    _scs_arr = np.full(len(out), 50.0, dtype=np.float64)
    _scf = shoe_change_flag.values
    _a2s = aluminum_to_steel.values
    _s2a = steel_to_aluminum.values
    _mud = muddy_signal.values
    _pwr = shoe_text.str.contains(r'パワー|踏ん張|力強|重馬場対応', regex=True, na=False).values
    _scs_arr[_scf] = 54.0
    _scs_arr[_a2s] = 60.0
    _scs_arr[_a2s & _mud] = 72.0
    _scs_arr[_s2a & (~_mud)] = 60.0
    _scs_arr[_s2a & _mud] = 42.0
    _scs_arr[_pwr & _mud] = 74.0
    shoe_change_score = _make_series(_scs_arr, idx)
    shoe_present = shoe_change_flag.astype(float)

    method_present = ((method_text.str.strip() != '') | (trainer_pref_text.str.strip() != '')).astype(float)
    rank_present = _first_existing_series(out, [
        'training_time_rank', '調教時計順位', '追い切り時計順位', '追切時計順位',
        '追い切り順位', '追切順位', '調教順位', '調教時計上位率', '追い切り上位率',
        '追切上位率', 'TrainingRank'
    ], default=np.nan).notna().astype(float)
    gaikyu_present = ((gaikyu_text.str.strip() != '') | gaikyu_text_flag | np.isfinite(weeks)).astype(float)

    out['weeks_since_last'] = weeks.astype(float)
    out['is_gaikyu_return'] = gaikyu_return_flag.astype(int)
    out['GaikyuReturnScore'] = _clip0100(gaikyu_score).astype(float)
    out['TrainingTimeRankScore'] = training_rank_score.astype(float)
    out['TrainingMethodScore'] = training_method_score.astype(float)
    out['mid_work_count'] = mid_work_count.fillna(0.0).astype(float)
    out['finish_work_count'] = finish_work_count.fillna(0.0).astype(float)
    out['cw_index'] = cw_index.fillna(0.0).astype(float)
    out['RestLoadCompensationScore'] = rest_load_score.astype(float)
    out['ShoeingChangeFlag'] = shoe_change_flag.astype(int)
    out['ShoeingCommentScore'] = shoe_change_score.astype(float)
    _ts_arr = _arr(out, 'TrainingScore', 50.0)
    _hcs_arr = np.clip(0.56 * _rls_arr + 0.22 * _scs_arr + 0.22 * _ts_arr, 0.0, 100.0)
    out['HorseConditionScore'] = _hcs_arr
    _gaikyu_present = gaikyu_present.values
    _rank_present = rank_present.values
    _method_present = method_present.values
    _shoe_present = shoe_present.values
    out['TrainingAdjustmentReliability'] = np.clip(
        100.0 * (_gaikyu_present + _rank_present + _method_present + _rest_present + _shoe_present) / 5.0, 0.0, 100.0)
    _grs_arr = out['GaikyuReturnScore'].values
    _ttrs_arr = out['TrainingTimeRankScore'].values
    _tms_arr = out['TrainingMethodScore'].values
    _rlcs_arr = out['RestLoadCompensationScore'].values
    _scss_arr = out['ShoeingCommentScore'].values
    out['TrainingAdjustmentScore'] = np.clip(
        0.18 * _grs_arr + 0.30 * _ttrs_arr + 0.10 * _tms_arr
        + 0.24 * _rlcs_arr + 0.08 * _scss_arr + 0.10 * _hcs_arr,
        0.0, 100.0)
    return out




def compute_race_condition_score_v1_1(df: pd.DataFrame, params: Optional[dict] = None) -> pd.Series:
    """レース条件適性スコア (0–100) を馬場・距離・コースから計算する。"""
    wp = ((params or {}).get('win_pattern_rules', {}) or {})
    ww = {
        'PaceFit': float(wp.get('race_pace_weight', 0.30) or 0.30),
        'GateFit': float(wp.get('race_gate_weight', 0.24) or 0.24),
        'ConditionFit': float(wp.get('race_condition_weight', 0.26) or 0.26),
        'MapFit': float(wp.get('race_map_weight', 0.12) or 0.12),
        'PosFit': float(wp.get('race_pos_weight', 0.08) or 0.08),
    }
    s = sum(max(0.0, float(v)) for v in ww.values())
    if s <= 0:
        ww = {'PaceFit': 0.30, 'GateFit': 0.24, 'ConditionFit': 0.26, 'MapFit': 0.12, 'PosFit': 0.08}
        s = 1.0
    out = pd.Series([0.0] * len(df), index=df.index, dtype=float)
    for k, v in ww.items():
        out = out + (max(0.0, float(v)) / s) * _num_series(df, k, 50.0)
    return _num_series(out, 50.0, index=df.index, lower=0.0, upper=100.0)


def compute_temperament_risk_v1_1(df: pd.DataFrame, params: Optional[dict] = None) -> pd.Series:
    """気性リスクスコアをコメントタグから計算する。"""
    tags = df.get('comment_tags', pd.Series([''] * len(df), index=df.index)).astype(str)
    short = df.get('comment_short', pd.Series([''] * len(df), index=df.index)).astype(str)
    cr = _num_series(df, 'CommentRisk', 0.0)
    kickback = short.str.contains(r'キックバック|砂を被|砂を嫌', regex=True, na=False)
    focus = short.str.contains(r'集中|気難|イレ込|テンション|気持ち|ムラ|若さ|幼さ|掛か|行きたが', regex=True, na=False)
    start = short.str.contains(r'出遅|スタート|ゲート|発馬|一歩目|二の脚|ダッシュ|行き脚', regex=True, na=False) | _comment_tag_mask(tags, ['G-出遅', 'G-スタートひと息', 'G-ゲートひと息', 'G-ゲート不安', 'G-1歩目は速くない', 'G-一歩目は速くない', 'G-ダッシュ付か', 'G-行き脚つか', 'G-モサッ', 'G-スタート課題', 'G-発馬課題'])
    base = (cr / 100.0) * 4.0
    risk = base + kickback.astype(float) * 3.5 + focus.astype(float) * 3.0 + start.astype(float) * 2.5
    return _num_series(risk, 0.0, index=df.index, lower=0.0, upper=14.0)

def compute_insurance_signals_v1_1(df: pd.DataFrame, params: Optional[dict] = None) -> tuple[pd.Series, pd.Series, pd.Series, pd.Series, pd.Series]:
    """保険シグナル群を返す (count / flag / reason / delta_train / train_rank)。
    
    Returns:
        (count, flag, reason, delta_train, train_rank)
    """
    ir = ((params or {}).get('insurance_rules', {}) or {})
    rise_thr = float(ir.get('rise_trend_threshold', 58.0) or 58.0)
    delta_thr = float(ir.get('delta_train_threshold', 1.0) or 1.0)
    tr_thr = float(ir.get('training_score_threshold', 58.0) or 58.0)
    tr_rank_thr = int(ir.get('training_rank_threshold', 4) or 4)
    comment_thr = float(ir.get('comment_fit_threshold', 56.0) or 56.0)
    track_thr = float(ir.get('track_adv_threshold', 58.0) or 58.0)

    trend = _num_series(df, 'CommentTrend', 50.0)
    delta = _num_series(df, 'delta_train', 0.0)
    training_score = _num_series(df, 'TrainingScore', 50.0)
    training_rank = _num_series(df, 'TrainingRank', 999.0)
    comment_fit = _num_series(df, 'CommentFit', 50.0)
    comment_condition = _num_series(df, 'CommentCondition', 50.0)
    map_fit = _num_series(df, 'MapFit', 50.0)
    condition_fit = _num_series(df, 'ConditionFit', 50.0)
    pos_fit = _num_series(df, 'PosFit', 50.0)

    rise = ((trend >= rise_thr) | (delta >= delta_thr)).astype(int)
    training = ((training_score >= tr_thr) | (training_rank <= tr_rank_thr)).astype(int)
    comment = ((comment_fit >= comment_thr) | (comment_condition >= track_thr) | (trend >= rise_thr)).astype(int)
    track = ((map_fit >= track_thr) | (condition_fit >= track_thr) | (pos_fit >= track_thr)).astype(int)
    count = (rise + training + comment + track).astype(int)
    return count, rise.astype(int), training.astype(int), comment.astype(int), track.astype(int)

def compute_front_collapse_risk_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> pd.Series:
    """先行馬の崩れリスクスコア (0–100) を計算する。"""
    params = params or {}
    pace = str((meta or {}).get('pace', '') or '').upper().strip()[:1]
    dist, surface = _meta_distance_surface(meta)
    if pace != 'H':
        return pd.Series([0.0] * len(df), index=df.index, dtype=float)

    z = df.get('zone_4c', pd.Series(['MIDDLE'] * len(df), index=df.index)).astype(str).map(normalize_zone_token)
    pf = _num_series(df, 'pred_first3f', np.nan)
    pl = _num_series(df, 'pred_last3f', np.nan)
    cg = _num_series(df, 'CommentGate', 50.0)
    tags = df.get('comment_tags', pd.Series([''] * len(df), index=df.index)).astype(str)

    try:
        base_front = float(params.get('high_pace_front_base_penalty', 8.0) or 8.0)
        fast_pen = float(params.get('high_pace_first3f_leader_penalty', 4.0) or 4.0)
        bad_gate_pen = float(params.get('high_pace_bad_gate_penalty', 4.0) or 4.0)
        last_relief = float(params.get('high_pace_last3f_relief', 5.0) or 5.0)
        middle_relief = float(params.get('high_pace_middle_relief', 3.0) or 3.0)
    except Exception:
        base_front, fast_pen, bad_gate_pen, last_relief, middle_relief = 8.0, 4.0, 4.0, 5.0, 3.0

    risk = pd.Series([0.0] * len(df), index=df.index, dtype=float)
    risk.loc[z == 'FRONT'] += base_front
    risk.loc[z == 'MIDDLE'] += 2.0

    try:
        pf_rank = pf.rank(method='min', ascending=True)
        risk.loc[pf_rank <= 2.0] += fast_pen
    except Exception:
        pass

    bad_gate_mask = (cg < 45.0) | _comment_tag_mask(tags, ['G-出遅', 'G-スタートひと息', 'G-ゲートひと息', 'G-ゲート不安', 'G-1歩目は速くない', 'G-一歩目は速くない', 'G-ダッシュ付か', 'G-行き脚つか', 'G-モサッ'])
    risk.loc[bad_gate_mask] += bad_gate_pen

    try:
        pl_rank = pl.rank(method='min', ascending=True)
        risk.loc[pl_rank <= 6.0] -= last_relief
    except Exception:
        pass
    risk.loc[z == 'MIDDLE'] -= middle_relief

    if surface == 'dirt' and np.isfinite(dist) and dist <= 1400:
        risk = risk * 1.15

    return _num_series(risk, 0.0, index=df.index, lower=0.0, upper=12.0)

def compute_start_risk_short_v1_1(df: pd.DataFrame, meta: Dict[str, str], params: Optional[dict] = None) -> pd.Series:
    """短距離戦でのスタートリスクスコア (0–100) を計算する。"""
    _ = params or {}
    dist, surface = _meta_distance_surface(meta)
    out = pd.Series([0.0] * len(df), index=df.index, dtype=float)
    if surface != 'dirt' or not np.isfinite(dist):
        return out

    cg = _num_series(df, 'CommentGate', 50.0)
    z = df.get('zone_4c', pd.Series(['MIDDLE'] * len(df), index=df.index)).astype(str).map(normalize_zone_token)
    tags = df.get('comment_tags', pd.Series([''] * len(df), index=df.index)).astype(str)
    bad_gate_mask = (cg < 45.0) | _comment_tag_mask(tags, ['G-出遅', 'G-スタートひと息', 'G-ゲートひと息', 'G-ゲート不安', 'G-1歩目は速くない', 'G-一歩目は速くない', 'G-ダッシュ付か', 'G-行き脚つか', 'G-モサッ'])

    if dist <= 1200:
        out.loc[cg < 45.0] += 4.0
        out.loc[bad_gate_mask] += 4.0
        out.loc[z == 'FRONT'] += 2.0
    elif dist <= 1400:
        out.loc[cg < 45.0] += 2.5
        out.loc[bad_gate_mask] += 2.5

    return _num_series(out, 0.0, index=df.index, lower=0.0, upper=10.0)

def compute_factorfit(df: pd.DataFrame) -> Tuple[pd.Series, pd.Series, pd.Series]:
    """ファクター印を点数化。

    v1.1 までは最初の列を "dirt" 扱いにしていたが、実データでは
    ここが「道悪」になるケースが多い。

    - michiaku (道悪) があればそれを優先
    - なければ dirt を代用

    Returns:
      FactorPts: 合計点 (max 12)
      FactorFit: 0-100
      MichiakuFit: 道悪列のみ 0-100（max=◎=2.0 -> 100）
    """
    # 道悪列の優先順位
    first_col = "michiaku" if "michiaku" in df.columns else ("dirt" if "dirt" in df.columns else None)

    cols = [c for c in [first_col, "course", "distance", "last", "training", "record"] if c]

    # ベクトル化: np.select で印→点数変換（Series.map を排除）
    n = len(df)
    idx = df.index
    pts_arr = np.zeros(n, dtype=np.float64)
    mich_arr = np.zeros(n, dtype=np.float64)
    for c in cols:
        raw = df[c].values if c in df.columns else np.full(n, '', dtype=object)
        # np.select: ◎=2.0, ○=1.0, △=0.5, それ以外=0.0
        mapped_arr = np.select(
            [raw == '◎', raw == '○', raw == '△'],
            [2.0,          1.0,        0.5],
            default=0.0,
        )
        pts_arr += mapped_arr
        if c == first_col:
            mich_arr = mapped_arr

    fit_arr = pts_arr / 12.0 * 100.0
    mich_fit_arr = mich_arr / 2.0 * 100.0
    return _make_series(pts_arr, idx), _make_series(fit_arr, idx), _make_series(mich_fit_arr, idx)


def _is_wet_track(meta: Dict[str, str]) -> bool:
    """馬場が『道悪寄り』かを判定（超簡易）。

    - 芝/ダ の going が 稍重/重/不良
    - or wetness_score_* が一定以上

    目的: 道悪印（◎○△）を強めに効かせるスイッチ。
    """
    # キャッシュがあれば即返す
    if '_cached_wet' in meta:
        return meta['_cached_wet']
    tg = str(meta.get("turf_going", "")).strip()
    dg = str(meta.get("dirt_going", "")).strip()
    if tg in ["稍重", "重", "不良"]:
        return True
    if dg in ["稍重", "重", "不良"]:
        return True

    def _f(k: str) -> float:
        """meta 辞書からキー k の値を float に変換するショートハンド。失敗時は nan。"""
        try:
            return float(str(meta.get(k, "")).strip())
        except Exception:
            return float("nan")

    # 含水率OCRが取れている場合
    for k in ["wetness_score_turf_goal", "wetness_score_turf_4c", "wetness_score_dirt_goal", "wetness_score_dirt_4c"]:
        v = _f(k)
        if np.isfinite(v) and v >= 30.0:
            return True

    return False


def weighted_geomean_0_100(row: pd.Series, keys: list[str], weights: dict[str, float], floor: float = 5.0, ceil: float = 95.0) -> float:
    """0-100スコア群の重み付き幾何平均（掛算式）。

    - 各要素を [floor, ceil] にクリップして log を取る
    - weights の合計は1.0想定（多少ズレても内部で正規化はしない）

    目的: どれか1要素が極端に悪いとスコアが伸びない（=弱点を隠しにくい）設計。
    """
    eps = 1e-9
    z = 0.0
    for k in keys:
        w = float(weights.get(k, 0.0))
        if w <= 0:
            continue
        try:
            x = float(row.get(k, np.nan))
        except Exception:
            x = np.nan
        if not np.isfinite(x):
            x = 50.0
        x = clamp(x, float(floor), float(ceil))
        z += w * float(np.log(max(eps, x / 100.0)))
    out = 100.0 * float(np.exp(z))
    return float(clamp(out, 0.0, 100.0))


def weighted_geomean_df_0_100(df: pd.DataFrame, keys: list[str], weights: dict[str, float], floor: float = 5.0, ceil: float = 95.0) -> pd.Series:
    """DataFrame行方向に weighted_geomean_0_100 を適用。NumPy完全ベクトル化版。

    NOTE: v9では compute_scores_v1_1 から参照されるが定義が欠けていたため追加。
    """
    if df is None or len(df) == 0:
        return pd.Series([], dtype=float)
    # 有効キー（weight > 0 かつ列が存在）だけ抽出
    valid_keys = [k for k in keys if float(weights.get(k, 0.0)) > 0]
    if not valid_keys:
        return pd.Series(50.0, index=df.index, dtype=float)
    eps = 1e-9
    w_arr = np.array([float(weights[k]) for k in valid_keys], dtype=float)
    # 各列を取り出し (n_rows, n_keys) の行列を作る
    mat = np.full((len(df), len(valid_keys)), 50.0, dtype=float)
    for j, k in enumerate(valid_keys):
        if k in df.columns:
            col = pd.to_numeric(df[k], errors='coerce').values
            finite_mask = np.isfinite(col)
            mat[:, j] = np.where(finite_mask, col, 50.0)
    mat = np.clip(mat, float(floor), float(ceil))
    # weighted log-sum → exp → scale
    log_mat = np.log(np.maximum(mat / 100.0, eps))  # (n_rows, n_keys)
    z = log_mat.dot(w_arr)  # (n_rows,)
    out = np.clip(100.0 * np.exp(z), 0.0, 100.0)
    return pd.Series(out, index=df.index, dtype=float)




